   // 🔧 Função para atualizar a aplicação
   function atualizarAplicacao() {
     console.log('🔄 Iniciando atualização da aplicação...');
     
     // Mostrar loading
     if (typeof Swal !== 'undefined') {
       Swal.fire({
         title: 'Atualizando...',
         html: 'Recarregando a aplicação com a nova versão',
         icon: 'info',
         allowOutsideClick: false,
         allowEscapeKey: false,
         showConfirmButton: false,
         didOpen: () => {
           Swal.showLoading();
         }
       });
     }
     
     // Limpar cache e recarregar após um pequeno delay
     setTimeout(() => {
       // Limpar service workers se existirem
       if ('serviceWorker' in navigator) {
         navigator.serviceWorker.getRegistrations().then(registrations => {
           registrations.forEach(registration => {
             registration.unregister();
           });
         });
       }
       
       // Limpar caches do navegador
       if ('caches' in window) {
         caches.keys().then(cacheNames => {
           return Promise.all(cacheNames.map(cacheName => caches.delete(cacheName)));
         });
       }
       
       // Limpar localStorage de cache (manter dados importantes)
      const keysToKeep = ['session_user', 'session_role', 'session_local', 'session_time', 'session_name', 'theme'];
       const allKeys = Object.keys(localStorage);
       allKeys.forEach(key => {
         if (!keysToKeep.includes(key) && !key.startsWith('ccb_')) {
           localStorage.removeItem(key);
         }
       });
       
       // Atualizar versão armazenada
       localStorage.setItem(VERSION_STORAGE_KEY, APP_VERSION);
       localStorage.setItem(LAST_UPDATE_CHECK_KEY, Date.now().toString());
       
       // Recarregar página com cache limpo
       window.location.reload(true);
     }, 1500);
   }
   
