  // 🛡️ FUNÇÃO CRÍTICA: Verificar se localStorage está disponível (COMPATIBILIDADE MULTIPLATAFORMA)
  // 🛡️ MELHORADO PARA XIAOMI/MIUI - Problemas conhecidos com localStorage em algumas versões
  function isLocalStorageAvailable() {
     try {
       // Verificar se localStorage existe
       if (typeof localStorage === 'undefined') {
         console.warn('⚠️ localStorage não está disponível nesta plataforma');
         return false;
       }
       
       // 🛡️ XIAOMI/MIUI: Teste mais robusto para detectar problemas específicos
       const test = '__localStorage_test__';
       const testValue = '__test_value_' + Date.now();
       
       try {
         localStorage.setItem(test, testValue);
         const retrieved = localStorage.getItem(test);
         localStorage.removeItem(test);
         
         // Verificar se o valor foi recuperado corretamente
         if (retrieved !== testValue) {
           console.warn('⚠️ localStorage não está funcionando corretamente (valor não corresponde)');
           if (isXiaomi) {
             console.warn('⚠️ XIAOMI/MIUI: Problema conhecido com localStorage - usando fallback');
           }
           return false;
         }
         
         // 🛡️ XIAOMI/MIUI: Teste adicional de quota (algumas versões MIUI têm problemas)
         try {
           const largeTest = 'x'.repeat(1024); // 1KB
           localStorage.setItem(test, largeTest);
           localStorage.removeItem(test);
         } catch (quotaError) {
           if (quotaError.name === 'QuotaExceededError' || quotaError.name === 'NS_ERROR_DOM_QUOTA_REACHED') {
             console.warn('⚠️ Quota do localStorage muito limitada');
             if (isXiaomi) {
               console.warn('⚠️ XIAOMI/MIUI: Quota limitada detectada - usando fallback');
             }
             return false;
           }
         }
         
         return true;
       } catch (setError) {
         console.warn('⚠️ Erro ao testar localStorage:', setError.message);
         if (isXiaomi) {
           console.warn('⚠️ XIAOMI/MIUI: Erro ao acessar localStorage - usando fallback');
         }
         return false;
       }
     } catch (e) {
       // Verificar tipo específico de erro (quota excedida, privacidade, etc)
       if (e.name === 'QuotaExceededError' || e.name === 'NS_ERROR_DOM_QUOTA_REACHED') {
         console.warn('⚠️ Quota do localStorage excedida');
         if (isXiaomi) {
           console.warn('⚠️ XIAOMI/MIUI: Quota excedida - usando fallback');
         }
       } else if (e.name === 'SecurityError' || e.code === 18) {
         console.warn('⚠️ localStorage bloqueado por política de segurança');
         if (isXiaomi) {
           console.warn('⚠️ XIAOMI/MIUI: localStorage bloqueado - usando fallback');
         }
       } else {
         console.warn('⚠️ localStorage não disponível:', e.message);
         if (isXiaomi) {
           console.warn('⚠️ XIAOMI/MIUI: localStorage não disponível - usando fallback');
         }
       }
       return false;
     }
   }
   
   // 🛡️ FALLBACK: Armazenamento alternativo quando localStorage não está disponível
   const memoryStorage = {};
   const useMemoryStorage = !isLocalStorageAvailable();
   
   if (useMemoryStorage) {
     console.warn('⚠️ Usando armazenamento em memória (fallback) - dados serão perdidos ao recarregar');
   } else {
     console.log('✅ localStorage disponível e funcional');
   }
   
   // 🛡️ WRAPPER UNIVERSAL: Funções para acesso consistente ao armazenamento (COMPATIBILIDADE TOTAL)
   function safeGetItem(key, defaultValue = null) {
     try {
       if (useMemoryStorage) {
         return memoryStorage[key] !== undefined ? memoryStorage[key] : defaultValue;
       }
       
       if (typeof localStorage !== 'undefined') {
         try {
           const value = localStorage.getItem(key);
           if (value === null) return defaultValue;
           
           // Tentar fazer parse JSON
           try {
             return JSON.parse(value);
           } catch (parseError) {
             // Se não for JSON válido, retornar string original
             console.warn(`⚠️ Valor de ${key} não é JSON válido, retornando string`);
             return value;
           }
         } catch (e) {
           console.warn(`⚠️ Erro ao ler ${key} do localStorage:`, e.message);
           // Fallback para memória
           return memoryStorage[key] !== undefined ? memoryStorage[key] : defaultValue;
         }
       }
       
       // Fallback final
       return memoryStorage[key] !== undefined ? memoryStorage[key] : defaultValue;
     } catch (e) {
       console.error(`❌ Erro crítico ao ler ${key}:`, e.message);
       return defaultValue;
     }
   }
   
   function safeSetItem(key, value) {
     try {
       if (useMemoryStorage) {
         memoryStorage[key] = value;
         return true;
       }
       
       if (typeof localStorage !== 'undefined') {
         try {
           const serialized = JSON.stringify(value);
           localStorage.setItem(key, serialized);
           return true;
         } catch (e) {
           // Verificar tipo específico de erro
           if (e.name === 'QuotaExceededError' || e.name === 'NS_ERROR_DOM_QUOTA_REACHED') {
             console.warn(`⚠️ Quota excedida ao salvar ${key}, usando memória`);
             memoryStorage[key] = value;
             return true;
           } else {
             console.warn(`⚠️ Erro ao salvar ${key} no localStorage:`, e.message);
             // Fallback para memória
             memoryStorage[key] = value;
             return true;
           }
         }
       }
       
       // Fallback para memória
       memoryStorage[key] = value;
       return true;
     } catch (e) {
       console.error(`❌ Erro crítico ao salvar ${key}:`, e.message);
       // Último recurso: tentar salvar em memória
       try {
         memoryStorage[key] = value;
         return true;
       } catch (e2) {
         console.error(`❌ Erro fatal ao salvar ${key} em memória`);
         return false;
       }
     }
   }
   
   function getOfflineQueue() {
     try {
       return safeGetItem(OFFLINE_QUEUE_KEY, []);
     } catch (error) {
       console.error('❌ Erro ao ler fila offline:', error);
       return [];
     }
   }
   
   function setOfflineQueue(queue) {
     try {
       safeSetItem(OFFLINE_QUEUE_KEY, queue);
       updateQueueCount();
     } catch (error) {
       console.error('❌ Erro ao salvar fila offline:', error);
     }
   }
   
   // 🛡️ FUNÇÃO CRÍTICA: Remove duplicações da fila offline
   function removeDuplicatesFromQueue(queue) {
     const uniqueItems = [];
     const seen = new Set();
     
     for (const item of queue) {
       // Criar chave única baseada nos dados essenciais
       const key = `${item.data.nome || item.data.NOME || ''}_${item.data.comum || item.data.COMUM || ''}_${item.data.cargo || item.data.CARGO || ''}_${item.data.uuid || item.data.UUID || ''}`;
       
       if (!seen.has(key)) {
         seen.add(key);
         uniqueItems.push(item);
       } else {
         console.warn('🧹 Duplicação removida da fila:', {
           nome: item.data.nome || item.data.NOME,
           comum: item.data.comum || item.data.COMUM,
           cargo: item.data.cargo || item.data.CARGO,
           id: item.id
         });
       }
     }
     
     return uniqueItems;
   }
   
   // 🧪 FUNÇÃO DE TESTE: Verificar diferenciação de gênero para Secretário/Secretária da Música
   async function testarDiferencacaoGeneroSecretario() {
     console.log('🧪 TESTE: Verificando diferenciação de gênero para Secretário/Secretária da Música...');
     
     // Simula dados de teste para FLÁVIA (feminino)
     const nomeTeste = 'FLÁVIA APARECIDA DE MORAES NASCIMENTO';
     const comumTeste = 'JARDIM COTIA';
     const cargoTeste = 'ORGANISTA'; // Cargo selecionado no formulário
     
     console.log('🧪 Dados de teste (FEMININO):', { nomeTeste, comumTeste, cargoTeste });
     
     if (!supabaseLoaded || !sb) {
       console.error('❌ Supabase não disponível para teste');
       return;
     }
     
     try {
       // Busca no banco para ver se a pessoa é Secretária da Música (feminino)
       const { data, error } = await sb
         .from(TABLE_CATALOGO)
         .select('nome, cargo, nivel, instrumento, comum')
         .ilike('comum', `%${comumTeste}%`)
         .ilike('nome', `%${nomeTeste}%`)
         .or('cargo.ilike.%ORGANISTA%,cargo.ilike.%EXAMINADORA%,cargo.ilike.%INSTRUTOR%,cargo.ilike.%INSTRUTORA%,cargo.ilike.%SECRETÁRIO DA MÚSICA%,cargo.ilike.%SECRETÁRIA DA MÚSICA%,cargo.ilike.%SECRETÁRIO DO GEM%,cargo.ilike.%SECRETÁRIA DO GEM%')
         .eq('ativo', true)
         .order('cargo', { ascending: true });
       
       console.log('🧪 Resultado da consulta:', { data, error });
       
       if (data && data.length > 0) {
         console.log('🧪 Registros encontrados:');
         data.forEach((r, index) => {
           console.log(`  ${index + 1}. Nome: "${r.nome}", Cargo: "${r.cargo}", Instrumento: "${r.instrumento}", Comum: "${r.comum}"`);
         });
         
         // Verifica especificamente a diferenciação de gênero
         const secretarioMusica = data.find(r => 
           r.cargo && r.cargo.toUpperCase().includes('SECRETÁRIO') && r.cargo.toUpperCase().includes('MÚSICA')
         );
         
         const secretariaMusica = data.find(r => 
           r.cargo && r.cargo.toUpperCase().includes('SECRETÁRIA') && r.cargo.toUpperCase().includes('MÚSICA')
         );
         
         if (secretarioMusica) {
           console.log('✅ SECRETÁRIO DA MÚSICA ENCONTRADO (MASCULINO):', secretarioMusica);
           console.log('🎯 Cargo correto deveria ser:', secretarioMusica.cargo);
           console.log('⚠️ ATENÇÃO: Nome feminino mas cargo masculino - pode estar incorreto!');
         } else if (secretariaMusica) {
           console.log('✅ SECRETÁRIA DA MÚSICA ENCONTRADA (FEMININO):', secretariaMusica);
           console.log('🎯 Cargo correto deveria ser:', secretariaMusica.cargo);
           console.log('✅ CORRETO: Nome feminino e cargo feminino!');
         } else {
           console.log('❌ Nenhum cargo de Secretário/Secretária da Música encontrado');
         }
       } else {
         console.log('❌ Nenhum registro encontrado para a pessoa');
       }
       
     } catch (error) {
       console.error('❌ Erro no teste:', error);
     }
   }
   
   // 🧪 FUNÇÃO DE TESTE: Verificar se duplicação offline foi corrigida
   function testarCorrecaoDuplicacaoOffline() {
     console.log('🧪 TESTE: Verificando se duplicação offline foi corrigida...');
     
     // Simula dados de teste
     const payloadTeste = {
       uuid: uuidv4(),
       nome: 'TESTE DUPLICAÇÃO',
       comum: 'TESTE',
       cargo: 'ORGANISTA',
       instrumento: 'ÓRGÃO',
       data_ensaio: new Date().toLocaleDateString('pt-BR'),
       data_ensaio_iso: new Date().toISOString().split('T')[0]
     };
     
     console.log('🧪 Dados de teste:', payloadTeste);
     
     // Testa adição à fila offline
     console.log('🧪 Testando adição à fila offline...');
     const id1 = addToOfflineQueue(payloadTeste);
     console.log('🧪 Primeira adição - ID:', id1);
     
     // Tenta adicionar novamente (deveria ser bloqueado)
     console.log('🧪 Tentando adicionar novamente (deveria ser bloqueado)...');
     const id2 = addToOfflineQueue(payloadTeste);
     console.log('🧪 Segunda adição - ID:', id2);
     
     // Verifica se são o mesmo ID (não duplicou)
     if (id1 === id2) {
       console.log('✅ SUCESSO: Duplicação foi prevenida!');
       console.log('✅ Ambas as tentativas retornaram o mesmo ID:', id1);
     } else {
       console.log('❌ FALHA: Duplicação ainda está ocorrendo!');
       console.log('❌ IDs diferentes:', id1, 'vs', id2);
     }
     
     // Verifica o conteúdo da fila
     const queue = getOfflineQueue();
     const itensComMesmoNome = queue.filter(item => 
       (item.data.nome || item.data.NOME) === payloadTeste.nome
     );
     
     console.log('🧪 Itens na fila com mesmo nome:', itensComMesmoNome.length);
     console.log('🧪 Total de itens na fila:', queue.length);
     
     if (itensComMesmoNome.length === 1) {
       console.log('✅ SUCESSO: Apenas 1 item na fila (sem duplicação)');
     } else {
       console.log('❌ FALHA: Múltiplos itens na fila (duplicação detectada)');
     }
     
     // Limpa os dados de teste
     console.log('🧪 Limpando dados de teste...');
     const queueLimpa = queue.filter(item => 
       (item.data.nome || item.data.NOME) !== payloadTeste.nome
     );
     setOfflineQueue(queueLimpa);
     console.log('🧪 Dados de teste removidos');
   }
   
   // 🧪 FUNÇÃO DE TESTE: Verificar captura de classe para cargos musicais
   async function testarCapturaClasseCargosMusicais() {
     console.log('🧪 TESTE: Verificando captura de classe para cargos musicais...');
     
     // Simula dados de teste para diferentes cargos
     const testes = [
       {
         nome: 'MAGDA DERTINATI SABINO',
         comum: 'CENTRO',
         cargo: 'EXAMINADORA DE ORGANISTAS',
         esperado: 'Classe de organista capturada'
       },
       {
         nome: 'CÍNTIA FERREIRA DE SOUZA',
         comum: 'PARQUE DO AGRESTE',
         cargo: 'SECRETÁRIA DA MÚSICA',
         esperado: 'Classe de organista capturada'
       },
       {
         nome: 'VIVIANE SOMOGGI GARCIA VILAR',
         comum: 'PARQUE DO AGRESTE',
         cargo: 'INSTRUTORA',
         esperado: 'Classe de organista capturada'
       },
       {
         nome: 'DANIELE CRISTINA DE SOUSA',
         comum: 'JARDIM MIRANDA',
         cargo: 'ORGANISTA',
         esperado: 'Classe com prefixo padronizada (RJM / OFICIALIZADO(A) → RJM / OFICIALIZADA)'
       }
     ];
     
     if (!supabaseLoaded || !sb) {
       console.error('❌ Supabase não disponível para teste');
       return;
     }
     
     for (const teste of testes) {
       console.log(`\n🧪 Testando: ${teste.nome} - ${teste.cargo}`);
       
       try {
         // Busca a classe de organista no banco
         const { data, error } = await sb
           .from(TABLE_CATALOGO)
           .select('cargo, nivel, instrumento')
           .ilike('nome', `%${teste.nome}%`)
           .ilike(COL_COMUM, `%${teste.comum}%`)
           .ilike('cargo', '%ORGANISTA%')
           .eq('ativo', true)
           .limit(1);
         
         console.log('🧪 Resultado da consulta:', { data, error });
         
         if (data && data.length > 0) {
           const registroOrganista = data[0];
           console.log('✅ REGISTRO DE ORGANISTA ENCONTRADO:', registroOrganista);
           
           if (registroOrganista.nivel) {
             console.log('✅ CLASSE DE ORGANISTA CAPTURADA:', registroOrganista.nivel);
             
             // Testa a lógica de padronização
             const classeOriginal = registroOrganista.nivel;
             let classePadronizada;
             
             if (classeOriginal.includes('/')) {
               const partes = classeOriginal.split('/');
               const prefixo = partes[0].trim();
               const sufixo = partes[1].trim();
               const sufixoPadronizado = sufixo.replace(/\(A\)/g, '').replace(/OFICIALIZADO/g, 'OFICIALIZADA').trim();
               classePadronizada = `${prefixo} / ${sufixoPadronizado}`;
               console.log('🎹 CLASSE COM PREFIXO SERÁ PADRONIZADA:', classeOriginal, '→', classePadronizada);
             } else {
               classePadronizada = classeOriginal.replace(/\(A\)/g, '').replace(/OFICIALIZADO/g, 'OFICIALIZADA').trim();
               console.log('🎹 CLASSE SERÁ PADRONIZADA PARA: "OFICIALIZADA" (sem o "(A)")');
             }
             
             console.log('🎯 RESULTADO: Classe real encontrada e padronizada');
           } else {
             console.log('⚠️ REGISTRO ENCONTRADO MAS SEM CLASSE - aplicando padrão "OFICIALIZADA"');
             console.log('🎯 RESULTADO: Classe padrão será aplicada');
           }
         } else {
           console.log('❌ NENHUM REGISTRO DE ORGANISTA ENCONTRADO - aplicando padrão "OFICIALIZADA"');
           console.log('🎯 RESULTADO: Classe padrão será aplicada');
         }
         
       } catch (error) {
         console.error('❌ Erro no teste:', error);
       }
     }
     
     console.log('\n🧪 TESTE CONCLUÍDO');
     console.log('💡 O sistema agora busca a classe real de organista para cargos musicais');
     console.log('💡 SEMPRE padroniza para "OFICIALIZADA" (sem o "(A)") para cargos musicais');
     console.log('💡 MANTÉM prefixos como "RJM / OFICIALIZADO(A)" → "RJM / OFICIALIZADA"');
     console.log('💡 Se não encontrar, aplica "OFICIALIZADA" como padrão');
   }
   
