   // 🛡️ FUNÇÃO DE EMERGÊNCIA: Limpar todas as duplicações do sistema
   function limparTodasDuplicacoes() {
     console.log('🧹 LIMPEZA DE EMERGÊNCIA: Removendo todas as duplicações...');
     
     let totalRemovidas = 0;
     
     // 1. Limpar fila offline principal
     const queue = getOfflineQueue();
     const cleanedQueue = removeDuplicatesFromQueue(queue);
     if (cleanedQueue.length !== queue.length) {
       totalRemovidas += (queue.length - cleanedQueue.length);
       setOfflineQueue(cleanedQueue);
       console.log(`🧹 Fila offline: ${queue.length - cleanedQueue.length} duplicações removidas`);
     }
     
     // 2. Limpar fila local (Google Sheets)
     try {
       const filaLocal = safeGetItem('fila_envio', []);
       const uniqueLocal = [];
       const seenLocal = new Set();
       
       for (const item of filaLocal) {
         const key = `${item.nome || item.NOME || ''}_${item.comum || item.COMUM || ''}_${item.cargo || item.CARGO || ''}_${item.uuid || item.UUID || ''}`;
         
         if (!seenLocal.has(key)) {
           seenLocal.add(key);
           uniqueLocal.push(item);
         }
       }
       
       if (uniqueLocal.length !== filaLocal.length) {
         totalRemovidas += (filaLocal.length - uniqueLocal.length);
         safeSetItem('fila_envio', uniqueLocal);
         console.log(`🧹 Fila local: ${filaLocal.length - uniqueLocal.length} duplicações removidas`);
       }
     } catch (error) {
       console.error('❌ Erro ao limpar fila local:', error);
     }
     
     // 3. Limpar fila Supabase
     try {
       const filaSupabase = safeGetItem('fila_supabase', []);
       const uniqueSupabase = [];
       const seenSupabase = new Set();
       
       for (const item of filaSupabase) {
         const key = `${item.nome || item.NOME || ''}_${item.comum || item.COMUM || ''}_${item.cargo || item.CARGO || ''}_${item.uuid || item.UUID || ''}`;
         
         if (!seenSupabase.has(key)) {
           seenSupabase.add(key);
           uniqueSupabase.push(item);
         }
       }
       
       if (uniqueSupabase.length !== filaSupabase.length) {
         totalRemovidas += (filaSupabase.length - uniqueSupabase.length);
         safeSetItem('fila_supabase', uniqueSupabase);
         console.log(`🧹 Fila Supabase: ${filaSupabase.length - uniqueSupabase.length} duplicações removidas`);
       }
     } catch (error) {
       console.error('❌ Erro ao limpar fila Supabase:', error);
     }
     
     // Atualizar contadores
     updateQueueCount();
     atualizarContadorFila();
     
     console.log(`✅ LIMPEZA CONCLUÍDA: ${totalRemovidas} duplicações removidas do sistema`);
     
     // Duplicações removidas - sem alertas
     
     return totalRemovidas;
   }
   
   function addToOfflineQueue(data) {
     try {
       // 🚨 VERIFICAÇÃO CRÍTICA: Verificar se já foi enviado ANTES de qualquer coisa
       // Isso previne que registros já enviados sejam adicionados à fila
       const sentRecords = safeGetItem('sent_records', {});
     
     // Verificar por UUID
     const dataUuid = data.uuid || data.UUID;
     if (dataUuid) {
       const recordKey = `gs_${dataUuid}`;
       if (sentRecords[recordKey]) {
         console.warn('🚨 BLOQUEIO CRÍTICO: Registro já foi enviado para Google Sheets (UUID):', dataUuid);
         console.warn('🚨 BLOQUEIO CRÍTICO: NÃO será adicionado à fila para evitar duplicação');
         return null; // Não adiciona à fila
       }
       
       // 🚨 VERIFICAÇÃO ADICIONAL: Verificar também por UUID no Supabase
       const supabaseKey = `sb_${dataUuid}`;
       if (sentRecords[supabaseKey]) {
         console.warn('🚨 BLOQUEIO CRÍTICO: Registro já foi enviado para Supabase (UUID):', dataUuid);
         console.warn('🚨 BLOQUEIO CRÍTICO: NÃO será adicionado à fila para evitar duplicação');
         return null; // Não adiciona à fila
       }
     }
     
     // Verificar por conteúdo (nome + comum + cargo)
     const contentKey = `content_${(data.nome || data.NOME || '').trim()}_${(data.comum || data.COMUM || '').trim()}_${(data.cargo || data.CARGO || '').trim()}`.replace(/\s+/g, '_').toLowerCase();
     if (sentRecords[contentKey]) {
       console.warn('🚨 BLOQUEIO CRÍTICO: Registro já foi enviado para Google Sheets (conteúdo):', contentKey);
       console.warn('🚨 BLOQUEIO CRÍTICO: NÃO será adicionado à fila para evitar duplicação');
       return null; // Não adiciona à fila
     }
     
     // 🚨 VERIFICAÇÃO ADICIONAL: Verificar se está na fila de processamento ativo
     if (window.activeSubmissions && dataUuid) {
       if (window.activeSubmissions.has(dataUuid)) {
         console.warn('🚨 BLOQUEIO CRÍTICO: Registro está sendo processado agora (UUID):', dataUuid);
         console.warn('🚨 BLOQUEIO CRÍTICO: NÃO será adicionado à fila para evitar duplicação');
         return null; // Não adiciona à fila
       }
     }
     
     const queue = getOfflineQueue();
     
     // 🛡️ VERIFICAÇÃO CRÍTICA: Prevenir duplicações
     const existingRecord = queue.find(item => {
       // Verifica se já existe um registro com os mesmos dados essenciais
       const sameName = (item.data.nome || item.data.NOME) === (data.nome || data.NOME);
       const sameComum = (item.data.comum || item.data.COMUM) === (data.comum || data.COMUM);
       const sameCargo = (item.data.cargo || item.data.CARGO) === (data.cargo || data.CARGO);
       const sameTimestamp = Math.abs(item.timestamp - Date.now()) < 60000; // 60 segundos (aumentado para maior segurança)
       
       return sameName && sameComum && sameCargo && sameTimestamp;
     });
     
     if (existingRecord) {
       console.warn('⚠️ DUPLICAÇÃO PREVENIDA: Registro já existe na fila:', {
         nome: data.nome || data.NOME,
         comum: data.comum || data.COMUM,
         cargo: data.cargo || data.CARGO,
         existingId: existingRecord.id,
         timeDiff: Math.abs(existingRecord.timestamp - Date.now())
       });
       return existingRecord.id; // Retorna o ID do registro existente
     }
     
     // 🚨 VERIFICAÇÃO ADICIONAL: Verificar duplicações por conteúdo exato
     const exactDuplicate = queue.find(item => {
       const itemData = item.data;
       const newData = data;
       
       // Comparar todos os campos principais
       const sameData = (
         (itemData.nome || itemData.NOME) === (newData.nome || newData.NOME) &&
         (itemData.comum || itemData.COMUM) === (newData.comum || newData.COMUM) &&
         (itemData.cargo || itemData.CARGO) === (newData.cargo || newData.CARGO) &&
         (itemData.instrumento || itemData.INSTRUMENTO) === (newData.instrumento || newData.INSTRUMENTO) &&
         (itemData.cidade || itemData.CIDADE) === (newData.cidade || newData.CIDADE)
       );
       
       return sameData && Math.abs(item.timestamp - Date.now()) < 300000; // 5 minutos
     });
     
     if (exactDuplicate) {
       console.warn('⚠️ DUPLICAÇÃO PREVENIDA: Registro idêntico já existe na fila:', {
         nome: data.nome || data.NOME,
         comum: data.comum || data.COMUM,
         cargo: data.cargo || data.CARGO,
         existingId: exactDuplicate.id
       });
       return exactDuplicate.id;
     }
     
     // 🛡️ VERIFICAÇÃO ADICIONAL: UUID nos dados (já verificado acima, mas verificar na fila)
     // dataUuid já foi declarado e verificado acima
     if (dataUuid) {
       // Verifica se já existe um registro com o mesmo UUID na fila
       const existingByUuid = queue.find(item => 
         (item.data.uuid || item.data.UUID) === dataUuid
       );
       
       if (existingByUuid) {
         console.warn('⚠️ DUPLICAÇÃO PREVENIDA: UUID já existe na fila:', dataUuid);
         return existingByUuid.id;
       }
       
       // 🚨 VERIFICAÇÃO CRÍTICA: Verificar se UUID já foi processado (BLOQUEIO DEFINITIVO)
       const processedUuids = safeGetItem('processed_uuids', []);
       if (processedUuids.includes(dataUuid)) {
         console.warn('⚠️ DUPLICAÇÃO PREVENIDA: UUID já foi processado:', dataUuid);
         return null; // Não adiciona à fila
       }
       
       // 🛡️ VERIFICAÇÃO CRÍTICA: Verificar se já foi enviado para Google Sheets (BLOQUEIO DEFINITIVO)
       // sentRecords já foi obtido acima, reutilizar
       const recordKey = `gs_${dataUuid}`;
       
       // Verificação DEFINITIVA - SEM TEMPO (já verificado acima, mas verificar novamente por segurança)
       if (sentRecords[recordKey]) {
         console.warn('⚠️ DUPLICAÇÃO PREVENIDA: Registro já foi enviado para Google Sheets:', dataUuid);
         return null; // Não adiciona à fila
       }
     } else {
       // Gera UUID se não existir
       const newUuid = uuidv4();
       data.uuid = newUuid;
       data.UUID = newUuid;
     }
     
     // Gerar ID único para o registro (SEMPRE UUID VÁLIDO)
     let recordId;
     try {
       recordId = uuidv4();
       
       // VERIFICAÇÃO OBRIGATÓRIA: UUID deve ser válido
       if (!isValidUUID(recordId)) {
         console.error('❌ UUID gerado é inválido, tentando corrigir...');
         recordId = fixInvalidUUID(recordId);
       }
       
       // VERIFICAÇÃO FINAL: Se ainda não for válido, usar UUID de emergência
       if (!isValidUUID(recordId)) {
         console.error('❌ CRÍTICO: Não foi possível gerar UUID válido!');
         recordId = '00000000-0000-4000-8000-000000000000';
       }
       
       console.log('✅ UUID final validado:', recordId);
       
     } catch (error) {
       console.error('❌ ERRO CRÍTICO ao gerar UUID:', error);
       recordId = '00000000-0000-4000-8000-000000000000';
     }
     
     const record = {
       id: recordId,
       data: data,
       timestamp: Date.now(),
       attempts: 0,
       synced: false
     };
     
     queue.push(record);
     setOfflineQueue(queue);
     
     // 🚨 CORREÇÃO CRÍTICA: Registrar UUID como processado para evitar duplicações futuras
     if (dataUuid) {
       const processedUuids = JSON.parse(localStorage.getItem('processed_uuids') || '[]');
       if (!processedUuids.includes(dataUuid)) {
         processedUuids.push(dataUuid);
         // Manter apenas os últimos 100 UUIDs para não sobrecarregar o localStorage
         if (processedUuids.length > 100) {
           processedUuids.splice(0, processedUuids.length - 100);
         }
         localStorage.setItem('processed_uuids', JSON.stringify(processedUuids));
       }
     }
     
     console.log('📋 Registro adicionado à fila offline:', recordId);
     console.log('📋 Total de itens na fila:', queue.length);
     
     // Log específico para mobile
     if (isMobile) {
       console.log('📱 MOBILE: Registro adicionado à fila offline:', {
         id: recordId,
         nome: data.nome || data.NOME || 'Sem nome',
         comum: data.comum || data.COMUM || 'Sem comum',
         cargo: data.cargo || data.CARGO || 'Sem cargo',
         timestamp: new Date().toLocaleTimeString()
       });
     }
     
     // Tentar processar imediatamente se online
     if (navigator.onLine) {
       setTimeout(async () => {
         try {
           const isOnline = await checkSupabaseConnection();
           if (isOnline) {
             await processOfflineQueue();
           }
         } catch (error) {
           console.error('❌ Erro no processamento imediato:', error);
         }
       }, 1000);
     }
     
     // 🚨 CORREÇÃO: Retornar o ID do registro para confirmar que foi adicionado
     return recordId;
     } catch (error) {
       console.error('❌ ERRO CRÍTICO em addToOfflineQueue:', error);
       console.error('❌ Stack trace:', error.stack);
       console.error('❌ Dados que causaram o erro:', data);
       // Retornar null em caso de erro para não quebrar o fluxo
       return null;
     }
   }
   
   function updateQueueCount() {
     const queue = getOfflineQueue();
     const pendingCount = queue.filter(item => !item.synced).length;
     
     // Atualizar elementos da UI se existirem
     const queueCountEl = document.getElementById('queue-count');
     const queueStatusEl = document.getElementById('queue-status');
     
     if (queueCountEl) {
       queueCountEl.textContent = pendingCount;
       
       // Atualizar status do badge
       if (queueStatusEl) {
         if (pendingCount > 0) {
           queueStatusEl.className = 'queue-badge pending';
           queueStatusEl.textContent = 'PENDENTE';
         } else {
           queueStatusEl.className = 'queue-badge empty';
           queueStatusEl.textContent = 'VAZIO';
         }
       }
       
       console.log(`📋 Fila offline: ${pendingCount} registro(s) pendente(s) de ${queue.length} total`);
     }
   }
   
   async function processOfflineQueue() {
     // Verificar se já está processando para evitar múltiplas execuções simultâneas
     if (window.offlineQueueProcessing) {
       console.log('⏳ Processamento da fila offline já em andamento, aguardando...');
       return;
     }
     
     window.offlineQueueProcessing = true;
     
     // 🚨 CORREÇÃO: Inicializar conjunto de processamento ativo se não existir
     if (!window.activeSubmissions) {
       window.activeSubmissions = new Set();
       console.log('🔧 Conjunto de processamento ativo inicializado');
     }
     
     try {
       const queue = getOfflineQueue();
       
       // 🛡️ LIMPEZA CRÍTICA: Remover duplicações antes de processar
       const cleanedQueue = removeDuplicatesFromQueue(queue);
       if (cleanedQueue.length !== queue.length) {
         console.log(`🧹 Removidas ${queue.length - cleanedQueue.length} duplicações da fila`);
         setOfflineQueue(cleanedQueue);
       }
       
       const pendingItems = cleanedQueue.filter(item => !item.synced);
       
       if (pendingItems.length === 0) {
         console.log('📋 Nenhum item pendente na fila offline');
         return;
       }
       
       console.log(`🔄 Processando ${pendingItems.length} itens da fila offline...`);
       
       // 🚨 CORREÇÃO CRÍTICA: Verificar conectividade REAL antes de processar
       // navigator.onLine pode ser falso positivo, então verificamos com checkSupabaseConnection
       const isReallyOnline = await checkSupabaseConnection();
       if (!isReallyOnline) {
         console.log('📴 Sem conexão real - pulando processamento da fila');
         window.offlineQueueProcessing = false; // Liberar lock
         return;
       }
       
       console.log('✅ Conectividade confirmada - processando fila offline');
       
       const processedItems = [];
       const failedItems = [];
       
       for (const item of pendingItems) {
         try {
           // 🛡️ VERIFICAÇÃO CRÍTICA MELHORADA: Verificar se já foi enviado recentemente (múltiplas camadas)
           const uuid = item.data.uuid || item.data.UUID;
           
           // Validação de dados antes de processar
           if (!item.data.cargo || item.data.cargo.trim() === '') {
             console.warn(`⚠️ Item ${item.id}: Cargo vazio - removendo da fila`);
             processedItems.push(item); // Remove da fila
             continue;
           }
           
           if (!item.data.nome || item.data.nome.trim() === '') {
             console.warn(`⚠️ Item ${item.id}: Nome vazio - removendo da fila`);
             processedItems.push(item); // Remove da fila
             continue;
           }
           
           if (uuid) {
             const sentRecords = safeGetItem('sent_records', {});
             
             // 1. Verificação DEFINITIVA por UUID - SEM TEMPO
             const recordKey = `gs_${uuid}`;
             if (sentRecords[recordKey]) {
               console.log(`✅ Item ${item.id}: Já foi enviado (BLOQUEIO DEFINITIVO - UUID), marcando como sincronizado`);
               item.synced = true;
               item.syncedAt = Date.now();
               processedItems.push(item);
               continue;
             }
             
             // 2. Verificação DEFINITIVA por conteúdo - SEM TEMPO
             const contentKey = `content_${(item.data.nome || '').trim()}_${(item.data.comum || '').trim()}_${(item.data.cargo || '').trim()}`.replace(/\s+/g, '_').toLowerCase();
             
             // Log específico para irmandade
             const cargoItemUpper = (item.data.cargo || '').toUpperCase();
             const isIrmandadeCheck = cargoItemUpper.includes('IRMANDADE');
             if (isIrmandadeCheck) {
               console.log(`🔍 DEBUG IRMANDADE - Verificação de duplicação:`, {
                 contentKey: contentKey,
                 sentRecordsHasKey: !!sentRecords[contentKey],
                 sentRecordsValue: sentRecords[contentKey]
               });
             }
             
             if (sentRecords[contentKey]) {
               console.log(`✅ Item ${item.id}: Já foi enviado (BLOQUEIO DEFINITIVO - CONTEÚDO), marcando como sincronizado`);
               if (isIrmandadeCheck) {
                 console.log(`🔍 DEBUG IRMANDADE - Item marcado como já enviado por conteúdo:`, contentKey);
               }
               item.synced = true;
               item.syncedAt = Date.now();
               processedItems.push(item);
               continue;
             }
           }
           
           // Log específico para irmandade
           const cargoItem = (item.data.cargo || '').toUpperCase();
           const isIrmandade = cargoItem.includes('IRMANDADE');
           
           if (isIrmandade) {
             console.log(`🔍 DEBUG IRMANDADE - Item ${item.id}:`, {
               uuid: item.data.uuid,
               nome: item.data.nome,
               comum: item.data.comum,
               cargo: item.data.cargo,
               cargoUpper: cargoItem
             });
           }
           
           // 🚨 VERIFICAÇÃO CRÍTICA DE DUPLICATAS NO BANCO: Verificar antes de processar
           const nomeVerificacao = item.data.nome || item.data.NOME || item.data['NOME COMPLETO'] || '';
           const comumVerificacao = item.data.comum || item.data.COMUM || '';
           const cargoVerificacao = item.data.cargo || item.data.CARGO || '';
           
           if (supabaseLoaded && sb && nomeVerificacao && comumVerificacao && cargoVerificacao) {
             try {
               const dataAtual = new Date();
               const dataISO = dataAtual.toISOString().split('T')[0];
               
               // Buscar registros duplicados (mesmo nome + comum + cargo no mesmo dia)
               const { data: duplicatas, error: dupError } = await sb
                 .from(TABLE_PRESENCAS)
                 .select('nome_completo, comum, cargo, created_at, uuid')
                 .ilike('nome_completo', `%${nomeVerificacao.trim()}%`)
                 .ilike('comum', `%${comumVerificacao.trim()}%`)
                 .gte('created_at', `${dataISO}T00:00:00.000Z`)
                 .lt('created_at', `${dataISO}T23:59:59.999Z`)
                 .limit(10);
               
               if (!dupError && duplicatas && duplicatas.length > 0) {
                 // Verificar se há duplicata exata (mesmo nome, comum e cargo)
                 const duplicataExata = duplicatas.find(d => {
                   const nomeMatch = norm(d.nome_completo || '').toUpperCase().trim() === norm(nomeVerificacao).toUpperCase().trim();
                   const comumMatch = compareComum(d.comum || '', comumVerificacao).match;
                   const cargoMatch = norm(d.cargo || '').toUpperCase().trim() === norm(cargoVerificacao).toUpperCase().trim();
                   return nomeMatch && comumMatch && cargoMatch;
                 });
                 
                 if (duplicataExata) {
                   // 🚨 CORREÇÃO: Verificar se usuário confirmou a duplicata antes de bloquear
                   const duplicataConfirmada = item.data.duplicataConfirmadaPeloUsuario === true || 
                                               item.data.duplicataConfirmadaPeloUsuario === 'true';
                   const platformType = isMobile ? 'MOBILE' : 'DESKTOP';
                   
                   if (duplicataConfirmada) {
                     console.log(`✅ ${platformType}: Item ${item.id}: Duplicata confirmada pelo usuário - permitindo envio mesmo com duplicata existente`, {
                       itemId: item.id,
                       nome: nomeVerificacao,
                       comum: comumVerificacao,
                       cargo: cargoVerificacao,
                       flagNoItem: item.data.duplicataConfirmadaPeloUsuario
                     });
                     // Não bloqueia - continua o processamento normalmente
                   } else {
                     console.log(`⚠️ ${platformType}: Item ${item.id}: Duplicata detectada mas flag não está ativa - bloqueando`);
                     console.error(`🚨🚨🚨 DUPLICATA DETECTADA NA FILA OFFLINE - BLOQUEANDO PROCESSAMENTO 🚨🚨🚨`, {
                       itemId: item.id,
                       nome: nomeVerificacao,
                       comum: comumVerificacao,
                       cargo: cargoVerificacao,
                       uuidExistente: duplicataExata.uuid,
                       dataExistente: duplicataExata.created_at
                     });
                     
                     // 🚨 BLOQUEIO COMPLETO: Marcar como sincronizado para não tentar novamente
                     item.synced = true;
                     item.syncedAt = Date.now();
                     processedItems.push(item);
                     console.log(`✅ Item ${item.id}: Duplicata detectada - marcado como sincronizado (não será enviado)`);
                     continue;
                   }
                 }
               }
             } catch (error) {
               // Se não conseguir verificar, continua o processamento (não bloqueia)
               console.warn(`⚠️ Erro ao verificar duplicatas para item ${item.id}:`, error);
             }
           }
           
           // 🚨 CORREÇÃO: Se item tem flag de duplicata confirmada, definir flag global antes de enviar
           const duplicataConfirmadaNoItem = item.data.duplicataConfirmadaPeloUsuario === true || 
                                             item.data.duplicataConfirmadaPeloUsuario === 'true';
           const platformType = isMobile ? 'MOBILE' : 'DESKTOP';
           if (duplicataConfirmadaNoItem) {
             window._duplicataConfirmadaPeloUsuario = true;
             console.log(`✅ ${platformType}: Item ${item.id}: Flag de duplicata confirmada detectada - definindo flag global para permitir envio`);
             console.log(`✅ ${platformType}: Flag window._duplicataConfirmadaPeloUsuario definida como:`, window._duplicataConfirmadaPeloUsuario);
           } else {
             console.log(`🔍 ${platformType}: Item ${item.id}: Flag de duplicata NÃO encontrada no item (item.data.duplicataConfirmadaPeloUsuario =`, item.data.duplicataConfirmadaPeloUsuario, ')');
           }
           
           console.log(`📤 Enviando item ${item.id}...`);
           console.log(`📤 Item ${item.id} - Dados:`, {
             nome: item.data.nome || item.data.NOME,
             comum: item.data.comum || item.data.COMUM,
             cargo: item.data.cargo || item.data.CARGO,
             uuid: item.data.uuid || item.data.UUID
           });
           
           // 🚨 CORREÇÃO CRÍTICA: Marcar como "em processamento" ANTES de enviar
           // Isso previne que o mesmo item seja processado múltiplas vezes durante oscilação
           const itemUuid = item.data.uuid || item.data.UUID;
           if (itemUuid && window.activeSubmissions) {
             if (window.activeSubmissions.has(itemUuid)) {
               console.warn(`⚠️ Item ${item.id}: Já está sendo processado (UUID: ${itemUuid}) - pulando`);
               continue; // Pula este item se já está sendo processado
             }
             window.activeSubmissions.add(itemUuid);
             console.log(`🔒 Item ${item.id}: Marcado como em processamento (UUID: ${itemUuid})`);
           }
           
           // 🚨 CORREÇÃO CRÍTICA: Tentar enviar para Google Sheets PRIMEIRO
           // A lógica deve ser: Google Sheets primeiro, depois Supabase
           let googleSheetsSuccess = false;
           try {
             console.log(`📤 Item ${item.id} - Chamando sendToGoogleSheets...`);
             googleSheetsSuccess = await sendToGoogleSheets(item.data);
             console.log(`📤 Item ${item.id} - Google Sheets resultado:`, googleSheetsSuccess);
             
             // 🚨 VALIDAÇÃO ADICIONAL: Verificar se realmente retornou true
             if (googleSheetsSuccess === true) {
               console.log(`✅ Item ${item.id} - Google Sheets confirmou sucesso (retornou true)`);
             } else {
               console.error(`❌ Item ${item.id} - Google Sheets retornou false ou valor inválido:`, googleSheetsSuccess);
               googleSheetsSuccess = false;
             }
           } catch (gsError) {
             console.error(`❌ Item ${item.id} - Erro ao enviar para Google Sheets:`, gsError);
             console.error(`❌ Item ${item.id} - Detalhes do erro:`, {
               message: gsError.message,
               name: gsError.name,
               stack: gsError.stack?.substring(0, 300)
             });
             googleSheetsSuccess = false;
           }
           
           // 🚨 CORREÇÃO: Limpar flag após envio para não afetar próximos itens
           if (duplicataConfirmadaNoItem) {
             window._duplicataConfirmadaPeloUsuario = false;
           }
           
           if (isIrmandade) {
             console.log(`🔍 DEBUG IRMANDADE - Resultado do envio:`, googleSheetsSuccess);
           }
           
           // 🚨 CORREÇÃO CRÍTICA: Só marcar como sincronizado se Google Sheets foi bem-sucedido
           if (googleSheetsSuccess) {
             console.log(`✅ Item ${item.id}: Google Sheets OK - enviando para Supabase...`);
             
             // 🛡️ CORREÇÃO: Também enviar para Supabase quando Google Sheets for bem-sucedido
             let supabaseSuccess = false;
             if (supabaseLoaded && sb) {
               try {
                 const supabaseResult = await insertSupabase(item.data);
                 console.log(`✅ Item ${item.id}: Supabase OK - resultado:`, supabaseResult);
                 
                 // 🚨 VALIDAÇÃO: Verificar se realmente inseriu
                 if (supabaseResult && (supabaseResult.success === true || supabaseResult.data)) {
                   supabaseSuccess = true;
                   console.log(`✅ Item ${item.id}: Supabase confirmou inserção bem-sucedida`);
                 } else {
                   console.warn(`⚠️ Item ${item.id}: Supabase retornou resultado inesperado:`, supabaseResult);
                   // Ainda considera sucesso se não houve erro
                   supabaseSuccess = true;
                 }
               } catch (e) {
                 // 🚨 TRATAMENTO ESPECÍFICO: Se for erro de duplicata bloqueada, considera sucesso e marca como sincronizado
                 if (e.message && e.message.includes('DUPLICATA_BLOQUEADA')) {
                   console.log(`✅ Item ${item.id}: Duplicata bloqueada - registro já existe no Supabase (não será enviado)`);
                   supabaseSuccess = true; // Considera sucesso pois já existe
                 } else if (e.code === '23505' || e.message.includes('duplicate key') || e.message.includes('already exists')) {
                   console.log(`✅ Item ${item.id}: Registro já existe no Supabase (duplicação evitada)`);
                   supabaseSuccess = true; // Considera sucesso pois já existe
                 } else {
                   console.error(`❌ Item ${item.id}: Erro no Supabase:`, e.message);
                   console.error(`❌ Item ${item.id}: Detalhes do erro Supabase:`, {
                     code: e.code,
                     message: e.message,
                     details: e.details
                   });
                   // 🚨 CORREÇÃO: Mesmo com erro no Supabase, se Google Sheets foi OK, marca como sincronizado
                   // O importante é que foi salvo no Google Sheets
                   supabaseSuccess = false; // Mas não bloqueia o envio
                 }
               }
             } else {
               console.warn(`⚠️ Item ${item.id}: Supabase não disponível - apenas Google Sheets foi salvo`);
               supabaseSuccess = true; // Considera sucesso se Supabase não está disponível
             }
             
             // 🚨 CORREÇÃO CRÍTICA: Só marca como sincronizado se Google Sheets foi bem-sucedido
             // Supabase é opcional - se falhar mas Google Sheets salvou, ainda marca como sincronizado
             item.synced = true;
             item.syncedAt = Date.now();
             processedItems.push(item);
             
             // 🚨 CORREÇÃO: Remover do conjunto de processamento ativo após sucesso
             if (itemUuid && window.activeSubmissions) {
               window.activeSubmissions.delete(itemUuid);
               console.log(`🔓 Item ${item.id}: Removido do conjunto de processamento (UUID: ${itemUuid})`);
             }
             
             console.log(`✅ Item ${item.id} enviado com sucesso (Google Sheets: OK, Supabase: ${supabaseSuccess ? 'OK' : 'Falhou mas não bloqueia'})`);
           } else {
             // 🚨 CORREÇÃO CRÍTICA: Se Google Sheets falhou, NÃO marca como sincronizado
             item.attempts = (item.attempts || 0) + 1;
             failedItems.push(item);
             
             // 🚨 CORREÇÃO: Remover do conjunto de processamento ativo após falha
             if (itemUuid && window.activeSubmissions) {
               window.activeSubmissions.delete(itemUuid);
               console.log(`🔓 Item ${item.id}: Removido do conjunto de processamento após falha (UUID: ${itemUuid})`);
             }
             
             console.error(`❌ Falha ao enviar item ${item.id} para Google Sheets (tentativa ${item.attempts}) - NÃO será marcado como sincronizado`);
           }
           
           // 🚨 CORREÇÃO: Pausa aumentada para 200ms (era 50ms - muito curto quebrava a lógica)
           await new Promise(resolve => setTimeout(resolve, 200));
           
         } catch (error) {
           // 🚨 CORREÇÃO: Remover do conjunto de processamento ativo em caso de erro
           const itemUuidError = item.data.uuid || item.data.UUID;
           if (itemUuidError && window.activeSubmissions) {
             window.activeSubmissions.delete(itemUuidError);
             console.log(`🔓 Item ${item.id}: Removido do conjunto de processamento após erro (UUID: ${itemUuidError})`);
           }
           
           // 🚨 TRATAMENTO ESPECÍFICO: Se for erro de duplicata bloqueada, marca como sincronizado
           if (error.message && error.message.includes('DUPLICATA_BLOQUEADA')) {
             console.log(`✅ Item ${item.id}: Duplicata bloqueada - registro já existe (não será enviado)`);
             item.synced = true;
             item.syncedAt = Date.now();
             processedItems.push(item);
           } else {
             // 🚨 CORREÇÃO CRÍTICA: Se Google Sheets falhou, NÃO marca como sincronizado
             console.error(`❌ Erro ao processar item ${item.id}:`, error);
             console.error(`❌ Item ${item.id} - Erro detalhado:`, {
               message: error.message,
               name: error.name,
               stack: error.stack?.substring(0, 200)
             });
             
             // Verificar se foi erro de Google Sheets
             const isGoogleSheetsError = error.message && (
               error.message.includes('Google Sheets') ||
               error.message.includes('Sem conexão') ||
               error.message.includes('Failed to fetch') ||
               error.message.includes('NetworkError')
             );
             
             if (isGoogleSheetsError) {
               console.error(`🚨 Item ${item.id}: Erro no Google Sheets - NÃO será marcado como sincronizado`);
             }
             
             item.attempts = (item.attempts || 0) + 1;
             failedItems.push(item);
             console.error(`❌ Item ${item.id} adicionado à lista de falhas (tentativa ${item.attempts})`);
           }
         }
       }
       
       // Atualizar fila removendo itens processados
       const updatedQueue = cleanedQueue.map(item => {
         const processed = processedItems.find(p => p.id === item.id);
         return processed || item;
       });
       
       setOfflineQueue(updatedQueue);
       
       if (processedItems.length > 0) {
         console.log(`✅ ${processedItems.length} itens processados com sucesso`);
         // showToast('success', 'Sincronizado', `${processedItems.length} registro(s) enviado(s)`, 2000); // Removido - alerta desnecessário
       }
       
       if (failedItems.length > 0) {
         console.log(`⚠️ ${failedItems.length} itens falharam e serão tentados novamente`);
       }
       
     } catch (error) {
       console.error('❌ Erro geral no processamento da fila offline:', error);
     } finally {
       // 🚨 CORREÇÃO: Sempre liberar o lock
       window.offlineQueueProcessing = false;
       
       // 🚨 CORREÇÃO: Limpar conjunto de processamento ativo para itens que foram processados
       // Isso previne que itens fiquem "travados" no conjunto
       if (window.activeSubmissions) {
         const queueAfter = getOfflineQueue();
         const processedUuids = new Set();
         queueAfter.forEach(item => {
           if (item.synced) {
             const uuid = item.data.uuid || item.data.UUID;
             if (uuid) processedUuids.add(uuid);
           }
         });
         
         // Remover apenas UUIDs que foram realmente processados
         processedUuids.forEach(uuid => {
           window.activeSubmissions.delete(uuid);
         });
         
         if (processedUuids.size > 0) {
           console.log(`🧹 Limpeza: ${processedUuids.size} UUID(s) removido(s) do conjunto de processamento ativo`);
         }
       }
     }
   }
   
   // 🚀 FUNÇÃO PARA APLICAR REGRAS DE GÊNERO: Padronizar "oficializado(a)" para "oficializada"
   function aplicarRegrasGenero(data) {
     if (!data) return data;
     
     // Cria uma cópia dos dados para não modificar o original
     const dadosProcessados = { ...data };
     
     // Lista de campos que podem conter "oficializado(a)"
     const camposParaProcessar = [
       'classe', 'CLASSE', 'nivel', 'NIVEL', 
       'classe_organista', 'CLASSE_ORGANISTA'
     ];
     
     // Processa cada campo
     camposParaProcessar.forEach(campo => {
       if (dadosProcessados[campo] && typeof dadosProcessados[campo] === 'string') {
         const valorOriginal = dadosProcessados[campo];
         
         // Aplica a regra: "OFICIALIZADO(A)" → "OFICIALIZADA"
         let valorProcessado = valorOriginal;
         
         // Verifica se tem prefixo (ex: "RJM / OFICIALIZADO(A)")
         if (valorProcessado.includes('/')) {
           const partes = valorProcessado.split('/');
           const prefixo = partes[0].trim();
           const sufixo = partes[1].trim();
           
           // Remove "(A)" do sufixo e padroniza para "OFICIALIZADA"
           const sufixoPadronizado = sufixo.replace(/\(A\)/g, '').replace(/OFICIALIZADO/g, 'OFICIALIZADA').trim();
           valorProcessado = `${prefixo} / ${sufixoPadronizado}`;
         } else {
           // Se não tem prefixo, apenas padroniza para "OFICIALIZADA"
           valorProcessado = valorProcessado.replace(/\(A\)/g, '').replace(/OFICIALIZADO/g, 'OFICIALIZADA').trim();
         }
         
         // Só atualiza se houve mudança
         if (valorProcessado !== valorOriginal) {
           dadosProcessados[campo] = valorProcessado;
           console.log(`🚀 Regra de gênero aplicada no campo ${campo}:`, valorOriginal, '→', valorProcessado);
         }
       }
     });
     
     return dadosProcessados;
   }

   // 🚀 FUNÇÃO ULTRA-OTIMIZADA: Envio rápido para Google Sheets
   async function sendToGoogleSheets(data) {
     try {
       // 🚀 APLICAR REGRA DE GÊNERO: Padronizar "oficializado(a)" para "oficializada"
       const dadosProcessados = aplicarRegrasGenero(data);
       console.log('🚀 Regras de gênero aplicadas:', dadosProcessados);
       
       // 🚨 VERIFICAÇÃO ROBUSTA DE DUPLICATAS: Verificar se usuário já confirmou duplicata
       // Se o usuário confirmou no modal, não bloquear novamente
       const duplicataJaConfirmada = window._duplicataConfirmadaPeloUsuario === true;
       
       if (duplicataJaConfirmada) {
         console.log('✅ Usuário já confirmou duplicata - permitindo cadastro');
         // Limpar flag após usar
         window._duplicataConfirmadaPeloUsuario = false;
         // Pular verificação de duplicata
       } else {
         // 🚨 VERIFICAÇÃO ROBUSTA DE DUPLICATAS: Verificar no Supabase antes de enviar
         const nomeVerificacao = dadosProcessados.nome || dadosProcessados.NOME || '';
         const comumVerificacao = dadosProcessados.comum || dadosProcessados.COMUM || '';
         const cargoVerificacao = dadosProcessados.cargo || dadosProcessados.CARGO || '';
         let isDuplicata = false;
         let duplicataInfo = null;
         
         // Verificar duplicatas no Supabase se disponível
         if (supabaseLoaded && sb && nomeVerificacao && comumVerificacao) {
           try {
             const dataAtual = new Date();
             const dataISO = dataAtual.toISOString().split('T')[0];
             
             // Buscar registros duplicados (mesmo nome + comum + cargo no mesmo dia)
             const { data: duplicatas, error: dupError } = await sb
               .from('presencas')
               .select('nome_completo, comum, cargo, created_at, uuid')
               .ilike('nome_completo', `%${nomeVerificacao.trim()}%`)
               .ilike('comum', `%${comumVerificacao.trim()}%`)
               .gte('created_at', `${dataISO}T00:00:00.000Z`)
               .lt('created_at', `${dataISO}T23:59:59.999Z`)
               .limit(10);
             
             if (!dupError && duplicatas && duplicatas.length > 0) {
               // Verificar se há duplicata exata (mesmo nome, comum e cargo)
               const duplicataExata = duplicatas.find(d => {
                 const nomeMatch = norm(d.nome_completo || '').toUpperCase().trim() === norm(nomeVerificacao).toUpperCase().trim();
                 const comumMatch = compareComum(d.comum || '', comumVerificacao).match;
                 const cargoMatch = norm(d.cargo || '').toUpperCase().trim() === norm(cargoVerificacao).toUpperCase().trim();
                 return nomeMatch && comumMatch && cargoMatch;
               });
               
               if (duplicataExata) {
                 isDuplicata = true;
                 duplicataInfo = {
                   encontrada: true,
                   uuid: duplicataExata.uuid,
                   data: duplicataExata.created_at,
                   totalEncontradas: duplicatas.length
                 };
                 console.error('🚨🚨🚨 DUPLICATA DETECTADA NO SUPABASE - BLOQUEANDO ENVIO 🚨🚨🚨', {
                   nome: nomeVerificacao,
                   comum: comumVerificacao,
                   cargo: cargoVerificacao,
                   uuidExistente: duplicataExata.uuid,
                   dataExistente: duplicataExata.created_at
                 });
                 // 🚨 BLOQUEIO COMPLETO: Retornar erro para impedir envio
                 throw new Error(`DUPLICATA_BLOQUEADA: Registro duplicado detectado. ${nomeVerificacao} de ${comumVerificacao} já foi cadastrado hoje.`);
               }
             }
           } catch (error) {
             // Se o erro for de duplicata bloqueada, propagar o erro
             if (error.message && error.message.includes('DUPLICATA_BLOQUEADA')) {
               throw error;
             }
             console.warn('⚠️ Erro ao verificar duplicatas no Supabase:', error);
             // Continua o envio apenas se não for erro de duplicata
           }
         }
       }
       
       // 🛡️ BLOQUEIO DEFINITIVO DE DUPLICAÇÕES: Verificação permanente (sem tempo)
       const uuid = dadosProcessados.uuid || dadosProcessados.UUID;
       
       if (uuid) {
         // 🛡️ FALLBACK: Usar wrapper universal para acesso consistente
         let sentRecords = safeGetItem('sent_records', {});
         
         // 1. Verificação DEFINITIVA por UUID - SEM LIMITE DE TEMPO
         const recordKey = `gs_${uuid}`;
         if (sentRecords[recordKey]) {
           console.warn('⚠️ DUPLICAÇÃO BLOQUEADA DEFINITIVAMENTE (UUID): Registro já foi enviado:', uuid);
           return true; // Retorna sucesso para evitar nova tentativa
         }
         
         // 2. Verificação DEFINITIVA por conteúdo (nome + comum + cargo) - SEM LIMITE DE TEMPO
         const contentKey = `content_${(dadosProcessados.nome || '').trim()}_${(dadosProcessados.comum || '').trim()}_${(dadosProcessados.cargo || '').trim()}`.replace(/\s+/g, '_').toLowerCase();
         if (sentRecords[contentKey]) {
           console.warn('⚠️ DUPLICAÇÃO BLOQUEADA DEFINITIVAMENTE (CONTEÚDO): Registro idêntico já foi enviado:', contentKey);
           return true;
         }
         
         // 3. Verificação na fila de processamento ativo (evita envios simultâneos)
         if (window.activeSubmissions && window.activeSubmissions.has(uuid)) {
           console.warn('⚠️ DUPLICAÇÃO BLOQUEADA (PROCESSAMENTO): Registro já está sendo processado:', uuid);
           return true;
         }
         
         // Marca como em processamento ANTES de enviar
         if (!window.activeSubmissions) window.activeSubmissions = new Set();
         window.activeSubmissions.add(uuid);
       }
       
       // 4. Validação crítica: Verificar se cargo está preenchido corretamente
       const cargo = dadosProcessados.cargo || dadosProcessados.CARGO;
       if (!cargo || cargo.trim() === '') {
         console.error('❌ ERRO CRÍTICO: Cargo não pode estar vazio ao enviar');
         if (uuid && window.activeSubmissions) window.activeSubmissions.delete(uuid);
         throw new Error('Cargo é obrigatório');
       }
       
       // Log específico para irmandade
       const cargoUpper = (cargo || '').toUpperCase();
       const isIrmandade = cargoUpper.includes('IRMANDADE');
       if (isIrmandade) {
         console.log('🔍 DEBUG IRMANDADE - sendToGoogleSheets:', {
           uuid: uuid,
           nome: dadosProcessados.nome || dadosProcessados.NOME,
           comum: dadosProcessados.comum || dadosProcessados.COMUM,
           cargo: cargo,
           cargoUpper: cargoUpper
         });
       }
       
       // 5. Validação crítica: Verificar se nome está preenchido corretamente
       const nome = dadosProcessados.nome || dadosProcessados.NOME;
       if (!nome || nome.trim() === '') {
         console.error('❌ ERRO CRÍTICO: Nome não pode estar vazio ao enviar');
         if (uuid && window.activeSubmissions) window.activeSubmissions.delete(uuid);
         throw new Error('Nome é obrigatório');
       }
       
       // 6. Validação crítica: Verificar se comum está preenchido corretamente
       const comum = dadosProcessados.comum || dadosProcessados.COMUM;
       if (!comum || comum.trim() === '') {
         console.error('❌ ERRO CRÍTICO: Comum não pode estar vazia ao enviar');
         if (uuid && window.activeSubmissions) window.activeSubmissions.delete(uuid);
         throw new Error('Comum é obrigatória');
       }
       
       // 🚀 OTIMIZAÇÃO: Geração rápida de horário
       const horarioRegistro = new Date().toLocaleTimeString('pt-BR', {
         timeZone: 'America/Sao_Paulo',
         hour: '2-digit',
         minute: '2-digit',
         second: '2-digit',
         hour12: false
       });
       
       // 🚀 OTIMIZAÇÃO: Construção direta sem logs verbosos
       const googleSheetsData = {
         "UUID": dadosProcessados.uuid || dadosProcessados.UUID || "",
         "NOME COMPLETO": dadosProcessados.nome || dadosProcessados.NOME || "",
         "COMUM": dadosProcessados.comum || dadosProcessados.COMUM || "",
         "CIDADE": dadosProcessados.cidade || dadosProcessados.CIDADE || dadosProcessados.local || dadosProcessados.LOCAL || "",
         "CARGO": dadosProcessados.cargo || dadosProcessados.CARGO || "",
         "INSTRUMENTO": dadosProcessados.instrumento || dadosProcessados.INSTRUMENTO || "",
         "NAIPE_INSTRUMENTO": dadosProcessados.naipe || dadosProcessados.NAIPE || dadosProcessados.naipe_instrumento || dadosProcessados.NAIPE_INSTRUMENTO || "",
         "CLASSE_ORGANISTA": dadosProcessados.classe || dadosProcessados.CLASSE || dadosProcessados.nivel || dadosProcessados.NIVEL || dadosProcessados.classe_organista || dadosProcessados.CLASSE_ORGANISTA || "",
         "LOCAL_ENSAIO": dadosProcessados.local_ensaio || dadosProcessados.LOCAL_ENSAIO || "",
         "DATA_ENSAIO": dadosProcessados.data_ensaio || dadosProcessados.DATA_ENSAIO || "",
         "HORÁRIO": horarioRegistro,
         "REGISTRADO_POR": dadosProcessados.registrado_por || dadosProcessados.REGISTRADO_POR || localStorage.getItem('current_user_name') || localStorage.getItem('session_user') || "Sistema",
         "USER_ID": dadosProcessados.user_id || dadosProcessados.USER_ID || "",
         "ANOTACOES": dadosProcessados.anotacoes || dadosProcessados.ANOTACOES || "",
         "SYNC_STATUS": "ATUALIZADO"
       };
       
       // 🚨 REMOVIDO: Não permitir envio de duplicatas - elas são bloqueadas antes de chegar aqui
       
       // 🎯 CORREÇÃO CRÍTICA: Determinar aba de destino baseado nas anotações
       // Se contém "SAM Desatualizado", envia para aba "Anotações"
       const anotacoes = googleSheetsData.ANOTACOES || '';
       const sheetDestino = (anotacoes.toUpperCase().includes('SAM DESATUALIZADO')) 
         ? 'Anotações' 
         : 'Dados';
       
       console.log('🔍 DEBUG - Detecção de anotações online:');
       console.log('  - anotacoes:', anotacoes);
       console.log('  - anotacoes.toUpperCase():', anotacoes.toUpperCase());
       console.log('  - includes SAM DESATUALIZADO:', anotacoes.toUpperCase().includes('SAM DESATUALIZADO'));
       console.log('  - sheetDestino:', sheetDestino);
       console.log('📤 Enviando para aba:', sheetDestino, anotacoes ? `(anotações: ${anotacoes})` : '');
       
       // 🚀 CORREÇÃO: Timeout otimizado para 15 segundos (equilíbrio entre segurança e performance)
       const controller = new AbortController();
       const timeoutId = setTimeout(() => controller.abort(), 15000);
       
       // 🚨 CORREÇÃO CRÍTICA: Verificar conectividade antes de tentar enviar
       if (!navigator.onLine) {
         console.error('❌ Google Sheets: Sem conexão - não é possível enviar');
         throw new Error('Sem conexão com a internet');
       }
       
       console.log('📤 Google Sheets: Iniciando envio para', sheetDestino);
       console.log('📤 Google Sheets: Dados a enviar:', {
         UUID: googleSheetsData.UUID,
         NOME: googleSheetsData['NOME COMPLETO'],
         COMUM: googleSheetsData.COMUM,
         CARGO: googleSheetsData.CARGO
       });
       console.log('📤 Google Sheets: URL do script:', "https://script.google.com/macros/s/AKfycbxPtvi86jPy7y41neTpIPvn3hpycd3cMjbgjgifzLD6qRwrJVPlF9EDulaQp42nma-i/exec");
       console.log('📤 Google Sheets: Payload completo:', JSON.stringify({
         op: 'append',
         sheet: sheetDestino,
         data: googleSheetsData
       }));
       
       console.log('📤 Google Sheets: Executando fetch...');
       let response;
       try {
         response = await fetch("https://script.google.com/macros/s/AKfycbxPtvi86jPy7y41neTpIPvn3hpycd3cMjbgjgifzLD6qRwrJVPlF9EDulaQp42nma-i/exec", {
           method: 'POST',
           headers: {
             'Content-Type': 'text/plain;charset=utf-8'
           },
           body: JSON.stringify({
             op: 'append',
             sheet: sheetDestino, // Usa aba determinada pela detecção de entrada manual
             data: googleSheetsData
           }),
           signal: controller.signal
         });
         console.log('📤 Google Sheets: Fetch concluído, status:', response.status);
       } catch (fetchError) {
         clearTimeout(timeoutId);
         console.error('❌ Google Sheets: Erro no fetch:', fetchError);
         throw new Error(`Erro ao executar fetch: ${fetchError.message}`);
       }
       
       clearTimeout(timeoutId);
       console.log('📤 Google Sheets: Timeout cancelado, processando resposta...');
       
       // 🚨 CORREÇÃO CRÍTICA: Verificar resposta de forma mais robusta
       const responseText = await response.text();
       console.log('📤 Google Sheets: Resposta recebida:', {
         status: response.status,
         ok: response.ok,
         responseText: responseText.substring(0, 200) // Primeiros 200 caracteres
       });
       
       // 🚨 CORREÇÃO CRÍTICA: Verificar se a resposta indica sucesso
       // Google Apps Script pode retornar status 200 mesmo com erro, então verificamos o conteúdo também
       const responseTextLower = responseText.toLowerCase().trim();
       const hasError = responseTextLower.includes('error') || 
                        responseTextLower.includes('erro') ||
                        responseTextLower.includes('failed') ||
                        responseTextLower.includes('falhou') ||
                        responseTextLower.includes('exception') ||
                        responseTextLower.includes('invalid') ||
                        responseTextLower.includes('inválido');
       
       // 🚨 CORREÇÃO CRÍTICA: Verificar se realmente salvou na planilha
       // Google Apps Script pode retornar 200 mesmo com erro, então verificamos o conteúdo
       const isSuccess = response.ok && 
                        (response.status === 200 || response.status === 201) &&
                        !hasError;
       
       // 🚨 CORREÇÃO: Se response.ok é true, status é 200/201 e NÃO há palavras de erro, considera sucesso
       // Não exige palavras explícitas de sucesso pois Google Apps Script pode retornar resposta vazia
       if (isSuccess) {
         console.log('✅ Google Sheets: Resposta confirmada como sucesso');
         console.log('✅ Google Sheets: Status:', response.status, '| OK:', response.ok, '| Sem erros detectados');
         console.log('✅ Google Sheets: Resposta:', responseText.substring(0, 100));
         // 🛡️ MARCAR COMO ENVIADO DEFINITIVAMENTE: Registrar permanente (SEM TEMPO)
         if (uuid) {
           // 🛡️ FALLBACK: Usar wrapper universal para acesso consistente
           let sentRecords = safeGetItem('sent_records', {});
           
           // 1. Marca por UUID - PERMANENTE (sem timestamp)
           sentRecords[`gs_${uuid}`] = true;
           
           // 2. Marca por conteúdo (nome + comum + cargo) - PERMANENTE
           const contentKey = `content_${(dadosProcessados.nome || '').trim()}_${(dadosProcessados.comum || '').trim()}_${(dadosProcessados.cargo || '').trim()}`.replace(/\s+/g, '_').toLowerCase();
           sentRecords[contentKey] = true;
           
           // 3. Limpa apenas se armazenamento estiver muito grande (>5MB)
           try {
             const storageSize = new Blob([JSON.stringify(sentRecords)]).size;
             if (storageSize > 5000000) { // 5MB
               // Limpa apenas registros mais antigos (com timestamp)
               Object.keys(sentRecords).forEach(key => {
                 if (typeof sentRecords[key] === 'number' && sentRecords[key] < Date.now() - 86400000) {
                   delete sentRecords[key];
                 }
               });
             }
           } catch (e) {
             // Ignora erro de limpeza
           }
           
           // Salva de forma consistente usando wrapper universal
           safeSetItem('sent_records', sentRecords);
           
           // Remove do conjunto de processamento ativo
           if (window.activeSubmissions) {
             window.activeSubmissions.delete(uuid);
           }
         }
         
         console.log('✅ Google Sheets: Enviado com sucesso para', sheetDestino);
         console.log('✅ Google Sheets: UUID enviado:', uuid);
         console.log('✅ Google Sheets: Registro salvo na planilha');
         console.log('✅ Google Sheets: Resposta completa:', {
           status: response.status,
           statusText: response.statusText,
           responseText: responseText.substring(0, 500),
           isSuccess: isSuccess,
           hasError: hasError
         });
         
         // 🚨 VALIDAÇÃO FINAL: Garantir que realmente salvou
         // Se chegou aqui, a validação passou - retornar true
         console.log('✅ Google Sheets: Validação completa - registro realmente salvo na planilha');
         return true;
       } else {
         // 🚨 CORREÇÃO CRÍTICA: Se a resposta não indica sucesso, lançar erro
         const errorMsg = hasError 
           ? `Google Sheets retornou erro na resposta: ${responseText.substring(0, 200)}`
           : `Google Sheets retornou status inválido: ${response.status} - ${response.statusText}`;
         
         console.error('❌ Google Sheets: Erro ao enviar', {
           status: response.status,
           statusText: response.statusText,
           ok: response.ok,
           hasError: hasError,
           isSuccess: isSuccess,
           responseText: responseText.substring(0, 200)
         });
         
         throw new Error(errorMsg);
       }
     } catch (error) {
       // Remove do conjunto de processamento ativo em caso de erro
       if (uuid && window.activeSubmissions) {
         window.activeSubmissions.delete(uuid);
       }
       
       // 🚨 CORREÇÃO: Tratamento específico para diferentes tipos de erro
       if (error.message && error.message.includes('DUPLICATA_BLOQUEADA')) {
         // 🚨 BLOQUEIO DE DUPLICATA: Retornar erro específico para ser tratado pelo chamador
         console.error('🚨🚨🚨 DUPLICATA BLOQUEADA - ENVIO CANCELADO 🚨🚨🚨');
         console.error('📋 Detalhes:', error.message);
         // Propagar o erro para que o chamador possa tratar adequadamente
         throw error;
       } else if (error.name === 'AbortError') {
         console.error('❌ Google Sheets: Timeout (15s)');
       } else if (error.message && (error.message.includes('Failed to fetch') || error.message.includes('CORS'))) {
         console.error('❌ Google Sheets: Erro de CORS ou conectividade');
         console.error('   Detalhes:', error.message);
         // 🚨 CORREÇÃO: Log detalhado para debug, mas retorna false para tratamento no handleSubmit
         console.error('   Isso geralmente indica problema de CORS no Google Apps Script ou falta de conexão');
       } else {
         console.error('❌ Google Sheets: Erro', error.message || error);
       }
       return false;
     }
   }
   
