   // === CONECTIVIDADE ROBUSTA (baseado no app que funciona) ===
   let isOnline = navigator.onLine; // Inicializar com o status real do navegador
   let connectivityCheckInterval = null;
   let lastConnectivityCheck = 0;
   let forceOfflineMode = false;
   
   // Detectar dispositivos móveis (variáveis já declaradas acima)
   const isChromeIOS = isIOS && /CriOS|Chrome/.test(navigator.userAgent);
   const isSafariIOS = isIOS && /Safari/.test(navigator.userAgent) && !/CriOS|Chrome/.test(navigator.userAgent);
   
   // 🛡️ FUNÇÃO CRÍTICA: Fetch com timeout compatível (COMPATIBILIDADE TOTAL)
   // 🚨 CORREÇÃO: Timeout padrão aumentado para 10 segundos (era 5s - muito curto para requisições lentas)
   async function fetchWithTimeout(url, options = {}, timeout = 10000) {
     try {
       // Verificar se AbortSignal.timeout está disponível
       if (typeof AbortSignal !== 'undefined' && AbortSignal.timeout) {
         // Método moderno (suportado em navegadores recentes)
         return await fetch(url, {
           ...options,
           signal: AbortSignal.timeout(timeout)
         });
       } else {
         // Fallback para AbortController (compatibilidade com navegadores antigos)
         const controller = new AbortController();
         const timeoutId = setTimeout(() => controller.abort(), timeout);
         
         try {
           const response = await fetch(url, {
             ...options,
             signal: controller.signal
           });
           clearTimeout(timeoutId);
           return response;
         } catch (error) {
           clearTimeout(timeoutId);
           if (error.name === 'AbortError') {
             throw new Error('Timeout: Requisição excedeu o tempo limite');
           }
           throw error;
         }
       }
     } catch (error) {
       // Tratamento de erro consistente
       if (error.name === 'AbortError' || error.message.includes('Timeout')) {
         console.warn(`⏱️ Timeout na requisição para ${url}`);
         throw new Error('Timeout: Requisição excedeu o tempo limite');
       }
       throw error;
     }
   }
   
   // Função para testar conectividade real (COMPATIBILIDADE TOTAL)
   async function testConnectivity() {
     try {
       if (forceOfflineMode) {
         console.log("🔧 Modo offline forçado ativo - retornando false");
         return false;
       }
       
       // Para protocolo file://, assumir online se o navegador estiver online
       if (window.location.protocol === 'file:') {
         console.log("📁 Protocolo file:// - verificando status do navegador");
         return navigator.onLine;
       }
       
       if (!navigator.onLine) {
         console.log("📴 Navegador reporta offline");
         return false;
       }
       
      // Verificação adicional para mobile (mais permissiva para iOS)
      if (navigator.connection) {
        const connection = navigator.connection;
        // CORREÇÃO iOS: Ser mais permissivo com conexões lentas
        if (connection.effectiveType === 'slow-2g' && connection.downlink < 0.1) {
          console.log("📴 Conexão extremamente lenta detectada - assumindo offline");
          return false;
        }
        // Remover verificação de RTT que pode causar falsos negativos no iOS
      }
       
      // 🚀 OTIMIZAÇÃO MOBILE: Teste unificado para Android e iOS (mesma performance)
      // Usar URL única e timeout unificado para garantir comportamento consistente
      const testUrls = [
        "https://www.google.com/favicon.ico" // URL única para ambas as plataformas
      ];
       
       let quickTestPassed = false;
       for (const url of testUrls) {
         try {
          // 🚨 CORREÇÃO CRÍTICA: Timeout aumentado para 8 segundos (era 2s - muito curto quebrava a lógica)
          // Timeout muito curto estava cancelando testes de conectividade antes que completassem
          const timeout = isMobile ? 8000 : 8000; // 8 segundos para mobile e desktop
          
           // Usar fetchWithTimeout para compatibilidade total
           const quickTest = await fetchWithTimeout(url, {
             method: 'HEAD',
             mode: 'no-cors',
             cache: 'no-store'
           }, timeout);
           
           console.log("✅ Teste rápido de conectividade passou:", url);
           quickTestPassed = true;
           break;
         } catch (quickError) {
           console.log("❌ Teste rápido falhou para:", url, quickError.message);
           continue;
         }
       }
       
       if (!quickTestPassed) {
         console.log("❌ Todos os testes rápidos falharam - assumindo offline");
         return false;
       }
       
       console.log("✅ Conectividade confirmada via teste rápido");
       return true;
       
     } catch (error) {
       console.log("❌ Conectividade falhou:", error.message);
       return false;
     }
   }
   
   // Função para atualizar status de conectividade
   async function updateConnectivityStatus() {
     if (forceOfflineMode) {
       console.log("🔧 Modo offline forçado ativo - pulando verificação automática");
       return isOnline;
     }
     
     const now = Date.now();
     
     // Evitar verificações muito frequentes (máximo a cada 2 segundos)
     if (now - lastConnectivityCheck < 2000) {
       return isOnline;
     }
     
     lastConnectivityCheck = now;
     
     // Verificar conectividade real
     const hasConnectivity = await testConnectivity();
     
     // Atualizar estado
     const wasOnline = isOnline;
     isOnline = hasConnectivity;
     
       // Sempre atualizar UI para garantir consistência
       updateStatusUI();
       
       // 🔧 CORREÇÃO CRÍTICA: Se voltou online, processar TODAS as filas
       if (isOnline && !wasOnline) {
         console.log("🌐 Conectividade restaurada - processando TODAS as filas");
         // Usar a função centralizada que processa todas as filas
         setTimeout(() => {
           processQueueOnConnectionRestore().catch(err => {
             console.error('❌ Erro ao processar filas após reconexão:', err);
           });
         }, 1000); // Aguardar 1s antes de sincronizar para garantir conexão estável
     }
     
     return isOnline;
   }
   
   // Função para atualizar a UI do status
   function updateStatusUI() {
     const statusIcon = document.getElementById('statusIcon');
     const statusText = document.getElementById('statusText');
     
     if (statusIcon && statusText) {
       if (isOnline) {
         statusIcon.classList.remove('offline');
         statusIcon.classList.add('online');
         statusText.textContent = "Online";
         console.log("✅ Status atualizado: Online");
       } else {
         statusIcon.classList.remove('online');
         statusIcon.classList.add('offline');
         statusText.textContent = "Offline";
         console.log("⚠️ Status atualizado: Offline");
       }
     }
   }
   
