   // === SISTEMA DE BACKUP AUTOMÁTICO ===
   let backupIntervalId = null;
   let lastBackupTime = null;
   
   // Função para criar backup dos dados
   function createBackup() {
     try {
       console.log('💾 Iniciando criação de backup...');
       
       const backupData = {
         timestamp: Date.now(),
         date: getCurrentTimestamp(),
         version: '1.0',
         data: {}
       };
       
       // Coletar dados do localStorage
       BACKUP_KEYS.forEach(key => {
         const value = localStorage.getItem(key);
         if (value !== null) {
           backupData.data[key] = value;
         }
       });
       
       // Adicionar dados da fila offline se configurado
       if (BACKUP_CONFIG.includeQueue) {
         const queue = getOfflineQueue();
         if (queue && queue.length > 0) {
           backupData.data.offline_queue = queue;
         }
       }
       
       // Comprimir dados se configurado
       let backupString;
       if (BACKUP_CONFIG.compress) {
         // Compressão simples usando JSON compacto
         backupString = JSON.stringify(backupData);
       } else {
         backupString = JSON.stringify(backupData, null, 2);
       }
       
       // Salvar backup
       const backupKey = `backup_${backupData.timestamp}`;
       localStorage.setItem(backupKey, backupString);
       
       // Atualizar lista de backups
       updateBackupList(backupKey, backupData);
       
       // Limpar backups antigos
       cleanupOldBackups();
       
       lastBackupTime = backupData.timestamp;
       
       // Atualizar timestamp do último backup
       localStorage.setItem('last_backup_time', backupData.timestamp.toString());
       
       console.log('✅ Backup criado com sucesso:', backupKey);
       // showToast('success', 'Backup Criado', 'Backup automático realizado com sucesso', 3000); // Removido - alerta desnecessário
       
       return backupKey;
       
     } catch (error) {
       console.error('❌ Erro ao criar backup:', error);
       // showToast('error', 'Erro no Backup', 'Falha ao criar backup automático', 3000); // Removido - alerta desnecessário para backup automático
       return null;
     }
   }
   
   // Função para restaurar backup
   function restoreBackup(backupKey) {
     try {
       console.log('🔄 Iniciando restauração do backup:', backupKey);
       
       const backupString = localStorage.getItem(backupKey);
       if (!backupString) {
         throw new Error('Backup não encontrado');
       }
       
       const backupData = JSON.parse(backupString);
       
       // Verificar se é um backup válido
       if (!backupData.data || !backupData.timestamp) {
         throw new Error('Formato de backup inválido');
       }
       
       // Restaurar dados
       Object.keys(backupData.data).forEach(key => {
         if (key !== 'offline_queue') {
           localStorage.setItem(key, backupData.data[key]);
         }
       });
       
       // Restaurar fila offline se existir
       if (backupData.data.offline_queue) {
         setOfflineQueue(backupData.data.offline_queue);
       }
       
       console.log('✅ Backup restaurado com sucesso');
       showToast('success', 'Backup Restaurado', 'Dados restaurados com sucesso', 3000);
       
       // Recarregar página para aplicar mudanças
       setTimeout(() => {
         window.location.reload();
       }, 2000);
       
       return true;
       
     } catch (error) {
       console.error('❌ Erro ao restaurar backup:', error);
       showToast('error', 'Erro na Restauração', 'Falha ao restaurar backup', 3000);
       return false;
     }
   }
   
   // Função para listar backups disponíveis
   function listBackups() {
     try {
       const backups = [];
       const keys = Object.keys(localStorage);
       
       keys.forEach(key => {
         if (key.startsWith('backup_')) {
           try {
             const backupString = localStorage.getItem(key);
             const backupData = JSON.parse(backupString);
             
             backups.push({
               key: key,
               timestamp: backupData.timestamp,
               date: backupData.date,
               size: backupString.length
             });
           } catch (error) {
             console.warn('⚠️ Backup corrompido ignorado:', key);
           }
         }
       });
       
       // Ordenar por timestamp (mais recente primeiro)
       backups.sort((a, b) => b.timestamp - a.timestamp);
       
       return backups;
       
     } catch (error) {
       console.error('❌ Erro ao listar backups:', error);
       return [];
     }
   }
   
   // Função para atualizar lista de backups
   function updateBackupList(backupKey, backupData) {
     try {
       const backupList = JSON.parse(localStorage.getItem('backup_list') || '[]');
       
       backupList.push({
         key: backupKey,
         timestamp: backupData.timestamp,
         date: backupData.date,
         size: JSON.stringify(backupData).length
       });
       
       // Ordenar por timestamp
       backupList.sort((a, b) => b.timestamp - a.timestamp);
       
       localStorage.setItem('backup_list', JSON.stringify(backupList));
       
     } catch (error) {
       console.error('❌ Erro ao atualizar lista de backups:', error);
     }
   }
   
   // Função para limpar backups antigos
   function cleanupOldBackups() {
     try {
       const backups = listBackups();
       
       if (backups.length > BACKUP_CONFIG.retention) {
         const backupsToRemove = backups.slice(BACKUP_CONFIG.retention);
         
         backupsToRemove.forEach(backup => {
           localStorage.removeItem(backup.key);
           console.log('🗑️ Backup antigo removido:', backup.key);
         });
         
         // Atualizar lista
         const updatedList = backups.slice(0, BACKUP_CONFIG.retention);
         localStorage.setItem('backup_list', JSON.stringify(updatedList));
         
         console.log(`✅ ${backupsToRemove.length} backup(s) antigo(s) removido(s)`);
       }
       
     } catch (error) {
       console.error('❌ Erro ao limpar backups antigos:', error);
     }
   }
   
   // Função para iniciar backup automático
   function startAutoBackup() {
     if (!BACKUP_CONFIG.autoBackup) {
       console.log('⏸️ Backup automático desabilitado');
       return;
     }
     
     // Verificar se já existe um intervalo ativo
     if (backupIntervalId) {
       clearInterval(backupIntervalId);
     }
     
     // Criar backup inicial se necessário
     const lastBackup = localStorage.getItem('last_backup_time');
     const now = Date.now();
     
     if (!lastBackup || (now - parseInt(lastBackup)) > BACKUP_CONFIG.interval) {
       console.log('🔄 Criando backup inicial...');
       createBackup();
     }
     
     // Configurar intervalo para backups automáticos
     backupIntervalId = setInterval(() => {
       console.log('⏰ Verificando necessidade de backup automático...');
       createBackup();
     }, BACKUP_CONFIG.interval);
     
     console.log(`✅ Backup automático iniciado (intervalo: ${BACKUP_CONFIG.interval / (1000 * 60 * 60)} horas)`);
   }
   
   // Função para parar backup automático
   function stopAutoBackup() {
     if (backupIntervalId) {
       clearInterval(backupIntervalId);
       backupIntervalId = null;
       console.log('⏹️ Backup automático parado');
     }
   }
   
   // Função para verificar status do backup
   function getBackupStatus() {
     const backups = listBackups();
     const lastBackup = localStorage.getItem('last_backup_time');
     
     return {
       enabled: BACKUP_CONFIG.autoBackup,
       interval: BACKUP_CONFIG.interval,
       retention: BACKUP_CONFIG.retention,
       totalBackups: backups.length,
       lastBackup: lastBackup ? new Date(parseInt(lastBackup)) : null,
       nextBackup: lastBackup ? new Date(parseInt(lastBackup) + BACKUP_CONFIG.interval) : null
     };
   }
   
   // Função para criar interface de gerenciamento de backup
