  // Função para determinar se um cargo é musical (deve receber anotação SAM DESATUALIZADO)
  function isCargoMusical(cargo) {
    if (!cargo) return false;
    
    const cargoUpper = cargo.toUpperCase();
    const cargoLower = cargo.toLowerCase();
    
    return cargoUpper.includes('MÚSICO') ||
           cargoUpper.includes('ORGANISTA') ||
           cargoUpper.includes('EXAMINADORA') ||
           cargoUpper.includes('INSTRUTORA') ||
           (cargoLower.includes('secretária') && cargoLower.includes('música'));
  }

