   // Função para inicializar Supabase
   async function initSupabase() {
     console.log('🔧 Tentando inicializar Supabase (opcional)...');
     
     // Configuração para desabilitar Supabase se necessário
     const SUPABASE_DISABLED = localStorage.getItem('supabase_disabled') === 'true';
     
     if (SUPABASE_DISABLED) {
       console.log('⚠️ Supabase desabilitado pelo usuário');
       supabaseLoaded = false;
       return false;
     }
     
     try {
       // 🚨 CORREÇÃO: Aguarda 500ms para garantir que o script carregou completamente (era 100ms - muito curto)
       await new Promise(resolve => setTimeout(resolve, 500));
       
       if (typeof window.supabase !== 'undefined' && typeof window.supabase.createClient === 'function') {
         console.log('🔧 Criando cliente Supabase...');
         // 🚨 CORREÇÃO: Configurar timeout de 30 segundos para consultas Supabase
         // Timeout muito curto estava cancelando consultas antes que completassem
         sb = window.supabase.createClient(SUPABASE_URL, SUPABASE_ANON_KEY, {
           db: {
             schema: 'public'
           },
           global: {
             headers: {
               'x-client-info': 'ccb-presenca'
             }
           },
           // Configurar timeout de 30 segundos para requisições
           fetch: (url, options = {}) => {
             const controller = new AbortController();
             const timeoutId = setTimeout(() => controller.abort(), 30000); // 30 segundos
             
             return fetch(url, {
               ...options,
               signal: controller.signal
             }).finally(() => {
               clearTimeout(timeoutId);
             });
           }
         });
         
         // Testar se o cliente foi criado corretamente
         if (sb && typeof sb.from === 'function') {
           supabaseLoaded = true;
           // 🚀 CORREÇÃO: Expor variáveis globalmente para o index.html
           window.supabaseLoaded = true;
           window.sb = sb;
           console.log('✅ Supabase carregado e inicializado com sucesso');
           console.log('✅ Variáveis expostas globalmente: window.supabaseLoaded =', window.supabaseLoaded);
           return true;
         } else {
           console.warn('⚠️ Cliente Supabase criado mas não funcional');
           supabaseLoaded = false;
           return false;
         }
       } else {
         console.warn('⚠️ Supabase não disponível - sistema funcionará apenas com Google Sheets');
         supabaseLoaded = false;
         // 🚀 CORREÇÃO: Expor variáveis mesmo quando Supabase não está disponível
         window.supabaseLoaded = false;
         window.sb = null;
         return false;
       }
     } catch (error) {
       console.warn('⚠️ Erro na inicialização do Supabase - sistema funcionará apenas com Google Sheets:', error.message);
       supabaseLoaded = false;
       // 🚀 CORREÇÃO: Expor variáveis mesmo em caso de erro
       window.supabaseLoaded = false;
       window.sb = null;
       return false;
     }
   }
   
  /* ===== HELPERS GERAIS ===== */
  // 🚨 CORREÇÃO: Remover logs excessivos de debug que geram spam no console
  // 🛡️ NORMALIZAÇÃO ROBUSTA CROSS-PLATFORM
  const norm  = s => {
    try {
      if (s === null || s === undefined) return '';
      // Garantir que é string e remover espaços extras
      let result = String(s).trim();
      // Remover caracteres de controle e caracteres invisíveis
      result = result.replace(/[\x00-\x1F\x7F-\x9F]/g, '');
      // Normalizar espaços múltiplos
      result = result.replace(/\s+/g, ' ');
      return result;
    } catch (e) {
      console.warn('⚠️ Erro na normalização:', e);
      return '';
    }
  };
  const upper = s => {
    try {
      return norm(s).toUpperCase();
    } catch (e) {
      console.warn('⚠️ Erro ao converter para maiúscula:', e);
      return '';
    }
  };
  // 🛡️ REMOÇÃO DE ACENTOS ROBUSTA CROSS-PLATFORM
  const noacc = s => {
    try {
      if (!s) return '';
      // Normalizar para NFD (decomposição canônica)
      let result = String(s).normalize('NFD');
      // Remover diacríticos (acentos)
      result = result.replace(/\p{Diacritic}/gu, '');
      // Fallback para navegadores antigos que não suportam \p{Diacritic}
      if (result === String(s)) {
        result = result
          .replace(/[\u0300-\u036f]/g, '') // Remover combining diacritical marks
          .replace(/[àáâãäå]/gi, 'a')
          .replace(/[èéêë]/gi, 'e')
          .replace(/[ìíîï]/gi, 'i')
          .replace(/[òóôõö]/gi, 'o')
          .replace(/[ùúûü]/gi, 'u')
          .replace(/[ç]/gi, 'c')
          .replace(/[ñ]/gi, 'n');
      }
      return result;
    } catch (e) {
      console.warn('⚠️ Erro ao remover acentos:', e);
      return String(s || '');
    }
  };
  const ucase = s => {
    try {
      return noacc(s).toUpperCase();
    } catch (e) {
      console.warn('⚠️ Erro ao converter sem acentos para maiúscula:', e);
      return '';
    }
  };
  
  // 🛡️ FUNÇÃO UTILITÁRIA: Comparação robusta de comum (cross-platform)
  // Centraliza a lógica de comparação de comum para garantir consistência
  // @param {string} comumRegistro - O valor de comum do registro
  // @param {string} comumBuscado - O valor de comum buscado
  // @param {object} options - Opções de debug (opcional)
  // @returns {object} - Objeto com resultado da comparação e detalhes para debug
  const compareComum = (comumRegistro, comumBuscado, options = {}) => {
    try {
      // Normalização prévia
      const comumRNormalizado = norm(comumRegistro || '');
      const comumValNormalizado = norm(comumBuscado || '');
      
      // Valores normalizados e sem acentos
      const comumRSemAcento = noacc(comumRNormalizado).toUpperCase().trim();
      const comumRUpper = comumRNormalizado.toUpperCase().trim();
      const comumValSemAcentoUpper = noacc(comumValNormalizado).toUpperCase().trim();
      const comumValUpper = comumValNormalizado.toUpperCase().trim();
      
      // Múltiplas estratégias de comparação para garantir robustez
      const match1 = comumRSemAcento.includes(comumValSemAcentoUpper);
      const match2 = comumRUpper.includes(comumValUpper);
      const match3 = comumValSemAcentoUpper.includes(comumRSemAcento);
      const match4 = comumValUpper.includes(comumRUpper);
      const match5 = comumRNormalizado.toUpperCase().trim() === comumValNormalizado.toUpperCase().trim();
      
      const match = match1 || match2 || match3 || match4 || match5;
      
      // Retorna objeto com resultado e detalhes para debug (se solicitado)
      const result = {
        match,
        comumRegistro: comumRNormalizado,
        comumBuscado: comumValNormalizado,
        matchDetails: options.debug ? {
          match1,
          match2,
          match3,
          match4,
          match5,
          comumRSemAcento,
          comumRUpper,
          comumValSemAcentoUpper,
          comumValUpper
        } : undefined
      };
      
      // 📊 Monitoramento automático (se disponível)
      if (window.monitorarComparacaoComum) {
        try {
          window.monitorarComparacaoComum.registrar(comumRegistro, comumBuscado, match, null);
        } catch (monitorError) {
          // Ignorar erros de monitoramento para não quebrar a função principal
          console.warn('⚠️ Erro no monitoramento:', monitorError);
        }
      }
      
      return result;
    } catch (e) {
      console.warn('⚠️ Erro na comparação de comum:', e);
      const errorResult = {
        match: false,
        error: e.message
      };
      
      // 📊 Registrar erro no monitoramento
      if (window.monitorarComparacaoComum) {
        try {
          window.monitorarComparacaoComum.registrar(comumRegistro, comumBuscado, false, e.message);
        } catch (monitorError) {
          // Ignorar erros de monitoramento
        }
      }
      
      return errorResult;
    }
  };
   
   // Função específica para normalizar instrumentos
  const normalizeInstrument = s => {
    let result = norm(s).toUpperCase();
    
    // Se a string está vazia, retorna vazio sem tentar normalizar
    if (!result || result.trim() === '') {
      console.log('🔍 DEBUG - normalizeInstrument(): entrada vazia, retornando vazio');
      return '';
    }
    
    // 🔧 CORREÇÃO: Normaliza variações do clarinete baixo (clarone)
    if (result.includes('CLARONE') || result.includes('CLARINETE BAIXO')) {
      // Se contém CLARONE ou CLARINETE BAIXO, garante que usa o nome completo padronizado
      if (result.includes('CLARONE') && !result.includes('CLARINETE BAIXO')) {
        // Se só tem CLARONE, converte para o nome completo
        result = 'CLARINETE BAIXO (CLARONE)';
      } else if (result.includes('CLARINETE BAIXO')) {
        // Garante que tenha os parênteses corretos
        if (!result.includes('(CLARONE)')) {
          result = result.replace(/CLARINETE\s*BAIXO.*/i, 'CLARINETE BAIXO (CLARONE)');
        } else {
          // Normaliza espaços extras nos parênteses
          result = result.replace(/CLARINETE\s*BAIXO\s*\(\s*CLARONE\s*\)/i, 'CLARINETE BAIXO (CLARONE)');
        }
      }
    }
    
    // 🚨 CORREÇÃO CRÍTICA: Normalizar "SAXOFONE SOPRANO (RETO)" para "SAXOFONE SOPRANO RET"
    // No banco de dados está armazenado como "SAXOFONE SOPRANO RET" (sem parênteses e sem "O")
    // Por isso precisamos normalizar para fazer match com o banco
    if (result.includes('SAXOFONE SOPRANO (RETO)')) {
      result = result.replace('SAXOFONE SOPRANO (RETO)', 'SAXOFONE SOPRANO RET');
    }
    if (result.includes('SAXOFONE SOPRANO (RET)')) {
      result = result.replace('SAXOFONE SOPRANO (RET)', 'SAXOFONE SOPRANO RET');
    }
    if (result.includes('SAXOFONE SOPRANO RETO') && !result.includes('SAXOFONE SOPRANO RET')) {
      // Se tem "SAXOFONE SOPRANO RETO" sem parênteses, normalizar para "SAXOFONE SOPRANO RET"
      result = result.replace('SAXOFONE SOPRANO RETO', 'SAXOFONE SOPRANO RET');
    }
    
    // Verifica se o resultado está na lista de instrumentos válidos
    // 🚨 CORREÇÃO CRÍTICA: Para SAXOFONE SOPRANO RET, não verificar na lista
    // O formato normalizado "SAXOFONE SOPRANO RET" não está na lista, mas está no banco
    // Por isso, se for SAXOFONE SOPRANO RET, manter como está para a busca funcionar
    if (!INSTRUMENTS_FIXED.includes(result)) {
      // Se for SAXOFONE SOPRANO RET, manter como está (está no banco assim)
      if (result.includes('SAXOFONE SOPRANO RET')) {
        console.log('🔍 SAXOFONE SOPRANO RET detectado - mantendo formato para busca (está no banco assim):', result);
        // Não alterar result, manter como está para a busca funcionar
      } else {
        console.warn('⚠️ Instrumento normalizado não encontrado na lista:', result);
        // Tenta encontrar um instrumento similar (apenas se result não for vazio)
        if (result && result.length > 0) {
          let similar = INSTRUMENTS_FIXED.find(inst => {
            // Busca exata
            if (inst === result) return true;
            // Busca por includes (ambas direções)
            if (inst.includes(result) || result.includes(inst)) return true;
            return false;
          });
          
          if (similar) {
            console.log('🔍 Instrumento similar encontrado:', similar, '(original:', result, ')');
            result = similar;
          }
        }
      }
    }
    
    console.log('🔍 DEBUG - normalizeInstrument():', { input: s, output: result });
    return result;
  };
  
  // 🔧 FUNÇÃO AUXILIAR: Compara instrumentos de forma robusta (especialmente para clarinete baixo e saxofone soprano)
  const matchInstrument = (instrumentoBusca, instrumentoBanco) => {
    if (!instrumentoBusca || !instrumentoBanco) return false;
    
    // Normaliza ambos os instrumentos
    const instBuscaNorm = normalizeInstrument(instrumentoBusca);
    const instBancoNorm = normalizeInstrument(instrumentoBanco);
    
    // Se ambos são vazios após normalização, não faz match
    if (!instBuscaNorm || !instBancoNorm) return false;
    
    // Comparação direta
    if (instBuscaNorm === instBancoNorm) return true;
    
    // 🔧 CORREÇÃO ESPECIAL: Para clarinete baixo, aceita qualquer variação
    if (instBuscaNorm.includes('CLARINETE BAIXO') || instBuscaNorm.includes('CLARONE') ||
        instBancoNorm.includes('CLARINETE BAIXO') || instBancoNorm.includes('CLARONE')) {
      const isClaroneBusca = instBuscaNorm.includes('CLARINETE BAIXO') || instBuscaNorm.includes('CLARONE');
      const isClaroneBanco = instBancoNorm.includes('CLARINETE BAIXO') || instBancoNorm.includes('CLARONE');
      if (isClaroneBusca && isClaroneBanco) {
        console.log('✅ Match CLARINETE BAIXO (CLARONE):', { instBuscaNorm, instBancoNorm });
        return true;
      }
    }
    
    // 🚨 CORREÇÃO ESPECÍFICA SAXOFONE SOPRANO: Aceita variações com/sem parênteses e RETO/RET
    if (instBuscaNorm.includes('SAXOFONE SOPRANO') && instBancoNorm.includes('SAXOFONE SOPRANO')) {
      const buscaTemReto = instBuscaNorm.includes('RETO') || instBuscaNorm.includes('RET');
      const bancoTemReto = instBancoNorm.includes('RETO') || instBancoNorm.includes('RET');
      if (buscaTemReto && bancoTemReto) {
        console.log('✅ Match SAXOFONE SOPRANO (RETO):', { instBuscaNorm, instBancoNorm });
        return true;
      }
    }
    
    // Comparação usando includes (fallback)
    return instBancoNorm.includes(instBuscaNorm) || instBuscaNorm.includes(instBancoNorm);
  };
   
   // Função para padronizar dados em maiúscula
   function padronizarDadosMaiuscula(dados) {
     if (!dados || typeof dados !== 'object') return dados;
     
     const dadosPadronizados = { ...dados };
     
     // 🛡️ PROTEÇÃO: Preserva o UUID original (NUNCA modificar UUID)
     const uuidOriginal = dados.uuid;
     
     // Campos que devem ser convertidos para maiúscula
     const camposMaiuscula = [
       'nome', 'nome_completo', 'comum', 'cidade', 'cargo', 'instrumento', 
       'naipe', 'naipe_instrumento', 'classe_organista', 'local_ensaio',
       'NOME COMPLETO', 'COMUM', 'CIDADE', 'CARGO', 'INSTRUMENTO', 
       'NAIPE_INSTRUMENTO', 'CLASSE_ORGANISTA', 'LOCAL_ENSAIO'
     ];
     
     // 🛡️ SEGURANÇA: Validação de comprimento máximo para campos de texto
     const MAX_FIELD_LENGTH = {
       nome: 255,
       comum: 255,
       cidade: 255,
       cargo: 100,
       instrumento: 100,
       anotacoes: 1000
     };
     
     camposMaiuscula.forEach(campo => {
       // Preserva null e undefined, só converte strings
       if (dadosPadronizados[campo] !== null && dadosPadronizados[campo] !== undefined && typeof dadosPadronizados[campo] === 'string') {
         // 🛡️ SEGURANÇA: Truncar campos que excedem comprimento máximo
         const campoKey = campo.toLowerCase().replace(/[_\s]/g, '');
         const maxLength = MAX_FIELD_LENGTH[campoKey] || 255;
         
         if (dadosPadronizados[campo].length > maxLength) {
           if (window.safeLog) {
             window.safeLog.warn(`⚠️ Campo ${campo} excedeu comprimento máximo (${maxLength}), truncando...`);
           }
           dadosPadronizados[campo] = dadosPadronizados[campo].substring(0, maxLength);
         }
         
         // 🛡️ SEGURANÇA: Remover caracteres de controle e normalizar
         dadosPadronizados[campo] = dadosPadronizados[campo]
           .replace(/[\x00-\x1F\x7F-\x9F]/g, '') // Remove caracteres de controle
           .trim();
         
         dadosPadronizados[campo] = upper(dadosPadronizados[campo]);
       }
     });
     
     // 🛡️ SEGURANÇA: Validar e sanitizar anotações
     if (dadosPadronizados.anotacoes && typeof dadosPadronizados.anotacoes === 'string') {
       if (dadosPadronizados.anotacoes.length > MAX_FIELD_LENGTH.anotacoes) {
         if (window.safeLog) {
           window.safeLog.warn(`⚠️ Campo anotacoes excedeu comprimento máximo, truncando...`);
         }
         dadosPadronizados.anotacoes = dadosPadronizados.anotacoes.substring(0, MAX_FIELD_LENGTH.anotacoes);
       }
       // Remover caracteres de controle
       dadosPadronizados.anotacoes = dadosPadronizados.anotacoes.replace(/[\x00-\x1F\x7F-\x9F]/g, '').trim();
     }
     
     // 🛡️ RESTAURA UUID ORIGINAL: Garante que o UUID nunca seja modificado
     if (uuidOriginal) {
       dadosPadronizados.uuid = uuidOriginal;
     }
     
     console.log('🔄 Dados padronizados em maiúscula:', dadosPadronizados);
     return dadosPadronizados;
   }
   
   // Função para obter o naipe do instrumento (PADRONIZADA)
   function getInstrumentNaipe(instrumento) {
     if (!instrumento) return null;
     const instrumentoUpper = upper(instrumento);
     const naipe = INSTRUMENT_NAIPES[instrumentoUpper];
     
     if (naipe) {
       console.log(`🎵 getInstrumentNaipe: ${instrumento} → ${naipe}`);
       return naipe;
     }
     
     // Busca parcial para instrumentos com variações
     for (const [instrumentoKey, naipeValue] of Object.entries(INSTRUMENT_NAIPES)) {
       if (instrumentoUpper.includes(instrumentoKey) || instrumentoKey.includes(instrumentoUpper)) {
         console.log(`🎵 getInstrumentNaipe (parcial): ${instrumento} → ${naipeValue}`);
         return naipeValue;
       }
     }
     
     console.log(`⚠️ getInstrumentNaipe: Naipe não encontrado para ${instrumento}`);
     return null;
   }
   
   // Função para normalizar cargos (remove variações de gênero)
   function normalizeCargo(cargo) {
     if (!cargo) return '';
     return upper(cargo)
       .replace(/\(A\)/g, '') // Remove (A)
       .replace(/\(O\)/g, '') // Remove (O)
       .replace(/\s+/g, ' ')  // Remove espaços extras
       .trim();
   }
   
   // Função para expandir busca de cargos (inclui variações de gênero)
   function expandCargoSearch(cargo) {
     if (!cargo) return [];
     
     const cargoNormalizado = normalizeCargo(cargo);
     const variacoes = [cargoNormalizado];
     
     // Se contém "SECRETÁRIO", adiciona variações
     if (cargoNormalizado.includes('SECRETÁRIO')) {
       variacoes.push(cargoNormalizado.replace('SECRETÁRIO', 'SECRETÁRIO (A)'));
       variacoes.push(cargoNormalizado.replace('SECRETÁRIO', 'SECRETÁRIO(A)'));
       // Também adiciona a busca original com acentos
       variacoes.push(cargo.replace('Secretário', 'Secretário (A)'));
       variacoes.push(cargo.replace('Secretário', 'Secretário(A)'));
     }
     
     // Se contém "MÚSICO", adiciona variações
     if (cargoNormalizado.includes('MÚSICO')) {
       variacoes.push(cargoNormalizado.replace('MÚSICO', 'MÚSICO (A)'));
       variacoes.push(cargoNormalizado.replace('MÚSICO', 'MÚSICO(A)'));
       // Também adiciona a busca original com acentos
       variacoes.push(cargo.replace('Músico', 'Músico (A)'));
       variacoes.push(cargo.replace('Músico', 'Músico(A)'));
     }
     
     // Se contém "ORGANISTA", adiciona variações
     if (cargoNormalizado.includes('ORGANISTA')) {
       variacoes.push(cargoNormalizado.replace('ORGANISTA', 'ORGANISTA (A)'));
       variacoes.push(cargoNormalizado.replace('ORGANISTA', 'ORGANISTA(A)'));
       // Também adiciona a busca original com acentos
       variacoes.push(cargo.replace('Organista', 'Organista (A)'));
       variacoes.push(cargo.replace('Organista', 'Organista(A)'));
     }
     
     return [...new Set(variacoes)]; // Remove duplicatas
   }
   
   
   /* ===== SISTEMA DE PESQUISA PARA COMUM ===== */
   let comumData = [];
   let searchCache = new Map(); // Cache para resultados de pesquisa
   
  function updateComumData() {
    // Atualiza os dados de pesquisa com as comuns atuais
    const comumInput = document.getElementById('comumInput');
    if (!comumInput) {
      console.error('❌ updateComumData: Campo comumInput não encontrado');
      return;
    }
    
    if (comumInput.dataset.comumList) {
      try {
        comumData = JSON.parse(comumInput.dataset.comumList);
        // Limpa o cache quando os dados são atualizados
        searchCache.clear();
        console.log('📋 Dados de comum atualizados:', comumData.length, 'itens');
      } catch (e) {
        console.error('❌ updateComumData: Erro ao parsear dados:', e);
        comumData = [];
        searchCache.clear();
      }
    } else {
      console.warn('⚠️ updateComumData: Dataset comumList não encontrado no campo');
      // Tenta buscar novamente após um pequeno delay
      setTimeout(() => {
        if (comumInput.dataset.comumList) {
          updateComumData();
        } else {
          console.warn('⚠️ updateComumData: Dataset ainda não disponível após delay');
        }
      }, 100);
    }
  }
   
   function highlightText(text, searchTerm) {
     if (!searchTerm) return text;
     
     const regex = new RegExp(`(${searchTerm.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})`, 'gi');
     return text.replace(regex, '<span class="highlight">$1</span>');
   }
   
   function searchComuns(searchTerm) {
     console.log('🔍 searchComuns chamada com termo:', searchTerm);
     console.log('🔍 comumData.length:', comumData.length);
     
     if (!searchTerm || searchTerm.length < 1) {
       console.log('🔍 Termo vazio, retornando TODAS as comuns (', comumData.length, ')');
       return comumData; // Retorna TODAS as comuns, sem limitação
     }
     
     const term = ucase(searchTerm);
     console.log('🔍 Termo normalizado:', term);
     
     // Cache mais eficiente
     if (searchCache.has(term)) {
       console.log('🔍 Resultado encontrado no cache');
       return searchCache.get(term);
     }
     
     // Pesquisa otimizada - busca por início primeiro
     let results = comumData.filter(comum => {
       const comumUpper = ucase(comum);
       return comumUpper.startsWith(term);
     });
     
     console.log('🔍 Resultados por início:', results.length, results);
     
     // 🚀 CORREÇÃO: Sempre busca por contém, independente do número de resultados por início
     const containsResults = comumData.filter(comum => {
       const comumUpper = ucase(comum);
       return comumUpper.includes(term) && !comumUpper.startsWith(term);
     });
     console.log('🔍 Resultados por contém:', containsResults.length, containsResults);
     results = results.concat(containsResults);
     
     // 🚨 CORREÇÃO CRÍTICA: Remover duplicatas dos resultados
     const resultsAntes = results.length;
     const resultsUnicos = new Set();
     results.forEach(comum => {
       if (comum && typeof comum === 'string') {
         resultsUnicos.add(comum.toUpperCase().trim());
       }
     });
     results = Array.from(resultsUnicos)
       .sort((a,b)=>a.localeCompare(b,'pt-BR'));
     
     if (results.length < resultsAntes) {
       console.warn(`⚠️ searchComuns: ${resultsAntes - results.length} duplicatas removidas dos resultados`);
     }
     
     // 🚀 CORREÇÃO: Remove limitação de resultados - retorna TODOS os resultados encontrados (sem duplicatas)
     console.log('🔍 Resultados finais (TODOS, sem duplicatas):', results.length, results);
     
     // Cache inteligente
     if (searchCache.size >= 100) {
       const firstKey = searchCache.keys().next().value;
       searchCache.delete(firstKey);
     }
     searchCache.set(term, results);
     
     return results;
   }
   
   function showComumResults(results, searchTerm) {
     const dropdown = document.getElementById('comumResults');
     if (!dropdown) {
       console.error('❌ Dropdown comumResults não encontrado!');
       return;
     }
     
     console.log('🔍 showComumResults chamada:', { results, searchTerm, resultsLength: results.length });
     
    if (results.length === 0) {
      // CORREÇÃO: Verificar se está no modal usando o dropdown
      const isInModal = dropdown.closest('#modalNovaComum');
      if (!isInModal) {
        dropdown.innerHTML = '<div class="suggestion-item no-suggestions">Nenhuma comum encontrada</div>';
        dropdown.classList.add('show');
        console.log('🔍 Mostrando "Nenhuma comum encontrada"');
      } else {
        dropdown.classList.remove('show');
        console.log('🔍 Modal detectado - não mostrando mensagem');
      }
    } else {
       // 🚨 CORREÇÃO: Normalizar comuns para maiúscula na exibição
       dropdown.innerHTML = results.map(comum => {
         const comumUpper = comum.toUpperCase();
         const searchTermUpper = searchTerm ? searchTerm.toUpperCase() : '';
         return `
         <div class="suggestion-item" data-value="${comum}">
           <i class="fa-solid fa-map-marker-alt"></i>
           <span>${highlightText(comumUpper, searchTermUpper)}</span>
         </div>
       `;
       }).join('');
       
       dropdown.classList.add('show');
       console.log('🔍 Mostrando', results.length, 'resultados');
     }
     
     // Ativa animação da seta
     const searchIcon = document.querySelector('.search-icon');
     if (searchIcon) {
       searchIcon.classList.add('active');
     }
     
     console.log('🔍 Dropdown deve estar visível agora');
   }
   
   function hideComumResults() {
     const dropdown = document.getElementById('comumResults');
     if (dropdown) {
       dropdown.classList.remove('show');
     }
     
     // Desativa animação da seta
     const searchIcon = document.querySelector('.search-icon');
     if (searchIcon) {
       searchIcon.classList.remove('active');
     }
     
     // Remove overlay no mobile (sempre remove para garantir)
     hideMobileOverlay();
   }
   
   // Funções para gerenciar overlay mobile
   function showMobileOverlay() {
     // Usar a variável global isMobile já declarada
     
     // Só usa overlay em mobile
     if (!isMobile) {
       return;
     }
     
     let overlay = document.getElementById('suggestionsOverlay');
     if (!overlay) {
       overlay = document.createElement('div');
       overlay.id = 'suggestionsOverlay';
       overlay.className = 'suggestions-overlay';
       document.body.appendChild(overlay);
       
       // Sistema unificado de eventos para mobile
       // Usar a variável global isMobile já declarada
       
       if (isMobile) {
         // Fecha dropdown ao tocar no overlay
         overlay.addEventListener('touchend', (e) => {
           e.preventDefault();
           e.stopPropagation();
           if (e.target === overlay) {
             hideComumResults();
           }
         }, { passive: false });
         
         // Previne scroll quando overlay está ativo
         overlay.addEventListener('touchmove', (e) => {
           e.preventDefault();
         }, { passive: false });
       } else {
         // Para desktop, usa click
         overlay.addEventListener('click', (e) => {
           if (e.target === overlay) {
             hideComumResults();
           }
         });
       }
     }
     overlay.classList.add('show');
   }
   
   function hideMobileOverlay() {
     const overlay = document.getElementById('suggestionsOverlay');
     if (overlay) {
       overlay.classList.remove('show');
     }
     
     // No Android, remove completamente o overlay se existir
     const isAndroid = /Android/.test(navigator.userAgent);
     if (isAndroid && overlay) {
       overlay.remove();
       console.log('🤖 Overlay removido do Android');
     }
   }
   
   function selectComumResult(comum) {
     const comumInput = document.getElementById('comumInput');
     if (comumInput) {
       // 🚨 CORREÇÃO: Normalizar para maiúscula ao selecionar
       comumInput.value = comum.toUpperCase();
       
       // Dispara evento de mudança para atualizar dependências
       const event = new Event('change', { bubbles: true });
       comumInput.dispatchEvent(event);
       
       // No mobile, remove o foco para fechar o teclado
       // Usar a variável global isMobile já declarada
       if (isMobile) {
         comumInput.blur();
         
         // Foca no próximo campo após um pequeno delay
         setTimeout(() => {
           const cargoField = document.getElementById('cargo');
           if (cargoField) {
             cargoField.focus();
             // Scroll suave para o campo de cargo
             cargoField.scrollIntoView({ behavior: 'smooth', block: 'center' });
           }
         }, 200);
       } else {
         // No desktop, foca no próximo campo imediatamente
         const cargoField = document.getElementById('cargo');
         if (cargoField) {
           setTimeout(() => cargoField.focus(), 100);
         }
       }
     }
     
     hideComumResults();
     
     // Log para debug
     console.log('✅ Comum selecionada:', comum);
   }
   
   function initComumSearch() {
     const comumInput = document.getElementById('comumInput');
     const comumResults = document.getElementById('comumResults');
     
     if (!comumInput || !comumResults) return;
     
     let searchTimeout;
     let isOpen = false;
     let highlightedIndex = -1;
     let currentResults = [];
     
     // Função para mostrar resultados apenas quando necessário
     function showResultsIfNeeded(searchTerm) {
       const hasResults = currentResults.length > 0;
       const hasSearchTerm = searchTerm && searchTerm.length > 0;
       
       console.log('🔍 showResultsIfNeeded:', { searchTerm, hasResults, hasSearchTerm, currentResults });
       
       // CORREÇÃO: Sempre mostra dropdown se houver termo de pesquisa
       if (hasSearchTerm) {
         showComumResults(currentResults, searchTerm);
         isOpen = true;
       } else {
         hideComumResults();
         isOpen = false;
       }
     }
     
     // Evento de digitação - OTIMIZADO PARA EFICIÊNCIA
     comumInput.addEventListener('input', (e) => {
       const searchTerm = e.target.value.trim();
       highlightedIndex = -1; // Reset seleção
       
       clearTimeout(searchTimeout);
       
       // Timeout mais rápido para melhor responsividade
       searchTimeout = setTimeout(() => {
         // CORREÇÃO: Garante que os dados estejam carregados
         if (comumData.length === 0) {
           console.log('🔍 Dados de comum vazios, tentando carregar...');
           updateComumData();
           
           // Se ainda estiver vazio, força carregamento
           if (comumData.length === 0) {
             console.log('🔍 Forçando carregamento de comuns...');
             loadComunsFromCatalog().then(() => {
               currentResults = searchComuns(searchTerm);
               showResultsIfNeeded(searchTerm);
             });
             return;
           }
         }
         
         currentResults = searchComuns(searchTerm);
         
         // 🚀 CORREÇÃO: Mostra dropdown apenas quando há texto digitado
         if (searchTerm && searchTerm.length > 0) {
           showResultsIfNeeded(searchTerm);
           isOpen = true;
         } else {
           hideComumResults();
           isOpen = false;
         }
       }, 150); // Aumentado para 150ms para melhor UX
     });
     
     // Evento de foco - NÃO mostra dropdown automaticamente quando vazio
     comumInput.addEventListener('focus', (e) => {
       const searchTerm = comumInput.value.trim();
       updateComumData();
       
       if (searchTerm && searchTerm.length > 0) {
         // Se há texto, busca normalmente
         currentResults = searchComuns(searchTerm);
         showResultsIfNeeded(searchTerm);
       } else {
         // 🚀 CORREÇÃO: Não mostra dropdown automaticamente quando vazio
         console.log('🔍 Campo vazio - dropdown não será mostrado automaticamente');
         hideComumResults();
         isOpen = false;
       }
     });
     
     // Evento de clique no campo - NÃO mostra dropdown automaticamente quando vazio
     comumInput.addEventListener('click', (e) => {
       const searchTerm = comumInput.value.trim();
       updateComumData();
       
       if (searchTerm && searchTerm.length > 0) {
         // Se há texto, busca normalmente
         currentResults = searchComuns(searchTerm);
         showResultsIfNeeded(searchTerm);
       } else {
         // 🚀 CORREÇÃO: Não mostra dropdown automaticamente quando vazio
         console.log('🔍 Campo vazio - dropdown não será mostrado automaticamente');
         hideComumResults();
         isOpen = false;
       }
     });
     
     // Evento de clique na seta do dropdown
     const searchIcon = document.querySelector('.search-icon');
     if (searchIcon) {
       searchIcon.addEventListener('click', (e) => {
         e.preventDefault();
         e.stopPropagation();
         
         if (!isOpen) {
           updateComumData();
           const searchTerm = comumInput.value.trim();
           
           if (searchTerm && searchTerm.length > 0) {
             currentResults = searchComuns(searchTerm);
             showResultsIfNeeded(searchTerm);
           } else {
             // 🚀 CORREÇÃO: Clique na seta mostra todas as comuns quando vazio
             console.log('🔍 Campo vazio - mostrando TODAS as comuns via clique na seta');
             currentResults = searchComuns(''); // Busca vazia retorna todas
             showComumResults(currentResults, '');
             isOpen = true;
           }
         } else {
           hideComumResults();
           isOpen = false;
           highlightedIndex = -1;
         }
       });
     }
     
     // Evento de clique nos resultados - SIMPLES E FUNCIONAL
     comumResults.addEventListener('click', (e) => {
       const item = e.target.closest('.suggestion-item');
       if (item) {
         e.preventDefault();
         e.stopPropagation();
         const value = item.dataset.value;
         selectComumResult(value);
         hideComumResults();
         isOpen = false;
         highlightedIndex = -1;
       }
     });
     
     // Evento de clique fora para fechar
     document.addEventListener('click', (e) => {
       if (!comumInput.contains(e.target) && !comumResults.contains(e.target)) {
         hideComumResults();
         isOpen = false;
         highlightedIndex = -1;
       }
     });
     
     // Navegação por teclado - MELHORADA
     comumInput.addEventListener('keydown', (e) => {
       const items = comumResults.querySelectorAll('.suggestion-item');
       
       switch (e.key) {
         case 'ArrowDown':
           e.preventDefault();
           if (items.length > 0) {
             highlightedIndex = Math.min(highlightedIndex + 1, items.length - 1);
             updateHighlight(items, highlightedIndex);
             scrollToSelected(items[highlightedIndex]);
           }
           break;
           
         case 'ArrowUp':
           e.preventDefault();
           if (items.length > 0) {
             highlightedIndex = Math.max(highlightedIndex - 1, 0);
             updateHighlight(items, highlightedIndex);
             scrollToSelected(items[highlightedIndex]);
           }
           break;
           
         case 'Enter':
           e.preventDefault();
           if (highlightedIndex >= 0 && items[highlightedIndex]) {
             const item = items[highlightedIndex];
             const value = item.dataset.value;
             selectComumResult(value);
             highlightedIndex = -1;
             isOpen = false;
           } else if (items.length > 0) {
             // Se não há item destacado, seleciona o primeiro
             const firstItem = items[0];
             const value = firstItem.dataset.value;
             selectComumResult(value);
             highlightedIndex = -1;
             isOpen = false;
           }
           break;
           
         case 'Escape':
           e.preventDefault();
           hideComumResults();
           highlightedIndex = -1;
           isOpen = false;
           comumInput.blur(); // Remove foco do campo
           break;
           
         case 'Tab':
           // Permite tab normal, mas fecha dropdown
           if (isOpen) {
             hideComumResults();
             isOpen = false;
             highlightedIndex = -1;
           }
           break;
       }
     });
     
     // Previne que o dropdown abra após envio do formulário
     comumInput.addEventListener('blur', (e) => {
       // 🔧 CORREÇÃO: Converte para maiúscula quando o campo perde o foco
       if (comumInput.value) {
         comumInput.value = comumInput.value.toUpperCase();
       }
       
       // Delay para permitir clique nos resultados
       setTimeout(() => {
         if (!comumResults.contains(document.activeElement)) {
           hideComumResults();
           isOpen = false;
           highlightedIndex = -1;
         }
       }, 150);
     });
     
     // CORREÇÃO: Inicialização forçada dos dados de comum
     console.log('🔍 Inicializando dados de comum...');
     updateComumData();
     
     // Se não há dados, força carregamento
     if (comumData.length === 0) {
       console.log('🔍 Dados vazios, forçando carregamento...');
       loadComunsFromCatalog().then(() => {
         console.log('🔍 Dados de comum carregados:', comumData.length, 'itens');
       });
     } else {
       console.log('🔍 Dados de comum já disponíveis:', comumData.length, 'itens');
     }
     
     function updateHighlight(items, index) {
       items.forEach((item, i) => {
         item.classList.toggle('selected', i === index);
         item.classList.toggle('highlighted', i === index);
       });
     }
     
     // Função auxiliar para scroll até item selecionado
     function scrollToSelected(item) {
       if (item) {
         item.scrollIntoView({
           behavior: 'smooth',
           block: 'nearest'
         });
       }
     }
   }
   
   /* ===== SISTEMA DE NOTIFICAÇÕES COM FALLBACK ===== */
   // 🎨 SISTEMA DE NOTIFICAÇÃO ELEGANTE E MODERNO
   function showFastAlert(type, title, message, duration = 800) {
     // 🚀 OTIMIZAÇÃO: Mobile - design moderno e rápido
     const notification = createElegantNotification(type, title, message, duration);
     
     // Adiciona ao DOM IMEDIATAMENTE
     document.body.appendChild(notification);
     
     // Posiciona IMEDIATAMENTE
     positionNotification(notification);
     
     // Animação de entrada INSTANTÂNEA (sem requestAnimationFrame para mobile)
     if (isMobile) {
       notification.classList.add('notification-enter');
     } else {
       requestAnimationFrame(() => {
         notification.classList.add('notification-enter');
       });
     }
     
     // Remove automaticamente (duração otimizada)
     setTimeout(() => {
       removeNotification(notification);
     }, duration);
   }
   
   function positionNotification(notification) {
     const existingNotifications = document.querySelectorAll('.elegant-notification');
     const index = existingNotifications.length;
     
     if (isMobile) {
       // 🚀 MOBILE: Design moderno centralizado com animação rápida
       notification.style.position = 'fixed';
       notification.style.top = '50%';
       notification.style.left = '50%';
       notification.style.right = 'auto';
       notification.style.bottom = 'auto';
       notification.style.transform = 'translate(-50%, -50%)';
       notification.style.width = 'calc(100vw - 32px)';
       notification.style.maxWidth = '380px';
       notification.style.margin = '0';
       notification.style.zIndex = '99999';
       notification.style.borderRadius = '20px';
       notification.style.boxShadow = '0 20px 60px rgba(0,0,0,0.3), 0 0 0 1px rgba(255,255,255,0.1)';
       notification.style.backdropFilter = 'blur(20px)';
     } else {
       // Para desktop: posicionamento no canto superior direito
       const topOffset = 20 + (index * 80); // 80px de espaçamento entre notificações
       notification.style.top = `${topOffset}px`;
       notification.style.right = '20px';
       notification.style.left = 'auto';
     }
   }
   
   function createElegantNotification(type, title, message, duration) {
     const notification = document.createElement('div');
     notification.className = 'elegant-notification';
     
     const icons = {
       success: '✓',
       error: '✕',
       warning: '⚠',
       info: 'ℹ',
       queue: '🚀'
     };
     
     const colors = {
       success: {
         bg: 'linear-gradient(135deg, #10b981 0%, #059669 50%, #047857 100%)',
         border: '#10b981',
         icon: '#ffffff',
         glow: 'rgba(16, 185, 129, 0.3)'
       },
       error: {
         bg: 'linear-gradient(135deg, #ef4444 0%, #dc2626 50%, #b91c1c 100%)',
         border: '#ef4444',
         icon: '#ffffff',
         glow: 'rgba(239, 68, 68, 0.3)'
       },
       warning: {
         bg: 'linear-gradient(135deg, #f59e0b 0%, #d97706 50%, #b45309 100%)',
         border: '#f59e0b',
         icon: '#ffffff',
         glow: 'rgba(245, 158, 11, 0.3)'
       },
       info: {
         bg: 'linear-gradient(135deg, #3b82f6 0%, #2563eb 50%, #1d4ed8 100%)',
         border: '#3b82f6',
         icon: '#ffffff',
         glow: 'rgba(59, 130, 246, 0.3)'
       },
       queue: {
         bg: 'linear-gradient(135deg, #8b5cf6 0%, #7c3aed 50%, #6d28d9 100%)',
         border: '#8b5cf6',
         icon: '#ffffff',
         glow: 'rgba(139, 92, 246, 0.3)'
       }
     };
     
     const config = colors[type] || colors.info;
     
     notification.innerHTML = `
       <div class="notification-content">
         <div class="notification-icon" style="background: ${config.bg}; color: ${config.icon}; box-shadow: 0 8px 20px ${config.glow};">
           ${icons[type] || icons.info}
         </div>
         <div class="notification-text">
           <div class="notification-title">${title}</div>
           <div class="notification-message">${message}</div>
         </div>
         <button class="notification-close" onclick="removeNotification(this.parentElement.parentElement)">
           ×
         </button>
       </div>
       <div class="notification-progress" style="background: linear-gradient(90deg, ${config.border}, ${config.border}dd); animation-duration: ${duration}ms;"></div>
       <div class="notification-glow" style="background: radial-gradient(circle, ${config.glow} 0%, transparent 70%);"></div>
     `;
     
     // Adiciona evento de clique para fechar
     notification.addEventListener('click', (e) => {
       if (!e.target.classList.contains('notification-close')) {
         removeNotification(notification);
       }
     });
     
     return notification;
   }
   
   function removeNotification(notification) {
     if (!notification) return;
     
     notification.classList.add('notification-exit');
     
     setTimeout(() => {
       if (notification.parentNode) {
         notification.parentNode.removeChild(notification);
         // Reposiciona as notificações restantes
         repositionRemainingNotifications();
       }
     }, 300);
   }
   
   function repositionRemainingNotifications() {
     const notifications = document.querySelectorAll('.elegant-notification');
     notifications.forEach((notification, index) => {
       const topOffset = 20 + (index * 80);
       notification.style.top = `${topOffset}px`;
     });
   }
   
   function removeAllNotifications() {
     const notifications = document.querySelectorAll('.elegant-notification');
     notifications.forEach(removeNotification);
   }
   
   // Sistema de alertas profissional e elegante
   // 🚨 CORREÇÃO: Simplificar para usar API padrão do SweetAlert2 (conforme documentação)
   function showToast(type, title, message = '', duration = 1500) {
     if (typeof Swal === 'undefined') {
       alert(`${title}: ${message}`);
       return;
     }
     
     // 🚨 CORREÇÃO: Usar API padrão do SweetAlert2 - simples e funcional
     // Conforme documentação: https://sweetalert2.github.io/#examples
     try {
       Swal.fire({
         icon: type || 'success',
         title: title,
         text: message,
         toast: true,
         position: 'top-end',
         showConfirmButton: false,
         timer: duration,
         timerProgressBar: true
       });
     } catch (error) {
       console.error('❌ Erro ao exibir SweetAlert2:', error);
       alert(`${title}: ${message}`);
     }
   }
   
   // 🚨 CORREÇÃO: Simplificar para usar API padrão do SweetAlert2
   function showConfirmAlert(title, text, confirmText = 'Sim', cancelText = 'Cancelar') {
     if (typeof Swal === 'undefined') {
       return Promise.resolve({ isConfirmed: confirm(text) });
     }
     
     return Swal.fire({
       title: title,
       text: text,
       icon: 'warning',
       showCancelButton: true,
       confirmButtonText: confirmText,
       cancelButtonText: cancelText
     });
   }
   
   // 🚨 CORREÇÃO: Simplificar para usar API padrão do SweetAlert2
   function showLoadingAlert(title = 'Carregando...', text = 'Aguarde um momento') {
     if (typeof Swal === 'undefined') {
       return;
     }
     
     return Swal.fire({
       title: title,
       text: text,
       allowOutsideClick: false,
       allowEscapeKey: false,
       showConfirmButton: false,
       didOpen: () => {
         Swal.showLoading();
       }
     });
   }
   
   // Função para fechar alertas de loading
   function hideLoadingAlert() {
     Swal.close();
   }
   
   // 🚨 CORREÇÃO: Simplificar para usar API padrão do SweetAlert2
   function showLoading(title = 'Processando...', message = 'Aguarde um momento') {
     if (typeof Swal === 'undefined') {
       return;
     }
     
     return Swal.fire({
       title: title,
       text: message,
       allowOutsideClick: false,
       allowEscapeKey: false,
       showConfirmButton: false,
       didOpen: () => {
         Swal.showLoading();
       }
     });
   }
   
   // Função para esconder loading
   function hideLoading() {
     if (typeof Swal !== 'undefined') {
       Swal.close();
     }
   }
   
   /* ===== SISTEMA DE EDIÇÃO DE REGISTROS ===== */
   
   // Função para verificar se o usuário pode editar um registro específico
   async function podeEditarRegistro(registro) {
     try {
       console.log('🔍 Verificando permissão para editar registro:', registro);
       
       // 1. Verificar se é usuário master
       const isMaster = await verificarStatusMaster();
       if (!isMaster) {
         console.log('❌ Usuário não é master - sem permissão para editar');
         return { pode: false, motivo: 'Usuário não é master' };
       }
       
       // 2. Verificar se o registro pertence ao local do usuário
       const sessionLocal = localStorage.getItem('session_local');
       const registroLocal = registro.local_ensaio || registro.LOCAL_ENSAIO || '';
       
       console.log('🔍 Comparando locais:', { sessionLocal, registroLocal });
       
       if (!sessionLocal) {
         console.log('❌ Usuário não tem local definido');
         return { pode: false, motivo: 'Usuário não tem local definido' };
       }
       
       // Verificar se os locais coincidem (case insensitive)
       const locaisCoincidem = sessionLocal.toLowerCase().trim() === registroLocal.toLowerCase().trim();
       
       if (!locaisCoincidem) {
         console.log('❌ Registro não pertence ao local do usuário');
         return { 
           pode: false, 
           motivo: `Registro pertence a "${registroLocal}" mas usuário é de "${sessionLocal}"` 
         };
       }
       
       console.log('✅ Usuário pode editar o registro');
       return { pode: true, motivo: 'Permissão concedida' };
       
     } catch (error) {
       console.error('❌ Erro ao verificar permissão de edição:', error);
       return { pode: false, motivo: 'Erro na verificação' };
     }
   }
   
   // Função para buscar registros editáveis pelo usuário
   async function buscarRegistrosEditaveis() {
     try {
       console.log('🔍 Buscando registros editáveis...');
       
       if (!supabaseLoaded || !sb) {
         console.log('❌ Supabase não disponível');
         return { sucesso: false, dados: [], erro: 'Supabase não disponível' };
       }
       
       const sessionLocal = localStorage.getItem('session_local');
       if (!sessionLocal) {
         console.log('❌ Usuário não tem local definido');
         return { sucesso: false, dados: [], erro: 'Usuário não tem local definido' };
       }
       
       // Buscar registros do local do usuário
       const { data, error } = await sb
         .from(TABLE_PRESENCAS)
         .select('*')
         .ilike('local_ensaio', `%${sessionLocal}%`)
         .order('created_at', { ascending: false })
         .limit(100); // Limitar a 100 registros mais recentes
       
       if (error) {
         console.error('❌ Erro ao buscar registros:', error);
         return { sucesso: false, dados: [], erro: error.message };
       }
       
       console.log(`✅ Encontrados ${data.length} registros editáveis`);
       return { sucesso: true, dados: data, erro: null };
       
     } catch (error) {
       console.error('❌ Erro geral ao buscar registros:', error);
       return { sucesso: false, dados: [], erro: error.message };
     }
   }
   
