   /* ===== CACHE OFFLINE ===== */
   const CACHE_KEYS = {
     COMUNS: 'cache_comuns',
     INSTRUMENTOS: 'cache_instrumentos',
     CARGOS: 'cache_cargos',
     NOMES: 'cache_nomes',
     LAST_UPDATE: 'cache_last_update'
   };
   
   function getCacheKey(key, params = {}) {
     // Cria uma chave mais específica e limpa
     const cleanParams = {};
     if (params.comumVal) cleanParams.comum = params.comumVal.toLowerCase().replace(/\s+/g, '_');
     if (params.instVal) cleanParams.inst = params.instVal.toLowerCase().replace(/\s+/g, '_');
     if (params.cargoVal) cleanParams.cargo = params.cargoVal.toLowerCase().replace(/\s+/g, '_');
     
     return `${key}_${JSON.stringify(cleanParams)}`;
   }
   
   function setCache(key, data, ttl = 24 * 60 * 60 * 1000) {
     const cacheData = {
       data,
       timestamp: Date.now(),
       ttl
     };
     localStorage.setItem(key, JSON.stringify(cacheData));
   }
   
   function getCache(key) {
     try {
       const cached = localStorage.getItem(key);
       if (!cached) return null;
       
       const { data, timestamp, ttl } = JSON.parse(cached);
       const now = Date.now();
       
       if (now - timestamp > ttl) {
         localStorage.removeItem(key);
         return null;
       }
       
       return data;
     } catch (e) {
       localStorage.removeItem(key);
       return null;
     }
   }
   
   function clearCache() {
     Object.values(CACHE_KEYS).forEach(key => {
       localStorage.removeItem(key);
     });
     Object.keys(localStorage).forEach(key => {
       if (key.startsWith('cache_')) {
         localStorage.removeItem(key);
       }
     });
   }
   
   /* ===== INDICADOR DE CONEXÃO ===== */
   function setStatus(ok, msg){
     const statusIcon = document.getElementById('statusIcon');
     const statusText = document.getElementById('statusText');
     const connectionStatus = document.getElementById('connectionStatus');
     
     if (statusIcon && statusText && connectionStatus) {
       if (ok) {
         statusIcon.className = 'fa-solid fa-wifi status-icon online';
         statusText.textContent = 'Online';
         connectionStatus.className = 'connection-status online';
         connectionStatus.title = 'Conectado ao Supabase';
       } else {
         statusIcon.className = 'fa-solid fa-wifi-slash status-icon offline';
         statusText.textContent = 'Offline';
         connectionStatus.className = 'connection-status offline';
         connectionStatus.title = 'Sem conexão - Modo offline';
       }
     }
   }
   
   // 🚀 FUNÇÃO ESTÁVEL: Verificação de conectividade robusta e confiável
   // 🚀 OTIMIZAÇÃO: Cache de resultados para evitar verificações repetidas
   let lastSupabaseCheck = 0;
   let cachedSupabaseResult = null;
   const SUPABASE_CACHE_DURATION = 2000; // 2 segundos de cache
   
   async function checkSupabaseConnection(){
     try {
       // 🚀 OTIMIZAÇÃO: Usar cache se a verificação foi feita recentemente
       const now = Date.now();
       if (cachedSupabaseResult !== null && (now - lastSupabaseCheck) < SUPABASE_CACHE_DURATION) {
         return cachedSupabaseResult;
       }
       
       // Verificação básica do navegador (rápida)
       if (!navigator.onLine) {
         console.log('📴 Navegador reporta offline');
         setStatus(false, 'Offline');
         cachedSupabaseResult = false;
         lastSupabaseCheck = now;
         return false;
       }
       
      // 🚨 CORREÇÃO: Timeout aumentado para 8 segundos (era 2s - muito curto quebrava a lógica)
      const timeout = 8000; // 8 segundos (timeout muito curto cancelava requisições)
       
       // MÉTODO 1: Teste de conectividade básica (compatível com file://)
       try {
         // Se estiver em file://, usar teste diferente
         if (window.location.protocol === 'file:') {
           console.log('📁 Protocolo file:// detectado - usando teste básico');
           // Para file://, apenas verificar se o navegador está online
           if (navigator.onLine) {
             console.log('✅ Navegador online (file://)');
             setStatus(true, 'Online (Local)');
             return true;
           } else {
             console.log('📴 Navegador offline (file://)');
             setStatus(false, 'Offline');
             return false;
           }
         }
         
         // Para http/https, tentar ping.json (com compatibilidade total)
         const pingResponse = await fetchWithTimeout('./ping.json', {
           method: 'HEAD',
           cache: 'no-cache'
         }, 3000);
         
         if (!pingResponse.ok) {
           console.log('📴 Teste de ping falhou');
           setStatus(false, 'Offline');
           return false;
         }
         
         console.log('✅ Conectividade básica confirmada');
         // 🚀 OTIMIZAÇÃO: Cachear resultado positivo
         cachedSupabaseResult = true;
         lastSupabaseCheck = Date.now();
         setStatus(true, 'Online');
         return true;
       } catch (pingError) {
         // 🚀 OTIMIZAÇÃO: Se falhar o ping, mas o navegador está online, assumir online (mais rápido)
         if (navigator.onLine) {
           console.log('⚠️ Ping falhou, mas navegador online - assumindo conectividade');
           // 🚀 OTIMIZAÇÃO: Cachear resultado positivo
           cachedConnectivityResult = true;
           lastConnectivityCheck = Date.now();
           setStatus(true, 'Online (Básico)');
           return true;
         }
         console.log('📴 Teste de ping falhou:', pingError.message);
         // 🚀 OTIMIZAÇÃO: Cachear resultado negativo se navegador offline
         cachedSupabaseResult = false;
         lastSupabaseCheck = Date.now();
         setStatus(false, 'Offline');
         return false;
       }
       
       // MÉTODO 2: Teste do Supabase (se disponível e habilitado)
       const supabaseDisabled = localStorage.getItem('supabase_disabled') === 'true';
       
       if (!supabaseDisabled && supabaseLoaded && sb) {
         try {
           const controller = new AbortController();
           const timeoutId = setTimeout(() => controller.abort(), timeout);
           
           const { error } = await sb.from(TABLE_PRESENCAS).select('uuid').limit(1);
           clearTimeout(timeoutId);
           
           if (!error) {
             console.log('✅ Supabase conectado');
             // 🚀 OTIMIZAÇÃO: Cachear resultado positivo
             cachedConnectivityResult = true;
             lastConnectivityCheck = Date.now();
             setStatus(true, 'Online');
             return true;
           } else {
             console.log('⚠️ Supabase com erro, mas conectividade básica OK');
             // 🚀 OTIMIZAÇÃO: Cachear resultado positivo
             cachedConnectivityResult = true;
             lastConnectivityCheck = Date.now();
             setStatus(true, 'Online (Básico)');
             return true; // Retorna true mesmo com erro do Supabase
           }
         } catch (e) {
           console.log('⚠️ Erro no Supabase, mas conectividade básica OK:', e.message);
           // 🚀 OTIMIZAÇÃO: Cachear resultado positivo
           cachedConnectivityResult = true;
           lastConnectivityCheck = Date.now();
           setStatus(true, 'Online (Básico)');
           return true; // Retorna true mesmo com erro do Supabase
         }
       } else if (supabaseDisabled) {
         console.log('ℹ️ Supabase desabilitado - usando apenas conectividade básica');
       }
       
       // Se chegou até aqui, conectividade básica está OK
       console.log('✅ Conectividade básica confirmada - sistema online');
       // 🚀 OTIMIZAÇÃO: Cachear resultado positivo
       cachedConnectivityResult = true;
       lastConnectivityCheck = Date.now();
       setStatus(true, 'Online');
       return true;
       
     } catch (e) {
       console.log('❌ Erro geral na verificação de conectividade:', e.message);
       
       // Em caso de erro, verificar se pelo menos o navegador está online
       if (navigator.onLine) {
         console.log('⚠️ Erro na verificação, mas navegador reporta online');
         // 🚀 OTIMIZAÇÃO: Cachear resultado positivo
         cachedSupabaseResult = true;
         lastSupabaseCheck = Date.now();
         setStatus(true, 'Online (Verificação)');
         return true;
       } else {
         setStatus(false, 'Offline');
         return false;
       }
     }
   }
   
