           dataFiltradaLength: dataFiltrada ? dataFiltrada.length : 0,
           dadosParaArmazenarLength: dadosParaArmazenar ? dadosParaArmazenar.length : 0,
           dadosAntesDeduplicacao: dadosAntesDeduplicacao.length,
