     const cargoUP = ucase(cargoVal);
     console.log('🔍 Processando cargo:', cargoVal, 'para busca de dados completos');
     
     // Busca dados completos no cache
     const cacheKey = `cache_nomes_${comumVal}_${instVal}_${cargoVal}`;
