          // 🚨 CORREÇÃO: Normalizar nome selecionado uma vez antes do loop (evita normalização repetida)
          const nomeSelecionadoNormalizado = norm(nomeSelecionado).toLowerCase().replace(/(^.|[\s\-'.][a-z])/g, m => m.toUpperCase());
          
