     console.log('🔍 Dados disponíveis:', dadosCompletos.map(r => ({ nome: r.nome, nivel: r.nivel })));
     
    // 🚨 CORREÇÃO: Buscar diretamente pelo nome, sem loop desnecessário e sem logs
