       console.log('📤 Request body completo:', requestBody);
       
       // 🚀 CORREÇÃO: Usa proxy local se disponível, senão usa URL direta
       const isLocalServer = window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1';
       const apiUrl = isLocalServer 
         ? '/api/google-script'  // Proxy local
         : "https://script.google.com/macros/s/AKfycbxPtvi86jPy7y41neTpIPvn3hpycd3cMjbgjgifzLD6qRwrJVPlF9EDulaQp42nma-i/exec";
       
       console.log('🌐 URL da API:', apiUrl);
       
       // 🚀 CORREÇÃO: Implementa retry com backoff exponencial
      const response = await fetchWithRetry(apiUrl, {
        method: 'POST',
        headers: {
          'Content-Type': 'text/plain;charset=utf-8'
        },
        body: JSON.stringify(requestBody)
      }, 3); // 3 tentativas
      
      console.log('📱 Mobile Debug - Response status:', response.status);
