   // Função para adicionar payload à fila Supabase (processamento em background)
   function adicionarAFilaSupabase(payload) {
     try {
       const filaSupabase = JSON.parse(localStorage.getItem('fila_supabase') || '[]');
       
       // 🛡️ VERIFICAÇÃO DE DUPLICAÇÃO: Verifica se já existe um item com o mesmo UUID
       const uuidExistente = filaSupabase.find(item => item.uuid === payload.uuid);
       if (uuidExistente) {
         console.log('⚠️ UUID já existe na fila Supabase, ignorando duplicação:', payload.uuid);
         return;
       }
       
       // 🛡️ VERIFICAÇÃO DE DUPLICAÇÃO: Verifica se já existe um item com os mesmos dados essenciais
       const dadosDuplicados = filaSupabase.find(item => 
         item.nome === payload.nome && 
         item.comum === payload.comum && 
         item.cargo === payload.cargo &&
         Math.abs(item.timestamp - Date.now()) < 30000 // 30 segundos
       );
       if (dadosDuplicados) {
         console.log('⚠️ Dados duplicados detectados na fila Supabase, ignorando:', payload.nome);
         return;
       }
       
       filaSupabase.push({
         ...payload,
         timestamp: Date.now(),
         tentativas: 0,
         status: 'pending' // Status para controle
       });
       localStorage.setItem('fila_supabase', JSON.stringify(filaSupabase));
       
       // Atualiza indicador visual
       updateSupabaseQueueIndicator(filaSupabase.length);
       
       // Inicia processamento em background se não estiver rodando
       if (!window.supabaseProcessorRunning) {
         processarFilaSupabase();
       }
     } catch (error) {
       console.warn('⚠️ Erro ao adicionar à fila Supabase:', error);
     }
   }
   
   // Processador em background para Supabase
   async function processarFilaSupabase() {
     if (window.supabaseProcessorRunning) {
       console.log('🔄 Processador Supabase já está rodando, aguardando...');
       return;
     }
     
     window.supabaseProcessorRunning = true;
     console.log('🚀 Iniciando processador Supabase...');
     
     try {
       let filaSupabase = JSON.parse(localStorage.getItem('fila_supabase') || '[]');
       
       // 🛡️ LIMPEZA CRÍTICA: Remove itens com UUID inválido
       const filaLimpa = filaSupabase.filter(item => {
         if (!item.uuid || !isValidUUID(item.uuid)) {
           console.warn('⚠️ Item com UUID inválido removido da fila:', item.uuid);
           return false;
         }
         return true;
       });
       
       // Atualiza a fila se houver itens removidos
       if (filaLimpa.length !== filaSupabase.length) {
         console.log(`🧹 ${filaSupabase.length - filaLimpa.length} item(s) com UUID inválido removido(s) da fila`);
         localStorage.setItem('fila_supabase', JSON.stringify(filaLimpa));
         filaSupabase = filaLimpa;
       }
       
       if (filaSupabase.length === 0) {
         console.log('📭 Fila Supabase vazia, nada para processar');
         window.supabaseProcessorRunning = false;
         return;
       }
       
       console.log(`🔄 Processando fila Supabase: ${filaSupabase.length} item(s)`);
       console.log('🔍 DEBUG - Itens na fila Supabase:', filaSupabase.map((item, index) => ({
         index: index + 1,
         uuid: item.uuid,
         nome: item.nome,
         status: item.status,
         tentativas: item.tentativas || 0
       })));
       
       // Verifica se Supabase está disponível
       if (!supabaseLoaded || !sb) {
         console.log('⚠️ Supabase não disponível, tentando inicializar...');
         await initSupabase();
         
         if (!supabaseLoaded || !sb) {
           console.log('❌ Supabase não pôde ser inicializado, mantendo fila');
           window.supabaseProcessorRunning = false;
           return;
         }
       }
       
       // Testa conectividade antes de processar
       const conectividadeOK = await checkSupabaseConnection();
       if (!conectividadeOK) {
         console.log('⚠️ Conectividade não estável, mantendo itens na fila Supabase');
         window.supabaseProcessorRunning = false;
         return;
       }
       
       const itensProcessados = [];
       const itensComErro = [];
       
       for (let i = 0; i < filaSupabase.length; i++) {
         const item = filaSupabase[i];
         
         try {
           // 🛡️ VERIFICAÇÃO FINAL: Verifica se o item já foi processado com sucesso
           if (item.status === 'success') {
             console.log(`✅ Item ${i + 1} já foi processado com sucesso, removendo da fila`);
             itensProcessados.push(item);
             continue;
           }
           
           console.log(`📤 Processando item ${i + 1}/${filaSupabase.length}: ${item.nome || item.uuid}`);
           await insertSupabase(item);
           
           // 🛡️ MARCA COMO SUCESSO: Atualiza status para evitar reprocessamento
           item.status = 'success';
           itensProcessados.push(item);
           console.log(`✅ Supabase (Background): Item ${i + 1} processado com sucesso`);
           
           // 🚨 CORREÇÃO: Pausa aumentada para 200ms (era 50ms - muito curto quebrava a lógica)
           await new Promise(resolve => setTimeout(resolve, 200));
           
         } catch (error) {
           console.warn(`⚠️ Supabase (Background): Erro no item ${i + 1}:`, error.message);
           
           // 🛡️ TRATAMENTO ESPECÍFICO PARA DUPLICAÇÃO: Se for erro de chave duplicada, remove da fila
           if (error.code === '23505' || error.message.includes('duplicate key') || error.message.includes('already exists')) {
             console.log(`🗑️ Item ${i + 1}: Chave duplicada detectada, removendo da fila (já existe no banco)`);
             item.status = 'duplicate';
             itensProcessados.push(item);
             continue;
           }
           
           // Incrementa tentativas
           item.tentativas = (item.tentativas || 0) + 1;
           
           // Se já tentou 3 vezes, remove da fila
           if (item.tentativas >= 3) {
             console.log(`🗑️ Supabase (Background): Item ${i + 1} removido após 3 tentativas`);
             item.status = 'failed';
             itensProcessados.push(item);
           } else {
             itensComErro.push(item);
           }
         }
       }
       
       // Atualiza fila removendo itens processados
       localStorage.setItem('fila_supabase', JSON.stringify(itensComErro));
       
       console.log(`✅ Fila Supabase processada: ${itensProcessados.length} sucessos, ${itensComErro.length} pendentes`);
       
       // Atualiza indicador visual da fila
       updateSupabaseQueueIndicator(itensComErro.length);
       
       // Se ainda há itens pendentes, agenda próxima execução
       if (itensComErro.length > 0) {
         console.log(`⏰ Agendando próxima tentativa em 5 segundos para ${itensComErro.length} itens pendentes`);
         setTimeout(() => {
           window.supabaseProcessorRunning = false;
           processarFilaSupabase();
         }, 5000); // Tenta novamente em 5 segundos
       } else {
         console.log('🎉 Todos os itens da fila Supabase foram processados com sucesso!');
         window.supabaseProcessorRunning = false;
       }
       
     } catch (error) {
       console.error('❌ Erro no processador Supabase:', error);
       window.supabaseProcessorRunning = false;
     }
   }
   
   // Função para salvar dados na fila local quando há erro de conectividade
   function salvarNaFilaLocal(payload) {
     try {
       // Busca fila existente
       let fila = JSON.parse(localStorage.getItem('fila_envio') || '[]');
       
       // 🛡️ VERIFICAÇÃO CRÍTICA: Prevenir duplicações na fila local
       const existingRecord = fila.find(item => {
         const sameName = (item.nome || item.NOME) === (payload.nome || payload.NOME);
         const sameComum = (item.comum || item.COMUM) === (payload.comum || payload.COMUM);
         const sameCargo = (item.cargo || item.CARGO) === (payload.cargo || payload.CARGO);
         const sameTimestamp = Math.abs(new Date(item.timestamp).getTime() - Date.now()) < 5000; // 5 segundos
         
         return sameName && sameComum && sameCargo && sameTimestamp;
       });
       
       if (existingRecord) {
         console.warn('⚠️ DUPLICAÇÃO PREVENIDA na fila local:', {
           nome: payload.nome || payload.NOME,
           comum: payload.comum || payload.COMUM,
           cargo: payload.cargo || payload.CARGO
         });
         return; // Não adiciona duplicata
       }
       
       // 🛡️ VERIFICAÇÃO ADICIONAL: UUID nos dados
       let dataUuid = payload.uuid || payload.UUID;
       if (dataUuid) {
         const existingByUuid = fila.find(item => 
           (item.uuid || item.UUID) === dataUuid
         );
         
         if (existingByUuid) {
           console.warn('⚠️ DUPLICAÇÃO PREVENIDA por UUID na fila local:', dataUuid);
           return; // Não adiciona duplicata
         }
       } else {
         // Gera UUID se não existir
         dataUuid = uuidv4();
         payload.uuid = dataUuid;
       }
       
       // Adiciona novo item à fila
       fila.push({
         ...payload,
         timestamp: new Date().toISOString(),
         tentativas: 0
       });
       
       // Salva fila atualizada
       localStorage.setItem('fila_envio', JSON.stringify(fila));
       
       console.log('💾 Dados salvos na fila local:', { 
         totalItens: fila.length, 
         ultimoItem: payload.nome 
       });
       
       // Atualiza contador na interface
       atualizarContadorFila();
       
       // 🛡️ CORREÇÃO: Não adicionar ao Supabase aqui para evitar duplicação
       // O processamento da fila local já cuida do Supabase
       
       // Tenta processar imediatamente se estiver online
       setTimeout(async () => {
         try {
           const isOnline = await checkSupabaseConnection();
           if (isOnline) {
             console.log('🔄 Item adicionado à fila - tentando processamento imediato...');
             await processarFilaLocal();
           }
         } catch (error) {
           console.log('⚠️ Erro no processamento imediato:', error.message);
         }
       }, 1000);
       
     } catch (error) {
       console.error('❌ Erro ao salvar na fila local:', error);
     }
   }
   
   // Função para atualizar contador da fila na interface
   function atualizarContadorFila() {
     try {
       const filaLocal = JSON.parse(localStorage.getItem('fila_envio') || '[]');
       const filaSupabase = JSON.parse(localStorage.getItem('fila_supabase') || '[]');
       const totalFila = filaLocal.length + filaSupabase.length;
       
       const contador = document.querySelector('.fila-contador');
       const syncBtn = document.getElementById('syncBtn');
       
       if (contador) {
         if (totalFila > 0) {
           contador.textContent = `${totalFila} na fila`;
           contador.style.display = 'block';
         } else {
           contador.style.display = 'none';
         }
       }
       
       // Mostra/oculta botões de sincronização
       if (syncBtn) {
         if (totalFila > 0) {
           syncBtn.style.display = 'inline-block';
           syncBtn.title = `Sincronizar ${totalFila} registro(s) pendente(s)`;
         } else {
           syncBtn.style.display = 'none';
         }
       }
       
       const forceBtn = document.getElementById('forceBtn');
       if (forceBtn) {
         if (totalFila > 0) {
           forceBtn.style.display = 'inline-block';
           forceBtn.title = `Forçar processamento de ${totalFila} registro(s)`;
         } else {
           forceBtn.style.display = 'none';
         }
       }
     } catch (error) {
       console.error('❌ Erro ao atualizar contador da fila:', error);
     }
   }
   
