   // Função para processar fila local quando conexão voltar
   async function processarFilaLocal() {
     try {
       const fila = JSON.parse(localStorage.getItem('fila_envio') || '[]');
       
       if (fila.length === 0) {
         console.log('📭 Fila vazia, nada para processar');
         return;
       }
       
       // Testa conectividade antes de processar
       const conectividadeOK = await checkSupabaseConnection();
       
       if (!conectividadeOK) {
         console.log('⚠️ Conectividade não estável, mantendo itens na fila');
         return;
       }
       
       console.log(`🔄 Processando fila local: ${fila.length} item(s)`);
       console.log('🔍 DEBUG - Itens na fila local:', fila.map((item, index) => ({
         index: index + 1,
         uuid: item.uuid,
         nome: item.nome,
         status: item.status,
         tentativas: item.tentativas || 0
       })));
       
       const itensProcessados = [];
       const itensComErro = [];
       
       for (let i = 0; i < fila.length; i++) {
         const item = fila[i];
         
         try {
           // 🛡️ VERIFICAÇÃO DE DUPLICAÇÃO: Verifica se já foi processado com sucesso
           if (item.status === 'success') {
             console.log(`✅ Item ${i + 1} já foi processado com sucesso, removendo da fila`);
             itensProcessados.push(item);
             continue;
           }
           
           console.log(`📤 Processando item ${i + 1}/${fila.length}: ${item.nome}`);
           
           // Tenta enviar para Google Sheets
           let sheetsSuccess = false;
           try {
             console.log(`🔄 Item ${i + 1}: Tentando enviar para Google Sheets...`);
             console.log(`📋 Dados do item:`, {
               uuid: item.uuid,
               nome: item.nome,
               comum: item.comum,
               cargo: item.cargo
             });
             
             const sheetsResult = await enviarParaSheets(item);
             
             console.log(`📥 Resultado do envio:`, sheetsResult);
             
             // Verifica se o retorno indica sucesso
             if (sheetsResult && (sheetsResult.ok === true || sheetsResult === true)) {
               sheetsSuccess = true;
               console.log(`✅ Item ${i + 1}: Google Sheets OK - Envio confirmado`);
             } else {
               console.error(`❌ Item ${i + 1}: Envio para Google Sheets retornou false ou undefined`);
               throw new Error('Envio para Google Sheets retornou false ou undefined');
             }
           } catch (sheetsError) {
             console.error(`❌ Item ${i + 1}: Erro ao enviar para Google Sheets:`, sheetsError.message);
             console.error(`❌ Stack trace:`, sheetsError.stack);
             throw sheetsError; // Lança erro para ser tratado no catch externo
           }
           
           // Só marca como sucesso se Google Sheets foi bem-sucedido
           if (sheetsSuccess) {
             // Tenta enviar para Supabase
             if (supabaseLoaded && sb) {
               try {
                 await insertSupabase(item);
                 console.log(`✅ Item ${i + 1}: Supabase OK`);
               } catch (e) {
                 // 🛡️ TRATAMENTO ESPECÍFICO PARA DUPLICAÇÃO: Se for erro de chave duplicada, considera sucesso
                 if (e.code === '23505' || e.message.includes('duplicate key') || e.message.includes('already exists')) {
                   console.log(`✅ Item ${i + 1}: Registro já existe no Supabase (duplicação evitada)`);
                 } else {
                   console.warn(`⚠️ Item ${i + 1}: Erro no Supabase:`, e.message);
                   // Não lança erro aqui - Google Sheets já foi enviado com sucesso
                 }
               }
             }
             
             // 🛡️ MARCA COMO SUCESSO: Atualiza status para evitar reprocessamento
             item.status = 'success';
             itensProcessados.push(item);
           } else {
             throw new Error('Google Sheets não retornou sucesso');
           }
           
         } catch (error) {
           console.error(`❌ Item ${i + 1}: Erro:`, error.message);
           
           // Incrementa tentativas
           item.tentativas = (item.tentativas || 0) + 1;
           
           // Se já tentou 3 vezes, remove da fila
           if (item.tentativas >= 3) {
             console.log(`🗑️ Item ${i + 1}: Removido após 3 tentativas`);
             item.status = 'failed';
             itensProcessados.push(item);
           } else {
             itensComErro.push(item);
           }
         }
       }
       
       // Atualiza fila removendo itens processados
       localStorage.setItem('fila_envio', JSON.stringify(itensComErro));
       
       console.log(`✅ Fila processada: ${itensProcessados.length} enviados, ${itensComErro.length} com erro`);
       
       // Atualiza contador
       atualizarContadorFila();
       
       if (itensProcessados.length > 0) {
         showToast('success', 'Fila processada', `${itensProcessados.length} registro(s) enviado(s) com sucesso!`, 3000);
       }
       
       // Se ainda há itens com erro, agenda nova tentativa
       if (itensComErro.length > 0) {
         console.log(`⏰ Agendando nova tentativa em 5 segundos para ${itensComErro.length} itens com erro`);
         setTimeout(async () => {
           console.log('🔄 Tentativa automática de reprocessamento...');
           await processarFilaLocal();
         }, 5000);
       }
       
     } catch (error) {
       console.error('❌ Erro ao processar fila local:', error);
     }
   }
   
  async function insertSupabase(payload){
    // 🚨 CORREÇÃO CRÍTICA: Validação mais robusta e logs detalhados
    if (!supabaseLoaded) {
      console.error('❌ Supabase não carregado (supabaseLoaded = false)');
      throw new Error('Supabase não está carregado');
    }
    
    if (!sb) {
      console.error('❌ Cliente Supabase não disponível (sb = null)');
      throw new Error('Cliente Supabase não está disponível');
    }
    
    if (!sb.from || typeof sb.from !== 'function') {
      console.error('❌ Cliente Supabase não tem método from');
      throw new Error('Cliente Supabase não tem método from');
    }
     
     console.log('📤 DEBUG - Payload original para Supabase:', payload);
     
     // 🛡️ VALIDAÇÃO CRÍTICA: Verificar se o payload tem dados válidos
     if (!payload || typeof payload !== 'object') {
       console.error('❌ Payload inválido para Supabase:', payload);
       return null;
     }
     
     // Verificar se tem pelo menos nome e cargo (campos essenciais)
     const nome = payload.nome || payload.nome_completo || payload.NOME || payload['NOME COMPLETO'];
     const cargo = payload.cargo || payload.CARGO;
     
     if (!nome || !cargo || nome.trim() === '' || cargo.trim() === '') {
       console.error('❌ Payload incompleto para Supabase - faltam dados essenciais:', {
         nome: nome,
         cargo: cargo,
         payload: payload
       });
       return null;
     }
     
     // 🛡️ VALIDAÇÃO CRÍTICA: Verifica se o UUID é válido ANTES de tudo
     if (!payload.uuid || !isValidUUID(payload.uuid)) {
       console.error('❌ UUID inválido detectado no payload:', payload.uuid);
       console.error('❌ Tipo do UUID:', typeof payload.uuid);
       console.error('❌ Payload completo:', payload);
       
       // Gera um novo UUID válido
       payload.uuid = uuidv4();
       console.log('✅ Novo UUID gerado:', payload.uuid);
       console.log('✅ UUID é válido?', isValidUUID(payload.uuid));
     }
     
     // 🛡️ VALIDAÇÃO CRÍTICA ADICIONAL: Garantir que campos obrigatórios estão preenchidos
     const nomeParaValidacao = payload.nome || payload.nome_completo || payload.NOME || payload['NOME COMPLETO'];
     const cargoParaValidacao = payload.cargo || payload.CARGO;
     
     if (!nomeParaValidacao || nomeParaValidacao.trim() === '') {
       console.error('❌ ERRO CRÍTICO: Nome está vazio no payload para Supabase');
       throw new Error('Nome é obrigatório');
     }
     
     if (!cargoParaValidacao || cargoParaValidacao.trim() === '') {
       console.error('❌ ERRO CRÍTICO: Cargo está vazio no payload para Supabase');
       throw new Error('Cargo é obrigatório');
     }
     
       // 🛡️ BLOQUEIO DEFINITIVO: Verificar se já foi enviado para Supabase (SEM TEMPO)
     const uuid = payload.uuid;
     if (uuid) {
       const sentRecords = safeGetItem('sent_records', {});
       const supabaseKey = `sb_${uuid}`;
       
       // Verificação DEFINITIVA - SEM TEMPO
       if (sentRecords[supabaseKey]) {
         console.warn('⚠️ DUPLICAÇÃO BLOQUEADA DEFINITIVAMENTE (Supabase): Registro já foi enviado:', uuid);
         // Retorna sucesso para evitar nova tentativa
         return { success: true, duplicate: true };
       }
     }
     
     // 🚀 APLICAR REGRA DE GÊNERO: Padronizar "oficializado(a)" para "oficializada"
     const dadosComRegrasGenero = aplicarRegrasGenero(payload);
     console.log('🚀 Regras de gênero aplicadas para Supabase:', dadosComRegrasGenero);
     
     // Padroniza os dados antes de inserir no Supabase
     const payloadPadronizado = padronizarDadosMaiuscula(dadosComRegrasGenero);
     
     // 🚨 VERIFICAÇÃO: Se usuário já confirmou duplicata, não bloquear novamente
     const duplicataJaConfirmada = window._duplicataConfirmadaPeloUsuario === true;
     const platformType = isMobile ? 'MOBILE' : 'DESKTOP';
     
     if (duplicataJaConfirmada) {
       console.log(`✅ ${platformType}: Usuário já confirmou duplicata - permitindo inserção no Supabase`);
       console.log(`✅ ${platformType}: Flag antes de limpar:`, window._duplicataConfirmadaPeloUsuario);
       // Limpar flag após usar
       window._duplicataConfirmadaPeloUsuario = false;
       console.log(`✅ ${platformType}: Flag limpa após uso no Supabase`);
     } else {
       console.log(`🔍 ${platformType}: Verificando duplicatas no insertSupabase (flag não está ativa)`);
       // 🚨 VERIFICAÇÃO CRÍTICA DE DUPLICATAS NO BANCO: Verificar no Supabase ANTES de inserir
       const nomeVerificacao = payloadPadronizado.nome || payloadPadronizado.nome_completo || payloadPadronizado.NOME || payloadPadronizado['NOME COMPLETO'] || '';
       const comumVerificacao = payloadPadronizado.comum || payloadPadronizado.COMUM || '';
       const cargoVerificacao = payloadPadronizado.cargo || payloadPadronizado.CARGO || '';
       
       if (supabaseLoaded && sb && nomeVerificacao && comumVerificacao && cargoVerificacao) {
         try {
           const dataAtual = new Date();
           const dataISO = dataAtual.toISOString().split('T')[0];
           
           // Buscar registros duplicados (mesmo nome + comum + cargo no mesmo dia)
           const { data: duplicatas, error: dupError } = await sb
             .from(TABLE_PRESENCAS)
             .select('nome_completo, comum, cargo, created_at, uuid')
             .ilike('nome_completo', `%${nomeVerificacao.trim()}%`)
             .ilike('comum', `%${comumVerificacao.trim()}%`)
             .gte('created_at', `${dataISO}T00:00:00.000Z`)
             .lt('created_at', `${dataISO}T23:59:59.999Z`)
             .limit(10);
           
           if (!dupError && duplicatas && duplicatas.length > 0) {
             // Verificar se há duplicata exata (mesmo nome, comum e cargo)
             const duplicataExata = duplicatas.find(d => {
               const nomeMatch = norm(d.nome_completo || '').toUpperCase().trim() === norm(nomeVerificacao).toUpperCase().trim();
               const comumMatch = compareComum(d.comum || '', comumVerificacao).match;
               const cargoMatch = norm(d.cargo || '').toUpperCase().trim() === norm(cargoVerificacao).toUpperCase().trim();
               return nomeMatch && comumMatch && cargoMatch;
             });
             
             if (duplicataExata) {
               console.error('🚨🚨🚨 DUPLICATA DETECTADA NO SUPABASE - BLOQUEANDO INSERÇÃO 🚨🚨🚨', {
                 nome: nomeVerificacao,
                 comum: comumVerificacao,
                 cargo: cargoVerificacao,
                 uuidExistente: duplicataExata.uuid,
                 dataExistente: duplicataExata.created_at
               });
               
               // 🚨 BLOQUEIO COMPLETO: Retornar erro para impedir inserção
               throw new Error(`DUPLICATA_BLOQUEADA: Registro duplicado detectado. ${nomeVerificacao} de ${comumVerificacao} já foi cadastrado hoje.`);
             }
           }
         } catch (error) {
           // Se o erro for de duplicata bloqueada, propagar o erro
           if (error.message && error.message.includes('DUPLICATA_BLOQUEADA')) {
             console.error('🚨🚨🚨 BLOQUEIO DEFINITIVO DE DUPLICATA NO insertSupabase 🚨🚨🚨');
             throw error;
           }
           console.warn('⚠️ Erro ao verificar duplicatas no Supabase (insertSupabase):', error);
           // Continua apenas se não for erro de duplicata
         }
       }
       }
     
     // 🛡️ VALIDAÇÃO DUPLA: Garante que o UUID não foi alterado na padronização
     if (!isValidUUID(payloadPadronizado.uuid)) {
       console.error('❌ UUID foi corrompido durante padronização:', payloadPadronizado.uuid);
       payloadPadronizado.uuid = uuidv4();
       console.log('✅ Novo UUID gerado após padronização:', payloadPadronizado.uuid);
     }
     
     console.log('📤 DEBUG - Payload padronizado para Supabase:', payloadPadronizado);
     
     // UUID já validado, não precisa corrigir novamente
     const validUUID = payloadPadronizado.uuid;
     console.log('🔧 UUID final validado:', validUUID);
     
     // Usando os nomes corretos das colunas baseado no schema mostrado no console
     const row = {
       uuid: validUUID,
       nome_completo: payloadPadronizado.nome,
       comum: payloadPadronizado.comum,
       cidade: payloadPadronizado.cidade || null, // Campo cidade adicionado
       cargo: payloadPadronizado.cargo,
       instrumento: payloadPadronizado.instrumento || null,
       naipe_instrumento: payloadPadronizado.naipe || null,
       classe_organista: payloadPadronizado.nivel || null, // Classe da organista (vem do campo nivel do payload)
       local_ensaio: payloadPadronizado.local_ensaio || null,
       data_ensaio: payloadPadronizado.data_ensaio_iso || null, // Formato ISO para Supabase
       registrado_por: payloadPadronizado.registrado_por || null,
       // user_id removido - coluna não existe na tabela presencas
       created_at: payloadPadronizado.created_at
     };
     
    console.log('📤 DEBUG - Row final para Supabase:', row);
    console.log('📤 DEBUG - TABLE_PRESENCAS:', TABLE_PRESENCAS);
    console.log('📤 DEBUG - Cliente Supabase disponível:', !!sb);
    console.log('📤 DEBUG - Método from disponível:', typeof sb?.from === 'function');
    
    // 🚨 CORREÇÃO CRÍTICA: Retry logic robusto para mobile/online
    const maxRetries = 3;
    let lastError = null;
    
    try {
      for (let attempt = 1; attempt <= maxRetries; attempt++) {
        try {
          // 🚨 CORREÇÃO CRÍTICA: Adicionar timeout explícito e logs detalhados
          console.log(`📤 Tentando inserir no Supabase (tentativa ${attempt}/${maxRetries})...`);
          const startTime = Date.now();
          
          const { data, error } = await sb.from(TABLE_PRESENCAS).insert(row);
          
          const endTime = Date.now();
          const duration = endTime - startTime;
          console.log(`📤 Resposta do Supabase recebida em ${duration}ms`);
          
          if(error) {
            console.error(`❌ ERRO no Supabase (tentativa ${attempt}/${maxRetries}):`, error);
            console.error('❌ Detalhes completos do erro:', {
              code: error.code,
              message: error.message,
              details: error.details,
              hint: error.hint,
              status: error.status,
              statusText: error.statusText
            });
            
            // 🚨 CORREÇÃO CRÍTICA: Verificar se é erro de RLS (permissão negada)
            if (error.code === '42501' || error.message?.includes('permission denied') || error.message?.includes('row-level security') || error.message?.includes('new row violates row-level security')) {
              console.error('❌ ERRO DE RLS: Permissão negada para INSERT na tabela presencas');
              console.error('❌ SOLUÇÃO: Execute o script RLS_POLICY_PRESENCAS.sql no Supabase');
              console.error('❌ O script cria política para permitir INSERT público');
              throw new Error('Erro de permissão: RLS está bloqueando a inserção. Execute RLS_POLICY_PRESENCAS.sql no Supabase.');
            }
            
            // 🚨 CORREÇÃO: Se for erro de duplicação, não retry
            if (error.code === '23505' || error.message?.includes('duplicate key') || error.message?.includes('already exists')) {
              console.log('✅ Duplicação detectada - não precisa retry');
              throw error; // Será tratado no catch externo
            }
            
            // 🚨 CORREÇÃO: Se for erro de validação, não retry
            if (error.code === '23514' || error.message?.includes('violates check constraint')) {
              console.error('❌ Erro de validação - não precisa retry');
              throw error;
            }
            
            // Para outros erros, tentar novamente
            lastError = error;
            
            if (attempt < maxRetries) {
              const delay = attempt * 1000; // 1s, 2s, 3s
              console.log(`⏳ Aguardando ${delay}ms antes de tentar novamente...`);
              await new Promise(resolve => setTimeout(resolve, delay));
              continue;
            } else {
              throw error;
            }
          }
          
          // Sucesso! - sai do loop de retry
          console.log(`✅ Supabase: Dados inseridos com sucesso (tentativa ${attempt})`);
          console.log(`✅ Supabase: Data retornada:`, data);
          console.log(`✅ Supabase: Row inserido:`, {
            uuid: row.uuid,
            nome_completo: row.nome_completo,
            comum: row.comum,
            cargo: row.cargo
          });
          
          // 🛡️ MARCAR COMO ENVIADO DEFINITIVAMENTE: Registrar permanente (SEM TEMPO)
          if (uuid) {
            let sentRecords = safeGetItem('sent_records', {});
            // Marca como enviado - PERMANENTE (sem timestamp)
            sentRecords[`sb_${uuid}`] = true;
            
            // Também marca por conteúdo - PERMANENTE
            const contentKey = `content_${(nomeParaValidacao || '').trim()}_${(payload.comum || '').trim()}_${(cargoParaValidacao || '').trim()}`.replace(/\s+/g, '_').toLowerCase();
            sentRecords[contentKey] = true;
            
            safeSetItem('sent_records', sentRecords);
            console.log(`✅ Supabase: Registro marcado como enviado (UUID: ${uuid})`);
          }
          
          // 🚨 CORREÇÃO: Retornar objeto de sucesso explícito
          return { success: true, data: data };
        } catch (retryError) {
          // Se for erro de duplicação, tratar no catch externo
          if (retryError.code === '23505' || retryError.message?.includes('duplicate key') || retryError.message?.includes('already exists')) {
            throw retryError;
          }
          
          // Se for erro de validação, tratar no catch externo
          if (retryError.code === '23514' || retryError.message?.includes('violates check constraint')) {
            throw retryError;
          }
          
          lastError = retryError;
          
          // Se não é a última tentativa, continua o loop
          if (attempt < maxRetries) {
            const delay = attempt * 1000; // 1s, 2s, 3s
            console.log(`⏳ Erro na tentativa ${attempt}, aguardando ${delay}ms antes de tentar novamente...`);
            console.error(`❌ Erro na tentativa ${attempt}:`, retryError.message);
            await new Promise(resolve => setTimeout(resolve, delay));
            continue;
          }
          
          // Última tentativa falhou
          console.error(`❌ Todas as ${maxRetries} tentativas falharam`);
          throw retryError;
        }
      }
      
      // Se chegou aqui, todas as tentativas falharam
      if (lastError) {
        throw lastError;
      }
      
      // Nunca deveria chegar aqui, mas se chegou, lança erro genérico
      throw new Error('Erro desconhecido ao inserir no Supabase');
    } catch (error) {
      // 🛡️ TRATAMENTO DE DUPLICAÇÃO: Se for erro de chave duplicada, retorna sucesso
      if (error.code === '23505' || error.message?.includes('duplicate key') || error.message?.includes('already exists')) {
        console.log('✅ Duplicação evitada no Supabase (registro já existe):', uuid);
        // Marca como enviado mesmo sendo duplicado - PERMANENTE
        if (uuid) {
          let sentRecords = safeGetItem('sent_records', {});
          sentRecords[`sb_${uuid}`] = true;
          safeSetItem('sent_records', sentRecords);
        }
        return { success: true, duplicate: true };
      }
      
      // 🚨 CORREÇÃO CRÍTICA: Logs detalhados para diagnóstico
      console.error('❌ ERRO GERAL no Supabase:', error);
      console.error('❌ Tipo do erro:', error.constructor.name);
      console.error('❌ Mensagem do erro:', error.message);
      console.error('❌ Stack do erro:', error.stack);
      console.error('❌ Código do erro:', error.code);
      console.error('❌ Payload que causou erro:', row);
      console.error('❌ UUID do registro:', validUUID);
      console.error('❌ Supabase carregado:', supabaseLoaded);
      console.error('❌ Cliente Supabase disponível:', !!sb);
      console.error('❌ Navigator online:', navigator.onLine);
      
      // 🚨 CORREÇÃO: Verificar se é erro de rede/timeout
      if (error.name === 'AbortError' || error.message?.includes('aborted') || error.message?.includes('timeout')) {
        console.error('❌ ERRO DE TIMEOUT/REDE no Supabase');
        throw new Error('Timeout ao enviar para Supabase. Verifique sua conexão com a internet.');
      }
      
      // 🚨 CORREÇÃO: Verificar se é erro de CORS
      if (error.message?.includes('CORS') || error.message?.includes('cross-origin')) {
        console.error('❌ ERRO DE CORS no Supabase');
        throw new Error('Erro de CORS ao enviar para Supabase. Verifique as configurações do servidor.');
      }
      
      throw error;
    }
   }
   
