   // Controle global de processamento de fila para evitar duplicações
   let globalQueueProcessing = false;
   
   // 🚨 SISTEMA DE CONCORRÊNCIA ROBUSTO PARA LANÇAMENTO - OTIMIZADO PARA 100+ USUÁRIOS
   const MAX_CONCURRENT_REQUESTS = 100; // Aumentado para 100 requisições simultâneas
   const MAX_REQUESTS_PER_MINUTE = 500; // Aumentado para 500 req/min (20 req/seg)
   const MAX_REQUESTS_PER_HOUR = 5000; // Aumentado para 5000 req/hora
   const MAX_QUEUE_SIZE = 200; // Fila máxima de 200 itens
   const BATCH_SIZE = 20; // Processar em lotes de 20
   const MAX_PROCESSING_TIME = 3000; // Tempo máximo de processamento: 3 segundos
   
   const requestQueue = [];
   const activeRequests = new Set();
   const requestCounts = {
     minute: new Map(),
     hour: new Map()
   };
   
   // Métricas de performance
   const performanceMetrics = {
     responseTime: [],
     errorRate: 0,
     successRate: 0,
     concurrentUsers: 0,
     queueLength: 0,
     totalRequests: 0,
     failedRequests: 0
   };
   
   // Alertas automáticos - OTIMIZADOS PARA 100+ USUÁRIOS REAIS
   const alertThresholds = {
     responseTime: 5000, // 5 segundos (baseado no tempo real de processamento)
     errorRate: 0.01, // 1% (mais rigoroso para alta carga)
     queueLength: 160, // 80% da capacidade máxima (200)
     concurrentUsers: 90 // 90% da capacidade máxima (100)
   };
   
   // Circuit breaker
   const circuitBreaker = {
     failureThreshold: 5,
     recoveryTimeout: 30000,
     state: 'CLOSED', // CLOSED, OPEN, HALF_OPEN
     failureCount: 0,
     lastFailureTime: 0
   };
   
   // Função para testar status da fila offline
