     // 🚨 CORREÇÃO CRÍTICA MULTI-PLATAFORMA: Função universal para verificar e carregar nomes
     // Esta função garante que os nomes sejam carregados quando comum + cargo estão preenchidos
     // Funciona em todas as plataformas móveis (Android, iOS, Chrome iOS, Xiaomi, etc.)
     // Tornada global para ser acessível de outros lugares
     window.verificarECarregarNomes = function verificarECarregarNomes() {
       const comumEl = findComumField();
       const cargoEl = findCargoField();
       const nomeEl = findNomeField();
       
       if (!comumEl || !cargoEl || !nomeEl) {
         return false;
       }
       
       const comum = comumEl.value?.trim() || '';
       const cargo = cargoEl.value?.trim() || '';
       
       // Verifica se ambos estão preenchidos
       if (comum && cargo) {
         // Verificar se já há nomes carregados para evitar chamadas desnecessárias
         const temNomesCarregados = window.nomesData && Array.isArray(window.nomesData) && window.nomesData.length > 0;
         const nomeElTemOpcoes = nomeEl.tagName === 'SELECT' && nomeEl.options.length > 1;
         
         // Se já tem nomes carregados e o campo já está populado, não recarregar
         if (temNomesCarregados && nomeElTemOpcoes) {
           return true;
         }
         
         console.log('✅ Verificação automática: Comum e Cargo preenchidos, carregando nomes...', { comum, cargo });
         
         // Resetar estado de digitação manual
         nomeEl.removeAttribute('data-nome-manual');
         nomeEl.removeAttribute('data-selected-from-list');
         if (nomeEl.style) {
           nomeEl.style.backgroundColor = '';
           nomeEl.style.borderColor = '';
         }
         
         // Carregar nomes
         if (typeof loadNomes === 'function') {
           loadNomes();
           return true;
         }
       }
       
       return false;
     };
     
     // 🚨 CORREÇÃO CRÍTICA MULTI-PLATAFORMA: Adicionar múltiplos tipos de eventos para garantir compatibilidade
     // Algumas plataformas móveis podem não disparar 'change' corretamente, então usamos múltiplos eventos
     function setupEventListenersRobustos() {
       const comumEl = findComumField();
       const cargoEl = findCargoField();
       
       if (!comumEl || !cargoEl) {
         console.warn('⚠️ Campos comum ou cargo não encontrados para configurar event listeners');
         return;
       }
       
       // Função handler para comum
       const handleComumChange = function() {
         console.log('🔄 Evento disparado: comum mudou');
         const nomeEl = findNomeField();
         if (nomeEl) {
           nomeEl.removeAttribute('data-nome-manual');
           nomeEl.removeAttribute('data-selected-from-list');
           if (nomeEl.style) {
             nomeEl.style.backgroundColor = '';
             nomeEl.style.borderColor = '';
           }
         }
         // Usar debounce para evitar múltiplas chamadas
         debouncedLoadNomes();
         // Verificação adicional após um pequeno delay
         setTimeout(verificarECarregarNomes, 200);
       };
       
       // Função handler para cargo
       const handleCargoChange = function() {
         console.log('🔄 Evento disparado: cargo mudou');
         const nomeEl = findNomeField();
         if (nomeEl) {
           nomeEl.removeAttribute('data-nome-manual');
           nomeEl.removeAttribute('data-selected-from-list');
           if (nomeEl.style) {
             nomeEl.style.backgroundColor = '';
             nomeEl.style.borderColor = '';
           }
         }
         toggleInstrumentFieldVisibility();
         // 🚀 OTIMIZAÇÃO: Chamar diretamente para resposta imediata
         // Removida chamada duplicada de verificarECarregarNomes() que causava carregamento duplo
         loadNomes();
       };
       
       // 🚨 MULTI-PLATAFORMA: Adicionar múltiplos tipos de eventos para garantir compatibilidade
       // 'change' - padrão, funciona na maioria dos casos
       // 'input' - para campos de texto que podem não disparar 'change' em algumas plataformas
       // 'blur' - quando o campo perde o foco (útil para mobile)
       // 'touchend' - específico para touch (mobile)
       
       // Eventos para comum
       comumEl.addEventListener('change', handleComumChange);
       comumEl.addEventListener('input', debounce(handleComumChange, 300));
       comumEl.addEventListener('blur', function() {
         setTimeout(verificarECarregarNomes, 100);
       });
       
       // Eventos para cargo
       cargoEl.addEventListener('change', handleCargoChange);
       cargoEl.addEventListener('input', debounce(handleCargoChange, 300));
       cargoEl.addEventListener('blur', function() {
         setTimeout(verificarECarregarNomes, 100);
       });
       
       // Eventos específicos para mobile (touch)
       if (isMobile) {
         comumEl.addEventListener('touchend', function() {
           setTimeout(verificarECarregarNomes, 150);
         });
         cargoEl.addEventListener('touchend', function() {
           setTimeout(verificarECarregarNomes, 150);
         });
       }
       
       console.log('✅ Event listeners robustos configurados para comum e cargo');
     }
     
     // Configurar event listeners robustos
     setupEventListenersRobustos();
     
     // 🚨 CORREÇÃO CRÍTICA MULTI-PLATAFORMA: Verificação periódica como fallback
     // Algumas plataformas móveis podem não disparar eventos corretamente, então verificamos periodicamente
     // Isso garante que os nomes sejam carregados mesmo se os eventos falharem
     let ultimaVerificacao = { comum: '', cargo: '' };
     let intervaloVerificacao = null;
     
     function iniciarVerificacaoPeriodica() {
       // Limpar intervalo anterior se existir
       if (intervaloVerificacao) {
         clearInterval(intervaloVerificacao);
       }
       
       // Verificar a cada 2 segundos se comum + cargo estão preenchidos mas nomes não foram carregados
       intervaloVerificacao = setInterval(() => {
         const comumEl = findComumField();
         const cargoEl = findCargoField();
         const nomeEl = findNomeField();
         
         if (!comumEl || !cargoEl || !nomeEl) {
           return;
         }
         
         const comum = comumEl.value?.trim() || '';
         const cargo = cargoEl.value?.trim() || '';
         
         // Se ambos estão preenchidos
         if (comum && cargo) {
           // Verificar se os valores mudaram desde a última verificação
           if (ultimaVerificacao.comum !== comum || ultimaVerificacao.cargo !== cargo) {
             ultimaVerificacao = { comum, cargo };
             
             // Verificar se os nomes já foram carregados
             const temNomesCarregados = window.nomesData && Array.isArray(window.nomesData) && window.nomesData.length > 0;
             const nomeElTemOpcoes = nomeEl.tagName === 'SELECT' && nomeEl.options.length > 1;
             
             // Se não tem nomes carregados, carregar agora
             if (!temNomesCarregados || !nomeElTemOpcoes) {
               console.log('🔄 Verificação periódica: Comum e Cargo preenchidos mas nomes não carregados, carregando agora...', { comum, cargo });
               window.verificarECarregarNomes();
             }
           }
         } else {
           // Se não estão mais preenchidos, resetar última verificação
           ultimaVerificacao = { comum: '', cargo: '' };
         }
       }, 2000); // Verificar a cada 2 segundos
       
       console.log('✅ Verificação periódica iniciada para garantir carregamento de nomes');
     }
     
     // Iniciar verificação periódica apenas em mobile (onde há mais problemas)
