   // Função para limpar overlays no Android
   function clearAndroidOverlays() {
     const isAndroid = /Android/.test(navigator.userAgent);
     if (isAndroid) {
       const overlays = document.querySelectorAll('.suggestions-overlay, #suggestionsOverlay');
       overlays.forEach(overlay => {
         overlay.remove();
         console.log('🤖 Overlay removido do Android');
       });
     }
   }
   
   // Limpa overlays no Android quando a página carrega
   clearAndroidOverlays();
   
   /* ===== PWA - PROGRESSIVE WEB APP ===== */
   
   // Variáveis globais para PWA
   let deferredPrompt = null;
   let isInstalled = false;
   
   // Verificar se o app já está instalado
   function checkIfInstalled() {
     // Verificar se está rodando em modo standalone (instalado)
     if (window.matchMedia('(display-mode: standalone)').matches || 
         window.navigator.standalone === true) {
       isInstalled = true;
       console.log('📱 PWA: App já está instalado');
       return true;
     }
     return false;
   }
   
   // Registrar Service Worker
   async function registerServiceWorker() {
     // Verificar se Service Worker é suportado
     if (!('serviceWorker' in navigator)) {
       console.log('ℹ️ PWA: Service Worker não suportado neste navegador');
       return null;
     }
     
     // Verificar se não está em protocolo file://
     if (window.location.protocol === 'file:') {
       console.log('ℹ️ PWA: Service Worker não funciona com protocolo file:// - use um servidor HTTP');
       return null;
     }
     
     // Verificar se não está em localhost sem HTTPS (exceto localhost)
     if (window.location.protocol === 'http:' && !window.location.hostname.includes('localhost')) {
       console.log('ℹ️ PWA: Service Worker requer HTTPS em produção');
       return null;
     }
     
     try {
       console.log('🔧 PWA: Registrando Service Worker...');
       
       const registration = await navigator.serviceWorker.register('./sw.js', {
         scope: './'
       });
       
       console.log('✅ PWA: Service Worker registrado com sucesso', registration);
       
       // Verificar atualizações
       registration.addEventListener('updatefound', () => {
         const newWorker = registration.installing;
         newWorker.addEventListener('statechange', () => {
           if (newWorker.state === 'installed' && navigator.serviceWorker.controller) {
             console.log('🔄 PWA: Nova versão disponível');
             showUpdateNotification();
           }
         });
       });
       
       return registration;
     } catch (error) {
       console.error('❌ PWA: Erro ao registrar Service Worker:', error);
       console.log('💡 Dica: Certifique-se de que está executando em um servidor HTTP/HTTPS');
       return null;
     }
   }
   
   // Mostrar notificação de atualização
   function showUpdateNotification() {
     if (typeof Swal !== 'undefined') {
       Swal.fire({
         title: 'Nova versão disponível!',
         text: 'Uma nova versão do app está disponível. Deseja atualizar?',
         icon: 'info',
         showCancelButton: true,
         confirmButtonText: 'Atualizar',
         cancelButtonText: 'Depois',
         confirmButtonColor: '#3b82f6',
         cancelButtonColor: '#6b7280'
       }).then((result) => {
         if (result.isConfirmed) {
           window.location.reload();
         }
       });
     }
   }
   
   // Detectar evento de instalação
   function setupInstallPrompt() {
     window.addEventListener('beforeinstallprompt', (e) => {
       console.log('📱 PWA: Evento beforeinstallprompt disparado');
       e.preventDefault();
       deferredPrompt = e;
       
       // Mostrar botão de instalação se não estiver instalado
       if (!checkIfInstalled()) {
         showInstallButton();
       }
     });
     
     // Detectar quando o app é instalado
     window.addEventListener('appinstalled', () => {
       console.log('✅ PWA: App instalado com sucesso!');
       isInstalled = true;
       hideInstallButton();
       
       if (typeof Swal !== 'undefined') {
         Swal.fire({
           title: 'App instalado!',
           text: 'O CCB Presença foi instalado com sucesso na sua tela inicial.',
           icon: 'success',
           timer: 3000,
           showConfirmButton: false
         });
       }
     });
   }
   
   // Mostrar botão de instalação
   function showInstallButton() {
     // Verificar se já existe o botão
     if (document.getElementById('pwaInstallBtn')) return;
     
     // Criar botão de instalação
     const installBtn = document.createElement('button');
     installBtn.id = 'pwaInstallBtn';
     installBtn.className = 'btn btn-outline-primary btn-sm';
     installBtn.innerHTML = '<i class="fa-solid fa-download me-1"></i>Instalar App';
     installBtn.style.cssText = `
       position: fixed;
       bottom: 20px;
       right: 20px;
       z-index: 1000;
       border-radius: 25px;
       padding: 10px 20px;
       font-size: 14px;
       font-weight: 600;
       box-shadow: 0 4px 12px rgba(59, 130, 246, 0.3);
       animation: pulse 2s infinite;
     `;
     
     // Adicionar animação CSS
     if (!document.getElementById('pwaInstallStyles')) {
       const style = document.createElement('style');
       style.id = 'pwaInstallStyles';
       style.textContent = `
         @keyframes pulse {
           0% { transform: scale(1); }
           50% { transform: scale(1.05); }
           100% { transform: scale(1); }
         }
         @media (max-width: 768px) {
           #pwaInstallBtn {
             bottom: 80px !important;
             right: 16px !important;
             left: 16px !important;
             width: auto !important;
           }
         }
       `;
       document.head.appendChild(style);
     }
     
     // Adicionar evento de clique
     installBtn.addEventListener('click', installPWA);
     
     // Adicionar ao DOM
     document.body.appendChild(installBtn);
     
     console.log('📱 PWA: Botão de instalação exibido');
   }
   
   // Esconder botão de instalação
   function hideInstallButton() {
     const installBtn = document.getElementById('pwaInstallBtn');
     if (installBtn) {
       installBtn.remove();
       console.log('📱 PWA: Botão de instalação removido');
     }
   }
   
   // Instalar PWA
   async function installPWA() {
     if (!deferredPrompt) {
       console.log('❌ PWA: Prompt de instalação não disponível');
       
       // Fallback para iOS
       if (/iPad|iPhone|iPod/.test(navigator.userAgent)) {
         showIOSInstallInstructions();
       } else {
         showToast('info', 'Instalação', 'Use o menu do navegador para instalar o app', 3000);
       }
       return;
     }
     
     try {
       console.log('📱 PWA: Iniciando instalação...');
       
       // Mostrar o prompt de instalação
       deferredPrompt.prompt();
       
       // Aguardar a resposta do usuário
       const { outcome } = await deferredPrompt.userChoice;
       
       console.log(`📱 PWA: Resultado da instalação: ${outcome}`);
       
       if (outcome === 'accepted') {
         console.log('✅ PWA: Usuário aceitou a instalação');
       } else {
         console.log('❌ PWA: Usuário rejeitou a instalação');
       }
       
       // Limpar o prompt
       deferredPrompt = null;
       hideInstallButton();
       
     } catch (error) {
       console.error('❌ PWA: Erro durante a instalação:', error);
     }
   }
   
   // Mostrar instruções de instalação para iOS
   function showIOSInstallInstructions() {
     if (typeof Swal !== 'undefined') {
       Swal.fire({
         title: 'Instalar no iPhone/iPad',
         html: `
           <div style="text-align: left; font-size: 14px;">
             <p><strong>Para instalar este app:</strong></p>
             <ol>
               <li>Toque no botão <strong>Compartilhar</strong> <i class="fa-solid fa-share"></i> na parte inferior da tela</li>
               <li>Role para baixo e toque em <strong>"Adicionar à Tela Inicial"</strong></li>
               <li>Toque em <strong>"Adicionar"</strong> no canto superior direito</li>
             </ol>
             <p style="margin-top: 15px; color: #6b7280;">
               <i class="fa-solid fa-info-circle"></i> 
               O app aparecerá na sua tela inicial como um ícone nativo.
             </p>
           </div>
         `,
         icon: 'info',
         confirmButtonText: 'Entendi',
         confirmButtonColor: '#3b82f6',
         width: '90%',
         maxWidth: '400px'
       });
     }
   }
   
   // Monitorar status de conexão
   function setupConnectionMonitoring() {
     window.addEventListener('online', async () => {
       isOnline = true;
       console.log('🌐 PWA: Conexão restaurada - usando processamento centralizado');
       // Removido alerta de conexão online - não é necessário
       await processQueueOnConnectionRestore();
     });
     
     window.addEventListener('offline', () => {
       isOnline = false;
       console.log('📴 PWA: Conexão perdida');
       // showToast('warning', 'Offline', 'Você está offline. Algumas funcionalidades podem estar limitadas.', 3000); // Removido - alerta desnecessário
     });
   }
   
   // Verificar recursos PWA
   function checkPWASupport() {
     const support = {
       serviceWorker: 'serviceWorker' in navigator,
       pushManager: 'PushManager' in window,
       notification: 'Notification' in window,
       installPrompt: 'onbeforeinstallprompt' in window,
       standalone: window.matchMedia('(display-mode: standalone)').matches
     };
     
     console.log('📱 PWA: Suporte disponível:', support);
     return support;
   }
   
   // Inicializar PWA
   async function initPWA() {
     console.log('🚀 PWA: Inicializando Progressive Web App...');
     
     // Verificar suporte
     const support = checkPWASupport();
     
     if (!support.serviceWorker) {
       console.log('ℹ️ PWA: Service Worker não suportado neste navegador');
       console.log('✅ PWA: Inicialização concluída (sem Service Worker)');
       return;
     }
     
     // Verificar se já está instalado
     checkIfInstalled();
     
     // Registrar Service Worker (com verificação de protocolo)
     const swRegistration = await registerServiceWorker();
     
     if (swRegistration) {
       console.log('✅ PWA: Service Worker registrado com sucesso');
     } else {
       console.log('ℹ️ PWA: Service Worker não registrado (protocolo não suportado)');
     }
     
     // Configurar eventos de instalação
     setupInstallPrompt();
     
     // Monitorar conexão
     setupConnectionMonitoring();
     
     console.log('✅ PWA: Inicialização concluída');
   }
   
   // Inicializar PWA quando a página carregar
   document.addEventListener('DOMContentLoaded', () => {
     // Aguardar um pouco para não interferir com a inicialização principal
     setTimeout(() => {
       initPWA();
     }, 1000);
   });
   
   // Função para verificar status das filas
   function verificarStatusFilas() {
     const filaLocal = JSON.parse(localStorage.getItem('fila_envio') || '[]');
     const filaSupabase = JSON.parse(localStorage.getItem('fila_supabase') || '[]');
     
     console.log('📊 Status das filas:');
     console.log(`  📋 Fila Local: ${filaLocal.length} item(s)`);
     console.log(`  🗄️ Fila Supabase: ${filaSupabase.length} item(s)`);
     
     if (filaLocal.length > 0) {
       console.log('🔍 Itens na fila local:', filaLocal.map((item, index) => ({
         index: index + 1,
         uuid: item.uuid,
         nome: item.nome,
         status: item.status,
         tentativas: item.tentativas || 0
       })));
     }
     
     if (filaSupabase.length > 0) {
       console.log('🔍 Itens na fila Supabase:', filaSupabase.map((item, index) => ({
         index: index + 1,
         uuid: item.uuid,
         nome: item.nome,
         status: item.status,
         tentativas: item.tentativas || 0
       })));
     }
     
     return {
       filaLocal: filaLocal.length,
       filaSupabase: filaSupabase.length,
       total: filaLocal.length + filaSupabase.length
     };
   }
   
   // Função para forçar sincronização manual
   async function forcarSincronizacao() {
     try {
       console.log('🔄 Forçando sincronização manual...');
       
       // Verifica status das filas antes
       const statusAntes = verificarStatusFilas();
       
       if (statusAntes.total === 0) {
         showToast('info', 'Info', 'Nenhum registro pendente para sincronizar', 2000);
         return true;
       }
       
       const isOnline = await checkSupabaseConnection();
       if (!isOnline) {
         showToast('error', 'Erro', 'Sem conexão com o servidor', 3000);
         return false;
       }
       
       // Alerta removido para acelerar processamento
       
       // Processa ambas as filas
       await processarFilaLocal();
       await processarFilaSupabase();
       
       // Verifica status das filas depois
       const statusDepois = verificarStatusFilas();
       const processados = statusAntes.total - statusDepois.total;
       
       if (processados > 0) {
         // showToast('success', 'Sucesso', `${processados} registro(s) sincronizado(s) com sucesso!`, 3000); // Removido - alerta desnecessário
       } else {
         // showToast('warning', 'Aviso', 'Nenhum registro foi processado. Verifique os logs.', 3000); // Removido - alerta desnecessário
       }
       
       return true;
       
     } catch (error) {
       console.error('❌ Erro na sincronização manual:', error);
       showToast('error', 'Erro', 'Falha na sincronização', 3000);
       return false;
     }
   }
   
   // Função para forçar processamento da fila SEM verificação de conectividade
   async function forcarProcessamentoFila() {
     try {
       console.log('🚀 FORÇANDO processamento da fila (bypass de conectividade)...');
       
       const filaLocal = JSON.parse(localStorage.getItem('fila_envio') || '[]');
       const filaSupabase = JSON.parse(localStorage.getItem('fila_supabase') || '[]');
       
       if (filaLocal.length === 0 && filaSupabase.length === 0) {
         console.log('📭 Nenhuma fila para processar');
         return { success: true, message: 'Nenhuma fila para processar' };
       }
       
       console.log(`📊 Processando: ${filaLocal.length} local + ${filaSupabase.length} supabase`);
       
       let totalProcessados = 0;
       let totalErros = 0;
       
       // Processa fila local
       if (filaLocal.length > 0) {
         console.log('🔄 Processando fila local...');
         for (let i = 0; i < filaLocal.length; i++) {
           const item = filaLocal[i];
           try {
             console.log(`📤 Enviando item ${i + 1}: ${item.nome}`);
             
             // Tenta enviar para Google Sheets
             await enviarParaSheets(item);
             console.log(`✅ Google Sheets OK: ${item.nome}`);
             
             // Tenta enviar para Supabase
             if (supabaseLoaded && sb) {
               await insertSupabase(item);
               console.log(`✅ Supabase OK: ${item.nome}`);
             }
             
             totalProcessados++;
             
           } catch (error) {
             console.error(`❌ Erro no item ${i + 1}:`, error);
             totalErros++;
           }
         }
         
         // Remove itens processados da fila local
         if (totalProcessados > 0) {
           const itensRestantes = filaLocal.slice(totalProcessados);
           localStorage.setItem('fila_envio', JSON.stringify(itensRestantes));
           console.log(`✅ Removidos ${totalProcessados} itens da fila local`);
         }
       }
       
       // Processa fila Supabase
       if (filaSupabase.length > 0) {
         console.log('🔄 Processando fila Supabase...');
         for (let i = 0; i < filaSupabase.length; i++) {
           const item = filaSupabase[i];
           try {
             console.log(`📤 Enviando item Supabase ${i + 1}: ${item.nome}`);
             await insertSupabase(item);
             totalProcessados++;
           } catch (error) {
             console.error(`❌ Erro no item Supabase ${i + 1}:`, error);
             totalErros++;
           }
         }
         
         // Remove itens processados da fila Supabase
         if (totalProcessados > 0) {
           const itensRestantes = filaSupabase.slice(totalProcessados);
           localStorage.setItem('fila_supabase', JSON.stringify(itensRestantes));
           console.log(`✅ Removidos ${totalProcessados} itens da fila Supabase`);
         }
       }
       
       // Atualiza contador
       atualizarContadorFila();
       
       const resultado = {
         success: totalErros === 0,
         processados: totalProcessados,
         erros: totalErros,
         message: `${totalProcessados} processados, ${totalErros} erros`
       };
       
       console.log('🎯 Resultado do processamento forçado:', resultado);
       return resultado;
       
     } catch (error) {
       console.error('❌ Erro no processamento forçado:', error);
       return { success: false, message: error.message };
     }
   }
   
   // Exportar funções para uso global
