   // Função para testar fila offline
   function testarFilaOffline() {
     console.log('🧪 Testando fila offline...');
     
     const queue = getOfflineQueue();
     const pendingCount = queue.filter(item => !item.synced).length;
     
     console.log('📊 Status da fila offline:', {
       total: queue.length,
       pending: pendingCount,
       synced: queue.length - pendingCount,
       items: queue.map(item => ({
         id: item.id,
         synced: item.synced,
         attempts: item.attempts,
         timestamp: new Date(item.timestamp).toLocaleString()
       }))
     });
     
     return {
       total: queue.length,
       pending: pendingCount,
       synced: queue.length - pendingCount,
       items: queue
     };
   }
   
   // Função para forçar processamento da fila offline
   async function forcarProcessamentoFilaOffline() {
     console.log('🔄 Forçando processamento da fila offline...');
     
     // Loading removido para acelerar processamento
     
     try {
       // Limpar flag de processamento se estiver travada
       window.offlineQueueProcessing = false;
       
       // Verificar conectividade
       const isOnline = await checkSupabaseConnection();
       if (!isOnline) {
         console.log('❌ Sem conectividade - não é possível processar a fila');
         showToast('error', 'Sem conexão', 'Verifique sua conexão com a internet', 3000);
         return false;
       }
       
       // Processar fila
       await processOfflineQueue();
       
       // Verificar se ainda há itens pendentes
       const queue = getOfflineQueue();
       const pendingItems = queue.filter(item => !item.synced);
       
       if (pendingItems.length === 0) {
         console.log('✅ Fila offline processada com sucesso!');
         showToast('success', 'Sucesso', 'Todos os registros foram enviados', 3000);
         return true;
       } else {
         console.log(`⚠️ Ainda há ${pendingItems.length} itens pendentes`);
         showToast('warning', 'Parcial', `${pendingItems.length} registro(s) ainda pendente(s)`, 3000);
         return false;
       }
     } catch (error) {
       console.error('❌ Erro no processamento forçado:', error);
       showToast('error', 'Erro', 'Falha no processamento da fila', 3000);
       return false;
     }
   }
   
