   // Função para limpar dados antigos com UUIDs inválidos (VERSÃO DEFINITIVA)
   function limparDadosAntigosComUUIDsInvalidos() {
     try {
       console.log('🧹 LIMPEZA DEFINITIVA de dados com UUIDs inválidos...');
       
       // Limpar todas as possíveis chaves de fila
       const chavesParaLimpar = [
         'offline_queue_v3',
         'offline_queue',
         'fila_offline',
         'pending_submissions',
         'recent_submissions',
         'queue',
         'fila_envio',
         'fila_supabase',
         'savedData',
         'fila_presencas_v2',
         'fila_presencas'
       ];
       
       let itensRemovidos = 0;
       
       chavesParaLimpar.forEach(chave => {
         try {
           const dados = localStorage.getItem(chave);
           if (dados) {
             const parsed = JSON.parse(dados);
             if (Array.isArray(parsed)) {
               // Filtrar itens com UUIDs inválidos
               const itensValidos = parsed.filter(item => {
                 // Verificar UUID no campo 'uuid'
                 if (item.uuid && !isValidUUID(item.uuid)) {
                   console.log('🗑️ Removendo item com UUID inválido (uuid):', item.uuid);
                   itensRemovidos++;
                   return false;
                 }
                 // Verificar UUID no campo 'id'
                 if (item.id && !isValidUUID(item.id)) {
                   console.log('🗑️ Removendo item com ID inválido (id):', item.id);
                   itensRemovidos++;
                   return false;
                 }
                 // Verificar UUID em item.data.uuid
                 if (item.data && item.data.uuid && !isValidUUID(item.data.uuid)) {
                   console.log('🗑️ Removendo item com UUID inválido (data.uuid):', item.data.uuid);
                   itensRemovidos++;
                   return false;
                 }
                 return true;
               });
               
               if (itensValidos.length !== parsed.length) {
                 localStorage.setItem(chave, JSON.stringify(itensValidos));
                 console.log(`✅ Chave ${chave}: ${parsed.length - itensValidos} itens inválidos removidos`);
               } else {
                 console.log(`✅ Chave ${chave}: sem UUIDs inválidos`);
               }
             }
           }
         } catch (error) {
           console.log(`⚠️ Erro ao processar chave ${chave}:`, error);
           // Se houver erro, remover a chave completamente
           localStorage.removeItem(chave);
         }
       });
       
       if (itensRemovidos > 0) {
         console.log(`✅ Limpeza concluída: ${itensRemovidos} itens com UUIDs inválidos removidos`);
         showToast('success', 'Limpeza Concluída', `${itensRemovidos} itens inválidos removidos`, 3000);
       } else {
         console.log('✅ Nenhum item com UUID inválido encontrado');
         showToast('info', 'Limpeza Concluída', 'Nenhum item inválido encontrado', 2000);
       }
       
     } catch (error) {
       console.error('❌ Erro na limpeza de dados antigos:', error);
       showToast('error', 'Erro', 'Falha na limpeza de dados antigos', 3000);
     }
   }
   
   // Função para limpar UUIDs inválidos da fila Supabase
   function limparUUIDsInvalidos() {
     try {
       const filaSupabase = JSON.parse(localStorage.getItem('fila_supabase') || '[]');
       const filaLimpa = filaSupabase.filter(item => {
         if (item.uuid && !isValidUUID(item.uuid)) {
           console.log('🗑️ Removendo item com UUID inválido:', item.uuid);
           return false;
         }
         return true;
       });
       
       if (filaLimpa.length !== filaSupabase.length) {
         localStorage.setItem('fila_supabase', JSON.stringify(filaLimpa));
         console.log(`✅ ${filaSupabase.length - filaLimpa.length} itens com UUIDs inválidos removidos da fila Supabase`);
       }
       
       return filaSupabase.length - filaLimpa.length;
     } catch (error) {
       console.error('❌ Erro ao limpar UUIDs inválidos:', error);
       return 0;
     }
   }
   
