     // Função para testar geração de UUIDs (VERSÃO ROBUSTA)
     testarUUIDs: function() {
       console.log('🧪 TESTE DEFINITIVO de geração de UUIDs...');
       let sucessos = 0;
       let falhas = 0;
       
       for (let i = 0; i < 10; i++) {
         try {
           const uuid = uuidv4();
           const isValid = isValidUUID(uuid);
           
           if (isValid) {
             sucessos++;
             console.log(`✅ UUID ${i + 1}: ${uuid} - VÁLIDO`);
           } else {
             falhas++;
             console.error(`❌ UUID ${i + 1}: ${uuid} - INVÁLIDO`);
           }
         } catch (error) {
           falhas++;
           console.error(`❌ Erro na geração ${i + 1}:`, error);
         }
       }
       
       console.log(`📊 RESULTADO: ${sucessos} sucessos, ${falhas} falhas`);
       
       if (falhas === 0) {
         showToast('success', 'Teste UUID', 'Todos os UUIDs são válidos!', 3000);
       } else {
         showToast('error', 'Teste UUID', `${falhas} UUIDs inválidos detectados!`, 5000);
       }
     },
     
     // Função para validar UUIDs existentes no localStorage
     validarUUIDsExistentes: function() {
       console.log('🔍 Validando UUIDs existentes no localStorage...');
       const chaves = ['offline_queue_v3', 'fila_presencas_v2', 'queue'];
       let totalItens = 0;
       let itensInvalidos = 0;
       
       chaves.forEach(chave => {
         try {
           const dados = localStorage.getItem(chave);
           if (dados) {
             const parsed = JSON.parse(dados);
             if (Array.isArray(parsed)) {
               parsed.forEach((item, index) => {
                 totalItens++;
                 if (item.uuid && !isValidUUID(item.uuid)) {
                   itensInvalidos++;
                   console.error(`❌ ${chave}[${index}]: UUID inválido - ${item.uuid}`);
                 }
                 if (item.id && !isValidUUID(item.id)) {
                   itensInvalidos++;
                   console.error(`❌ ${chave}[${index}]: ID inválido - ${item.id}`);
                 }
               });
             }
           }
         } catch (error) {
           console.error(`❌ Erro ao validar ${chave}:`, error);
         }
       });
       
       console.log(`📊 VALIDAÇÃO: ${totalItens} itens verificados, ${itensInvalidos} inválidos`);
       
       if (itensInvalidos > 0) {
         showToast('warning', 'UUIDs Inválidos', `${itensInvalidos} UUIDs inválidos encontrados!`, 5000);
       } else {
         showToast('success', 'UUIDs Válidos', 'Todos os UUIDs são válidos!', 3000);
       }
     },
     
