   // 🧪 FUNÇÃO DE TESTE: Validar comparação de comum em diferentes plataformas
   // Pode ser executada no console do navegador para testar a função compareComum
   window.testarComparacaoComum = function(testCases = null) {
     console.log('🧪 TESTE: Validação de comparação de comum (cross-platform)');
     console.log('🧪 Plataforma:', {
       userAgent: navigator.userAgent,
       isAndroid: /Android/.test(navigator.userAgent),
       isIOS: /iPhone|iPad|iPod/.test(navigator.userAgent),
       isMobile: /Android|iPhone|iPad|iPod/.test(navigator.userAgent)
     });
     
     // Casos de teste padrão
     const defaultTestCases = [
       // Casos básicos
       { comumRegistro: 'Jardim Honória', comumBuscado: 'Jardim Honoria', esperado: true, descricao: 'Comum com acento vs sem acento' },
       { comumRegistro: 'Jardim Honoria', comumBuscado: 'Jardim Honória', esperado: true, descricao: 'Comum sem acento vs com acento' },
       { comumRegistro: 'Jardim Honória', comumBuscado: 'Jardim Honória', esperado: true, descricao: 'Comum idêntico' },
       { comumRegistro: 'Jardim Honória', comumBuscado: 'Jardim', esperado: true, descricao: 'Comum parcial (buscado menor)' },
       { comumRegistro: 'Jardim', comumBuscado: 'Jardim Honória', esperado: true, descricao: 'Comum parcial (registro menor)' },
       
       // Casos com espaços
       { comumRegistro: 'Jardim  Honória', comumBuscado: 'Jardim Honoria', esperado: true, descricao: 'Comum com espaços múltiplos' },
       { comumRegistro: ' Jardim Honória ', comumBuscado: 'Jardim Honoria', esperado: true, descricao: 'Comum com espaços extras' },
       
       // Casos que não devem fazer match
       { comumRegistro: 'Jardim Honória', comumBuscado: 'São Paulo', esperado: false, descricao: 'Comuns diferentes' },
       { comumRegistro: 'Jardim', comumBuscado: 'São Paulo', esperado: false, descricao: 'Completamente diferentes' },
       
       // Casos especiais
       { comumRegistro: '', comumBuscado: 'Jardim Honoria', esperado: false, descricao: 'Registro vazio' },
       { comumRegistro: 'Jardim Honória', comumBuscado: '', esperado: false, descricao: 'Buscado vazio' },
       { comumRegistro: null, comumBuscado: 'Jardim Honoria', esperado: false, descricao: 'Registro null' },
       { comumRegistro: 'Jardim Honória', comumBuscado: null, esperado: false, descricao: 'Buscado null' }
     ];
     
     const tests = testCases || defaultTestCases;
     const results = [];
     let passed = 0;
     let failed = 0;
     
     console.log('🧪 Executando', tests.length, 'casos de teste...');
     
     tests.forEach((testCase, index) => {
       const result = compareComum(testCase.comumRegistro, testCase.comumBuscado, { debug: true });
       const testPassed = result.match === testCase.esperado;
       
       if (testPassed) {
         passed++;
       } else {
         failed++;
         console.error(`❌ TESTE ${index + 1} FALHOU:`, {
           descricao: testCase.descricao,
           comumRegistro: testCase.comumRegistro,
           comumBuscado: testCase.comumBuscado,
           esperado: testCase.esperado,
           obtido: result.match,
           detalhes: result.matchDetails
         });
       }
       
       results.push({
         ...testCase,
         resultado: result.match,
         passou: testPassed,
         detalhes: result.matchDetails
       });
     });
     
     console.log('🧪 RESULTADOS DO TESTE:');
     console.log(`✅ Passou: ${passed}/${tests.length}`);
     console.log(`❌ Falhou: ${failed}/${tests.length}`);
     console.log(`📊 Taxa de sucesso: ${((passed / tests.length) * 100).toFixed(2)}%`);
     
     if (failed === 0) {
       console.log('✅ TODOS OS TESTES PASSARAM!');
     } else {
       console.warn('⚠️ ALGUNS TESTES FALHARAM - Verifique os logs acima');
     }
     
     return {
       total: tests.length,
       passed,
       failed,
       taxaSucesso: (passed / tests.length) * 100,
       resultados: results
     };
   };
   
   // 📊 FUNÇÃO DE MONITORAMENTO: Coletar estatísticas de comparação de comum
   // Armazena estatísticas para análise de padrões de problemas
   window.monitorarComparacaoComum = (function() {
     const stats = {
       total: 0,
       matches: 0,
       nonMatches: 0,
       erros: 0,
       casosProblema: [],
       ultimaAtualizacao: null
     };
     
     return {
       // Registrar uma comparação
       registrar: function(comumRegistro, comumBuscado, match, error = null) {
         stats.total++;
         if (error) {
           stats.erros++;
         } else if (match) {
           stats.matches++;
         } else {
           stats.nonMatches++;
           // Armazenar casos que não fizeram match para análise
           if (stats.casosProblema.length < 50) { // Limitar a 50 casos
             stats.casosProblema.push({
               comumRegistro,
               comumBuscado,
               timestamp: new Date().toISOString(),
               userAgent: navigator.userAgent
             });
           }
         }
         stats.ultimaAtualizacao = new Date().toISOString();
       },
       
       // Obter estatísticas
       getStats: function() {
         return {
           ...stats,
           taxaMatch: stats.total > 0 ? (stats.matches / stats.total * 100).toFixed(2) + '%' : '0%',
           taxaErro: stats.total > 0 ? (stats.erros / stats.total * 100).toFixed(2) + '%' : '0%'
         };
       },
       
       // Limpar estatísticas
       limpar: function() {
         stats.total = 0;
         stats.matches = 0;
         stats.nonMatches = 0;
         stats.erros = 0;
         stats.casosProblema = [];
         stats.ultimaAtualizacao = null;
         console.log('📊 Estatísticas de comparação de comum limpas');
       },
       
       // Exportar estatísticas para análise
       exportar: function() {
         const statsData = this.getStats();
         const json = JSON.stringify(statsData, null, 2);
         console.log('📊 Estatísticas de comparação de comum:');
         console.log(json);
         return statsData;
       }
     };
   })();
   
   // Expor função compareComum globalmente para testes
   window.compareComum = compareComum;
   
   // Função de debug para testar detecção de cargos
   async function debugCargoDetection(nome, comum) {
     console.log('🔍 DEBUG - Testando detecção de cargo para:', { nome, comum });
     
     if (!supabaseLoaded || !sb) {
       console.log('⚠️ Supabase não disponível para debug');
       return;
     }
     
     try {
       // Busca todos os registros da pessoa
       const { data, error } = await sb
         .from(TABLE_CATALOGO)
         .select('nome, cargo, nivel, instrumento, comum')
         .ilike('nome', `%${nome}%`)
         .ilike(COL_COMUM, `%${comum}%`)
         .eq('ativo', true)
         .order('cargo', { ascending: true });
       
       if (error) {
         console.error('❌ Erro na busca de debug:', error);
         return;
       }
       
       console.log('🔍 DEBUG - Registros encontrados:', data);
       
       if (data && data.length > 0) {
         data.forEach((r, index) => {
           console.log(`  ${index + 1}. Nome: "${r.nome}", Cargo: "${r.cargo}", Instrumento: "${r.instrumento}", Comum: "${r.comum}"`);
         });
         
         // Testa detecção de cargo especial
         const cargoEspecial = data.find(r => {
           const cargoUpper = r.cargo.toUpperCase();
           // 🛡️ CORREÇÃO: Diferenciação de gênero para cargos
           const isExaminadora = cargoUpper.includes('EXAMINADORA');
           const isInstrutora = cargoUpper.includes('INSTRUTORA');
           const isSecretariaMusica = cargoUpper.includes('SECRETÁRIA') && cargoUpper.includes('MÚSICA');
           // 🚨 SECRETÁRIO DA MÚSICA (masculino) NÃO deve ser detectado como cargo especial
           
           return isExaminadora || isInstrutora || isSecretariaMusica;
         });
         
         if (cargoEspecial) {
           console.log('✅ Cargo especial detectado:', cargoEspecial.cargo);
         } else {
           console.log('❌ Nenhum cargo especial detectado');
         }
       } else {
         console.log('❌ Nenhum registro encontrado');
       }
     } catch (error) {
       console.error('❌ Erro no debug:', error);
     }
   }
   
   // Expor função de debug globalmente para testes
   window.debugCargoDetection = debugCargoDetection;
   
