   // Função genérica para testar detecção de cargo
   async function testarDetecaoCargoCompleta(nome, comum, cargo, instrumento) {
     console.log('🔍 TESTANDO DETECÇÃO DE CARGO GENÉRICA');
     console.log('🔍 Dados do teste:', { nome, comum, cargo, instrumento });
     
     // Simula preenchimento do formulário
     const comumEl = document.getElementById('comumInput') || document.querySelector('[name="comum"]');
     const cargoEl = document.getElementById('cargo') || document.querySelector('[name="cargo"]');
     const nomeEl = document.getElementById('nome') || document.querySelector('[name="nome"]');
     const instEl = document.getElementById('instrumento') || document.querySelector('[name="instrumento"]');
     
     if (!comumEl || !cargoEl || !nomeEl) {
       console.error('❌ Campos não encontrados');
       return;
     }
     
     // Preenche os dados
     comumEl.value = comum;
     cargoEl.value = cargo;
     nomeEl.value = nome;
     if (instEl) instEl.value = instrumento || '';
     
     console.log('🔍 Dados preenchidos:', {
       comum: comumEl.value,
       cargo: cargoEl.value,
       nome: nomeEl.value,
       instrumento: instEl ? instEl.value : 'N/A'
     });
     
     // Força detecção de cargo
     console.log('🔍 Forçando detecção de cargo...');
     await forcarDetecaoCargo();
     
     // Verifica se o cargo real foi detectado
     const cargoReal = cargoEl.getAttribute('data-cargo-real');
     console.log('🔍 Cargo real detectado:', cargoReal);
     
     if (cargoReal) {
       console.log('✅ SUCESSO: Cargo real detectado:', cargoReal);
     } else {
       console.log('❌ FALHA: Nenhum cargo real detectado');
     }
     
     // Testa o collectFormData
     console.log('🔍 Testando collectFormData...');
     const formData = await collectFormData();
     console.log('🔍 Dados coletados:', formData);
     
     if (formData && formData.cargo === cargoReal) {
       console.log('✅ SUCESSO: Cargo correto no collectFormData');
     } else {
       console.log('❌ FALHA: Cargo incorreto no collectFormData:', formData?.cargo);
     }
   }
   
