   window.testarDetecaoCargoCompleta = testarDetecaoCargoCompleta;
   
   // Função para testar busca de nomes
   async function testarBuscaNomes(comum, cargo, instrumento) {
     console.log('🔍 TESTANDO BUSCA DE NOMES');
     console.log('🔍 Dados:', { comum, cargo, instrumento });
     
     if (!supabaseLoaded || !sb) {
       console.error('❌ Supabase não disponível');
       return;
     }
     
     try {
       const comumVal = norm(comum);
       const cargoVal = norm(cargo);
       const instVal = upper(instrumento);
       const cargoUP = ucase(cargoVal);
       
       console.log('🔍 Dados normalizados:', { comumVal, cargoVal, instVal, cargoUP });
       
       // Verifica se precisa de instrumento
       const precisaInstrumento = ['MUSICO','MUSICO(A)','MÚSICO','MÚSICO(A)','ORGANISTA','EXAMINADORA','INSTRUTOR','INSTRUTORA'].includes(cargoUP) ||
                                 (cargoVal.toLowerCase().includes('secretária') && cargoVal.toLowerCase().includes('música'));
       
       console.log('🔍 Precisa instrumento:', precisaInstrumento);
       
       if (precisaInstrumento && !instVal) {
         console.log('❌ Instrumento obrigatório não fornecido');
         return;
       }
       
       // Consulta ao Supabase
       let query = sb.from(TABLE_CATALOGO)
         .select(`nome,instrumento,${COL_COMUM},cargo,ativo`)
         .ilike(COL_COMUM, `%${comumVal}%`)
         .eq('ativo', true);
   
       // Lógica de filtro
       if (cargoVal.toLowerCase().includes('secretária') && cargoVal.toLowerCase().includes('música')) {
         query = query.ilike('cargo', '%SECRETÁRIA DA MÚSICA%');
       } else if (cargoVal.toLowerCase().includes('organista')) {
         query = query.ilike('instrumento', '%ÓRGÃO%');
      } else if (cargoVal.toLowerCase().includes('músico') && instVal) {
        // Músico com instrumento - busca por instrumento (seguindo lógica das organistas)
        // 🔧 CORREÇÃO: Busca especial para clarinete baixo (clarone) para músicos
        if (instVal.includes('CLARINETE BAIXO') || instVal.includes('CLARONE')) {
          console.log('🔍 Busca especial CLARINETE BAIXO para MÚSICO (teste)');
          query = query.or('instrumento.ilike.%CLARINETE BAIXO (CLARONE)%,instrumento.ilike.%CLARINETE BAIXO%,instrumento.ilike.%CLARONE%');
        } else {
          query = query.ilike('instrumento', `%${instVal}%`);
        }
      } else if (cargoVal.toLowerCase().includes('músico')) {
        // Músico sem instrumento - busca apenas por cargo
        query = query.ilike('cargo', '%MÚSICO%').not('cargo', 'ilike', '%SECRETÁRIO%');
     } else if (cargoVal.toLowerCase().includes('instrutor')) {
       // Distingue entre INSTRUTOR e INSTRUTORA
       if (cargoVal.toUpperCase() === 'INSTRUTOR') {
         if (instVal) {
           // 🔧 CORREÇÃO: Busca especial para clarinete baixo (clarone) para instrutores
           if (instVal.includes('CLARINETE BAIXO') || instVal.includes('CLARONE')) {
             query = query.ilike('cargo', '%INSTRUTOR%').not('cargo', 'ilike', '%INSTRUTORA%')
               .or('instrumento.ilike.%CLARINETE BAIXO (CLARONE)%,instrumento.ilike.%CLARINETE BAIXO%,instrumento.ilike.%CLARONE%');
           } else {
             query = query.ilike('cargo', '%INSTRUTOR%').not('cargo', 'ilike', '%INSTRUTORA%').ilike('instrumento', `%${instVal}%`);
           }
         } else {
           query = query.ilike('cargo', '%INSTRUTOR%').not('cargo', 'ilike', '%INSTRUTORA%');
         }
       } else if (cargoVal.toUpperCase() === 'INSTRUTORA') {
         if (instVal) {
           // 🔧 CORREÇÃO: Busca especial para clarinete baixo (clarone) para instrutoras
           if (instVal.includes('CLARINETE BAIXO') || instVal.includes('CLARONE')) {
             query = query.ilike('cargo', '%INSTRUTORA%')
               .or('instrumento.ilike.%CLARINETE BAIXO (CLARONE)%,instrumento.ilike.%CLARINETE BAIXO%,instrumento.ilike.%CLARONE%');
           } else {
             query = query.ilike('cargo', '%INSTRUTORA%').ilike('instrumento', `%${instVal}%`);
           }
         } else {
           query = query.ilike('cargo', '%INSTRUTORA%');
         }
       } else {
         if (instVal) {
           // 🔧 CORREÇÃO: Busca especial para clarinete baixo (clarone) para instrutores genéricos
           if (instVal.includes('CLARINETE BAIXO') || instVal.includes('CLARONE')) {
             query = query.ilike('cargo', '%INSTRUTOR%')
               .or('instrumento.ilike.%CLARINETE BAIXO (CLARONE)%,instrumento.ilike.%CLARINETE BAIXO%,instrumento.ilike.%CLARONE%');
           } else {
             query = query.ilike('cargo', '%INSTRUTOR%').ilike('instrumento', `%${instVal}%`);
           }
         } else {
           query = query.ilike('cargo', '%INSTRUTOR%');
         }
       }
       } else {
         query = query.ilike('cargo', `%${cargoVal}%`);
       }
   
       query = query.order('nome', { ascending: true });
   
       const { data, error } = await query;
       
       if (error) {
         console.error('❌ Erro na consulta:', error);
         return;
       }
   
       console.log('🔍 Resultado da consulta:', data?.length || 0, 'registros');
       
       if (data && data.length > 0) {
         data.forEach((r, i) => {
           console.log(`${i+1}. Nome: "${r.nome}", Cargo: "${r.cargo}", Instrumento: "${r.instrumento}"`);
         });
       } else {
         console.log('❌ Nenhum resultado encontrado');
       }
       
     } catch (error) {
       console.error('❌ Erro no teste:', error);
     }
   }
   
   window.testarBuscaNomes = testarBuscaNomes;
   
