   // 🧪 FUNÇÃO DE TESTE DE CARGA PARA LANÇAMENTO
   async function testarCarga40Usuarios() {
     console.log('🚨 TESTE DE CARGA: 40 USUÁRIOS SIMULTÂNEOS');
     console.log('==========================================');
     console.log('⚠️ ATENÇÃO: Este teste simula o cenário de lançamento');
     console.log('');
     
     const usuarios = [];
     const resultados = [];
     
     // Criar 40 usuários simulados
     for (let i = 1; i <= 40; i++) {
       usuarios.push({
         id: `user_${i}`,
         nome: `Usuário ${i}`,
         comum: `Comum Teste ${i}`,
         cargo: 'ORGANISTA',
         instrumento: 'ÓRGÃO'
       });
     }
     
     console.log('👥 Usuários criados:', usuarios.length);
     console.log('📊 Configurações do teste:');
     console.log('   - Máximo de requisições simultâneas:', MAX_CONCURRENT_REQUESTS);
     console.log('   - Rate limit por minuto:', MAX_REQUESTS_PER_MINUTE);
     console.log('   - Rate limit por hora:', MAX_REQUESTS_PER_HOUR);
     console.log('');
     
     // Limpar métricas anteriores para teste limpo
     performanceMetrics.responseTime = [];
     performanceMetrics.totalRequests = 0;
     performanceMetrics.failedRequests = 0;
     performanceMetrics.successRate = 0;
     performanceMetrics.errorRate = 0;
     performanceMetrics.concurrentUsers = 0;
     performanceMetrics.queueLength = 0;
     
     console.log('🧹 Métricas limpas para teste');
     
     // Simular requisições simultâneas
     const promises = usuarios.map(async (usuario, index) => {
       const startTime = performance.now();
       
       try {
         // Simular verificação de rate limiting
         const rateLimitOk = checkRateLimits(usuario.id);
         if (!rateLimitOk) {
           throw new Error('Rate limit excedido');
         }
         
         // Simular verificação de circuit breaker
         const circuitOk = checkCircuitBreaker();
         if (!circuitOk) {
           throw new Error('Circuit breaker aberto');
         }
         
         // Simular adição às listas de controle (como uma requisição real)
         processingUsers.add(usuario.id);
         activeRequests.add(usuario.id);
         
         // Atualizar métricas de concorrência ANTES do processamento
         performanceMetrics.concurrentUsers = processingUsers.size;
         performanceMetrics.queueLength = requestQueue.length;
         
         // Simular tempo de processamento
         await new Promise(resolve => setTimeout(resolve, Math.random() * 2000 + 500));
         
         const endTime = performance.now();
         const duration = endTime - startTime;
         
         // Registrar métricas de performance (como uma requisição real)
         recordPerformanceMetrics(duration, true);
         
         // Simular remoção das listas de controle
         processingUsers.delete(usuario.id);
         activeRequests.delete(usuario.id);
         
         // Atualizar métricas de concorrência APÓS o processamento
         performanceMetrics.concurrentUsers = processingUsers.size;
         performanceMetrics.queueLength = requestQueue.length;
         
         resultados.push({
           usuario: usuario.id,
           sucesso: true,
           duracao: duration,
           timestamp: new Date().toISOString()
         });
         
         console.log(`✅ Usuário ${usuario.id}: Sucesso em ${duration.toFixed(2)}ms`);
         
       } catch (error) {
         const endTime = performance.now();
         const duration = endTime - startTime;
         
         // Registrar métricas de performance (falha)
         recordPerformanceMetrics(duration, false);
         
         // Simular remoção das listas de controle em caso de erro
         processingUsers.delete(usuario.id);
         activeRequests.delete(usuario.id);
         
         resultados.push({
           usuario: usuario.id,
           sucesso: false,
           erro: error.message,
           duracao: duration,
           timestamp: new Date().toISOString()
         });
         
         console.log(`❌ Usuário ${usuario.id}: Erro - ${error.message} em ${duration.toFixed(2)}ms`);
       }
     });
     
     console.log('⏳ Executando teste de carga...');
     console.log('');
     
     // Aguardar todas as requisições
     await Promise.all(promises);
     
     // Analisar resultados
     const sucessos = resultados.filter(r => r.sucesso).length;
     const falhas = resultados.filter(r => !r.sucesso).length;
     const duracaoMedia = resultados.reduce((acc, r) => acc + r.duracao, 0) / resultados.length;
     const duracaoMaxima = Math.max(...resultados.map(r => r.duracao));
     const duracaoMinima = Math.min(...resultados.map(r => r.duracao));
     
     console.log('📊 RESULTADOS DO TESTE DE CARGA:');
     console.log('================================');
     console.log(`✅ Sucessos: ${sucessos}/${resultados.length} (${((sucessos/resultados.length)*100).toFixed(1)}%)`);
     console.log(`❌ Falhas: ${falhas}/${resultados.length} (${((falhas/resultados.length)*100).toFixed(1)}%)`);
     console.log(`⏱️ Duração média: ${duracaoMedia.toFixed(2)}ms`);
     console.log(`⏱️ Duração máxima: ${duracaoMaxima.toFixed(2)}ms`);
     console.log(`⏱️ Duração mínima: ${duracaoMinima.toFixed(2)}ms`);
     console.log('');
     
     // Verificar métricas de performance
     const metrics = getPerformanceMetrics();
     console.log('📈 MÉTRICAS DE PERFORMANCE:');
     console.log('   - Usuários simultâneos:', metrics.concurrentUsers);
     console.log('   - Tamanho da fila:', metrics.queueLength);
     console.log('   - Taxa de erro:', (metrics.errorRate * 100).toFixed(2) + '%');
     console.log('   - Taxa de sucesso:', (metrics.successRate * 100).toFixed(2) + '%');
     console.log('   - Tempo médio de resposta:', metrics.avgResponseTime.toFixed(2) + 'ms');
     console.log('   - Estado do circuit breaker:', metrics.circuitBreakerState);
     console.log('');
     
     // Avaliar se o sistema está pronto para o lançamento
     const isReady = sucessos >= 38 && duracaoMedia < 3000 && metrics.errorRate < 0.05;
     
     if (isReady) {
       console.log('🎉 SISTEMA PRONTO PARA LANÇAMENTO!');
       console.log('✅ Todos os critérios foram atendidos');
     } else {
       console.log('🚨 SISTEMA NÃO ESTÁ PRONTO PARA LANÇAMENTO!');
       console.log('❌ Alguns critérios não foram atendidos');
       
       if (sucessos < 38) {
         console.log('   - Taxa de sucesso muito baixa');
       }
       if (duracaoMedia >= 3000) {
         console.log('   - Tempo de resposta muito alto');
       }
       if (metrics.errorRate >= 0.05) {
         console.log('   - Taxa de erro muito alta');
       }
     }
     
     console.log('');
     console.log('🎯 Teste de carga concluído!');
     
     return {
       sucessos,
       falhas,
       duracaoMedia,
       duracaoMaxima,
       duracaoMinima,
       isReady,
       metrics
     };
   }
   
   window.testarCarga40Usuarios = testarCarga40Usuarios;
   
