     // Terceira tentativa (mesmo registro, internet ainda instável)
     console.log('3️⃣ Terceira tentativa - Mesmo registro, internet instável');
     const id3 = addToOfflineQueue(dadosTeste);
     console.log('   Resultado:', id3 ? `ID: ${id3}` : 'BLOQUEADO');
     
     // Verificar fila final
     const filaFinal = getOfflineQueue();
     const registrosComMesmoNome = filaFinal.filter(item => 
       (item.data.nome || item.data.NOME) === dadosTeste.nome
     );
     
     console.log('');
     console.log('📊 RESULTADOS DO TESTE:');
     console.log('========================');
     console.log(`   - Total de itens na fila: ${filaFinal.length}`);
     console.log(`   - Registros com mesmo nome: ${registrosComMesmoNome.length}`);
     console.log(`   - IDs gerados: ${id1}, ${id2}, ${id3}`);
     console.log('');
     
     // Avaliar resultado
     if (registrosComMesmoNome.length === 1) {
       console.log('✅ SUCESSO: Duplicação foi prevenida!');
       console.log('✅ Apenas 1 registro foi adicionado à fila');
       console.log('✅ Sistema está protegido contra oscilações de internet');
     } else {
       console.log('❌ FALHA: Duplicação ainda está ocorrendo!');
       console.log(`❌ ${registrosComMesmoNome.length} registros duplicados encontrados`);
       console.log('❌ Sistema precisa de mais correções');
     }
     
     console.log('');
