   // Função para enviar dados com anotação (entrada manual)
   async function enviarDadosComAnotacao(dados) {
     try {
       console.log('📤 Enviando dados com anotação:', dados);
       
       // Preparar dados para envio
       const dadosParaEnvio = {
         comum: dados.comum,
         cargo: dados.cargo,
         nome: dados.nome,
         instrumento: dados.instrumento || 'ÓRGÃO', // Default para órgão se não especificado
        anotacoes: dados.anotacao || 'SAM Desatualizado',
         registrado_por: localStorage.getItem('current_user_name') || 'Sistema',
         user_id: localStorage.getItem('current_user_id') || '',
         timestamp: dados.timestamp || new Date().toISOString()
       };
       
       console.log('📋 Dados preparados para envio:', dadosParaEnvio);
       
       // Enviar para Google Sheets
       const resultado = await enviarParaSheets(dadosParaEnvio);
       
       if (resultado.success) {
         console.log('✅ Dados enviados com sucesso para Google Sheets');
         // Verificar se deve mostrar anotação SAM baseado no cargo
        const isCargoMusicalInline = dadosParaEnvio.cargo && (
          dadosParaEnvio.cargo.toUpperCase().includes('MÚSICO') ||
          dadosParaEnvio.cargo.toUpperCase().includes('ORGANISTA') ||
          dadosParaEnvio.cargo.toUpperCase().includes('EXAMINADORA') ||
          dadosParaEnvio.cargo.toUpperCase().includes('INSTRUTORA') ||
          (dadosParaEnvio.cargo.toLowerCase().includes('secretária') && dadosParaEnvio.cargo.toLowerCase().includes('música'))
        );
        if (isCargoMusicalInline) {
          showStatusModal('SUCESSO', 'REGISTRO SALVO COM ANOTAÇÃO "SAM DESATUALIZADO"', 'success', () => {
            console.log('🔄 Recarregando página após envio com anotação SAM');
            window.location.reload();
          });
        } else {
          showStatusModal('SUCESSO', 'REGISTRO SALVO COM SUCESSO', 'success', () => {
            console.log('🔄 Recarregando página após envio bem-sucedido');
            window.location.reload();
          });
        }
        // Timeout de segurança adicional
        setTimeout(() => {
          console.log('⏰ Timeout de segurança - forçando recarregamento');
          if (typeof window.forceReload === 'function') {
            window.forceReload();
          } else {
            window.location.reload();
          }
        }, 2000);
         return { success: true, message: 'Dados enviados com sucesso' };
       } else {
         console.error('❌ Erro ao enviar dados:', resultado.error);
         showStatusModal('ERRO', 'ERRO AO SALVAR REGISTRO COM ANOTAÇÃO', 'error');
         return { success: false, error: resultado.error };
       }
       
     } catch (error) {
       console.error('❌ Erro na função enviarDadosComAnotacao:', error);
       showStatusModal('ERRO', 'ERRO INTERNO AO PROCESSAR DADOS', 'error');
       return { success: false, error: error.message };
     }
   }
   
  // Expor função globalmente
  window.enviarDadosComAnotacao = enviarDadosComAnotacao;
  
